# Simple in-memory store for OpenID4VP login sessions.
# Keys: state UUIDs; Values: dict with status, vp_token, principal_did, expiry, etc.
_openid_vp_sessions: dict[str, dict[str, Any]] = {}

# Generate an ephemeral P-256 key pair for signing OpenID4VP presentation requests.
# In production this should be a persisted key (env var / secret).
try:
    from cryptography.hazmat.primitives.asymmetric.ec import generate_private_key, SECP256R1
    from jwt.algorithms import ECAlgorithm

    _openid_vp_signing_key = generate_private_key(SECP256R1())
    _openid_vp_signing_public_jwk = json.loads(ECAlgorithm.to_jwk(_openid_vp_signing_key.public_key()))
except Exception:
    _openid_vp_signing_key = None
    _openid_vp_signing_public_jwk = {}
