def _resolve_data_dir() -> Path:
    """Return a writable data directory.

    In local development this is the project ``data/`` folder. On read-only
    serverless runtimes (e.g. Vercel) it falls back to ``/tmp/dss-dashboard-data``
    so ephemeral uploads and shadow state do not fail the request path.
    """
    env_dir = str(os.getenv("DSS_DATA_DIR") or "").strip()
    if env_dir:
        p = Path(env_dir)
        try:
            p.mkdir(parents=True, exist_ok=True)
            return p
        except Exception:
            pass
    local = APP_ROOT / "data"
    try:
        local.mkdir(parents=True, exist_ok=True)
        if os.access(local, os.W_OK):
            return local
    except Exception:
        pass
    fallback = Path("/tmp/dss-dashboard-data")
    fallback.mkdir(parents=True, exist_ok=True)
    return fallback


