def _default_control_plane_state() -> dict[str, Any]:
    return {
        "providers": [],
        "model_bindings": [],
        "app_surfaces": [],
        "entity_settings": [],
        "relationships": [],
        "manual_ledgers": [],
        "manual_principals": [],
        "sources": [],
        "source_jobs": [],
    }



def load_verification_method() -> tuple[dict[str, Any], dict[str, Any]]:
    verification_method_id = os.getenv("DID_VERIFICATION_METHOD_ID") or f"{ISSUER_DID}#v1"
    raw_jwk = (os.getenv("DID_PUBLIC_JWK_JSON") or "").strip()
    if raw_jwk:
        try:
            public_key_jwk = json.loads(raw_jwk)
        except Exception:
            public_key_jwk = None
        if isinstance(public_key_jwk, dict):
            return (
                {
                    "id": verification_method_id,
                    "type": "JsonWebKey2020",
                    "controller": ISSUER_DID,
                    "publicKeyJwk": public_key_jwk,
                },
                {
                    "configured": True,
                    "placeholder": False,
                    "source": "DID_PUBLIC_JWK_JSON",
                    "verification_method_id": verification_method_id,
                },
            )

    x_value = os.getenv("DID_VERIFICATION_KEY_X", "REPLACE_ME")
    return (
        {
            "id": verification_method_id,
            "type": "JsonWebKey2020",
            "controller": ISSUER_DID,
            "publicKeyJwk": {
                "kty": "OKP",
                "crv": "Ed25519",
                "x": x_value,
            },
        },
        {
            "configured": x_value != "REPLACE_ME",
            "placeholder": x_value == "REPLACE_ME",
            "source": "DID_VERIFICATION_KEY_X",
            "verification_method_id": verification_method_id,
        },
    )


def _ensure_control_plane_state_dir() -> None:
    DATA_DIR.mkdir(parents=True, exist_ok=True)


def _load_control_plane_state() -> dict[str, Any]:
    try:
        raw = CONTROL_PLANE_STATE_PATH.read_text(encoding="utf-8")
    except FileNotFoundError:
        return _default_control_plane_state()
    except Exception:
        return _default_control_plane_state()
    try:
        payload = json.loads(raw)
    except Exception:
        return _default_control_plane_state()
    if not isinstance(payload, dict):
        return _default_control_plane_state()
    return _normalized_control_plane_state({
        "providers": payload.get("providers") if isinstance(payload.get("providers"), list) else [],
        "model_bindings": payload.get("model_bindings") if isinstance(payload.get("model_bindings"), list) else [],
        "app_surfaces": payload.get("app_surfaces") if isinstance(payload.get("app_surfaces"), list) else [],
        "entity_settings": payload.get("entity_settings") if isinstance(payload.get("entity_settings"), list) else [],
        "relationships": payload.get("relationships") if isinstance(payload.get("relationships"), list) else [],
        "manual_ledgers": payload.get("manual_ledgers") if isinstance(payload.get("manual_ledgers"), list) else [],
        "manual_principals": payload.get("manual_principals") if isinstance(payload.get("manual_principals"), list) else [],
        "sources": payload.get("sources") if isinstance(payload.get("sources"), list) else [],
        "source_jobs": payload.get("source_jobs") if isinstance(payload.get("source_jobs"), list) else [],
    })


def _save_control_plane_state(payload: dict[str, Any]) -> None:
    try:
        _ensure_control_plane_state_dir()
        CONTROL_PLANE_STATE_PATH.write_text(json.dumps(_normalized_control_plane_state(payload), indent=2, sort_keys=True), encoding="utf-8")
    except Exception:
        # Serverless/runtime filesystems may be read-only. The backend control-plane
        # API is now the source of truth, so local shadow persistence must not fail
        # the user-facing request path.
        return


def _source_job_root(job_id: str) -> Path:
    safe_job_id = re.sub(r"[^a-zA-Z0-9._-]+", "-", str(job_id or "").strip()) or "source-job"
    return SOURCE_UPLOADS_DIR / safe_job_id


def _sanitize_source_filename(filename: str) -> str:
    base = Path(str(filename or "").strip()).name
    cleaned = re.sub(r"[^a-zA-Z0-9._-]+", "-", base).strip("-._")
    return cleaned or "source.txt"


def _extract_pdf_text(raw_bytes: bytes) -> str:
    for module_name in ("pypdf", "PyPDF2"):
        try:
            module = __import__(module_name, fromlist=["PdfReader"])
        except Exception:
            continue
        reader_cls = getattr(module, "PdfReader", None)
        if reader_cls is None:
            continue
        try:
            reader = reader_cls(io.BytesIO(raw_bytes))
            text_parts: list[str] = []
            for page in getattr(reader, "pages", []) or []:
                try:
                    page_text = page.extract_text() if hasattr(page, "extract_text") else ""
                except Exception:
                    page_text = ""
                if page_text:
                    text_parts.append(str(page_text))
            combined = "\n\n".join(part.strip() for part in text_parts if part and str(part).strip())
            if combined.strip():
                return combined
        except Exception:
            continue
    return ""


def _extract_source_text(raw_bytes: bytes, *, file_name: str = "", content_type: str = "") -> str:
    file_hint = str(file_name or "").strip().lower()
    content_hint = str(content_type or "").strip().lower()
    if file_hint.endswith(".pdf") or content_hint == "application/pdf":
        pdf_text = _extract_pdf_text(raw_bytes)
        if pdf_text.strip():
            return pdf_text
    if file_hint.endswith(".docx") or content_hint == "application/vnd.openxmlformats-officedocument.wordprocessingml.document":
        try:
            with zipfile.ZipFile(io.BytesIO(raw_bytes)) as archive:
                document_xml = archive.read("word/document.xml")
            root = ET.fromstring(document_xml)
            text_parts: list[str] = []
            for node in root.iter():
                if node.text:
                    text_parts.append(node.text)
            text = "\n".join(part for part in text_parts if part.strip())
            if text.strip():
                return text
        except Exception:
            pass
    try:
        return raw_bytes.decode("utf-8")
    except UnicodeDecodeError:
        return raw_bytes.decode("utf-8", errors="ignore")


def _chunk_text_content(text: str, *, max_chars: int = 1800) -> list[dict[str, Any]]:
    body = str(text or "").strip()
    if not body:
        return []
    paragraphs = [part.strip() for part in re.split(r"\n\s*\n+", body) if part.strip()]
    chunks: list[dict[str, Any]] = []

    def append_chunk(chunk_text: str) -> None:
        chunk = chunk_text.strip()
        if not chunk:
            return
        chunks.append({
            "chunk_index": len(chunks) + 1,
            "text": chunk,
            "char_count": len(chunk),
        })

    buffer: list[str] = []
    buffer_len = 0
    iterable = paragraphs or [body]
    for paragraph in iterable:
        if not paragraph:
            continue
        if len(paragraph) > max_chars:
            if buffer:
                append_chunk("\n\n".join(buffer))
                buffer = []
                buffer_len = 0
            for start in range(0, len(paragraph), max_chars):
                append_chunk(paragraph[start:start + max_chars])
            continue
        projected_len = len(paragraph) if not buffer else buffer_len + 2 + len(paragraph)
        if buffer and projected_len > max_chars:
            append_chunk("\n\n".join(buffer))
            buffer = []
            buffer_len = 0
        buffer.append(paragraph)
        buffer_len = sum(len(item) for item in buffer) + max(0, (len(buffer) - 1) * 2)
    if buffer:
        append_chunk("\n\n".join(buffer))
    if not chunks:
        append_chunk(body)
    return chunks


def _source_records_from_state(state: dict[str, Any]) -> list[dict[str, Any]]:
    records = [
        _normalized_source_record(item)
        for item in _as_dict_list(state.get("sources"))
        if isinstance(item, dict)
    ]
    records.sort(
        key=lambda item: str(item.get("updated_at") or item.get("uploaded_at") or ""),
        reverse=True,
    )
    return records


def _source_jobs_from_state(state: dict[str, Any]) -> list[dict[str, Any]]:
    jobs = [
        _normalized_source_job_record(item)
        for item in _as_dict_list(state.get("source_jobs"))
        if isinstance(item, dict)
    ]
    jobs.sort(
        key=lambda item: str(item.get("updated_at") or item.get("queued_at") or ""),
        reverse=True,
    )
    return jobs


def _payload_state_for_meta(meta: dict[str, Any] | None) -> str:
    meta = meta or {}
    if meta.get("governance_error") or meta.get("blocked"):
        return "gated"
    if meta.get("full_payload") or meta.get("full_payload_coord"):
        return "full"
    if meta.get("kernel_projections"):
        return "projection"
    if meta.get("summary") or meta.get("attachment_summary"):
        return "skim"
    if meta.get("part_coordinates"):
        return "part_walk_required"
    return "skim"


def _normalized_source_record(record: dict[str, Any]) -> dict[str, Any]:
    normalized = dict(record)
    source_id = str(normalized.get("source_id") or "").strip()
    if not source_id:
        return normalized
    def _int_value(value: Any, default: int = 0) -> int:
        try:
            return int(str(value).strip() or default)
        except Exception:
            return default
    normalized["source_id"] = source_id
    normalized["canonical_subject"] = _canonical_subject_for_record("source", source_id, normalized.get("canonical_subject"))
    normalized["canonical_subject_source"] = str(normalized.get("canonical_subject_source") or "did:web:source").strip()
    normalized["status"] = str(normalized.get("status") or "queued").strip().lower() or "queued"
    normalized["file_name"] = str(normalized.get("file_name") or normalized.get("filename") or source_id).strip() or source_id
    normalized["job_id"] = str(normalized.get("job_id") or "").strip()
    normalized["ledger_id"] = str(normalized.get("ledger_id") or "").strip()
    normalized["principal_did"] = str(normalized.get("principal_did") or "").strip()
    normalized["content_type"] = str(normalized.get("content_type") or "application/octet-stream").strip() or "application/octet-stream"
    normalized["storage_path"] = str(normalized.get("storage_path") or "").strip()
    normalized["chunk_manifest_path"] = str(normalized.get("chunk_manifest_path") or "").strip()
    normalized["chunk_count"] = _int_value(normalized.get("chunk_count"), 0)
    normalized["size_bytes"] = _int_value(normalized.get("size_bytes"), 0)
    normalized["payload_state"] = str(normalized.get("payload_state") or "skim").strip() or "skim"
    normalized["full_payload_coord"] = str(normalized.get("full_payload_coord") or "").strip()
    normalized["projection_coordinates"] = [
        str(c) for c in _as_list(normalized.get("projection_coordinates")) if str(c).strip()
    ]
    return normalized


def _normalized_source_job_record(record: dict[str, Any]) -> dict[str, Any]:
    normalized = dict(record)
    job_id = str(normalized.get("job_id") or "").strip()
    if not job_id:
        return normalized
    def _int_value(value: Any, default: int = 0) -> int:
        try:
            return int(str(value).strip() or default)
        except Exception:
            return default
    normalized["job_id"] = job_id
    normalized["status"] = str(normalized.get("status") or "queued").strip().lower() or "queued"
    normalized["source_ids"] = [str(item).strip() for item in _as_list(normalized.get("source_ids")) if str(item).strip()]
    normalized["source_count"] = _int_value(normalized.get("source_count"), len(normalized["source_ids"]))
    normalized["progress_done"] = _int_value(normalized.get("progress_done"), 0)
    normalized["progress_total"] = _int_value(normalized.get("progress_total"), normalized["source_count"])
    normalized["ledger_id"] = str(normalized.get("ledger_id") or "").strip()
    normalized["principal_did"] = str(normalized.get("principal_did") or "").strip()
    normalized["queued_at"] = str(normalized.get("queued_at") or "").strip()
    normalized["started_at"] = str(normalized.get("started_at") or "").strip()
    normalized["completed_at"] = str(normalized.get("completed_at") or "").strip()
    normalized["updated_at"] = str(normalized.get("updated_at") or normalized.get("queued_at") or "").strip()
    normalized["failure_message"] = str(normalized.get("failure_message") or "").strip()
    return normalized


def _schedule_source_job(job_id: str) -> None:
    safe_job_id = str(job_id or "").strip()
    if not safe_job_id:
        return
    existing = _SOURCE_JOB_TASKS.get(safe_job_id)
    if existing is not None and not existing.done():
        return
    task = asyncio.create_task(_process_source_job(safe_job_id))
    _SOURCE_JOB_TASKS[safe_job_id] = task

    def _cleanup(_task: asyncio.Task[None]) -> None:
        _SOURCE_JOB_TASKS.pop(safe_job_id, None)

    task.add_done_callback(_cleanup)


async def _process_source_job(job_id: str) -> None:
    job_id = str(job_id or "").strip()
    if not job_id:
        return
    await asyncio.sleep(0)
    state = _load_control_plane_state()
    jobs = _source_jobs_from_state(state)
    job = next((item for item in jobs if str(item.get("job_id") or "").strip() == job_id), None)
    if not isinstance(job, dict):
        return
    now = datetime.now(timezone.utc).isoformat()
    job["status"] = "running"
    job["started_at"] = job.get("started_at") or now
    job["updated_at"] = now
    state["source_jobs"] = _upsert_control_plane_record(_as_dict_list(state.get("source_jobs")), "job_id", job)
    _save_control_plane_state(state)

    source_ids = [str(item).strip() for item in _as_list(job.get("source_ids")) if str(item).strip()]
    processed = 0
    for source_id in source_ids:
        current_state = _load_control_plane_state()
        sources = _source_records_from_state(current_state)
        source = next((item for item in sources if str(item.get("source_id") or "").strip() == source_id), None)
        if not isinstance(source, dict):
            continue
        source["status"] = "running"
        source["updated_at"] = datetime.now(timezone.utc).isoformat()
        current_state["sources"] = _upsert_control_plane_record(_as_dict_list(current_state.get("sources")), "source_id", source)
        _save_control_plane_state(current_state)
        try:
            raw_path = Path(str(source.get("storage_path") or "").strip())
            raw_bytes = raw_path.read_bytes()
            text = _extract_source_text(
                raw_bytes,
                file_name=str(source.get("file_name") or raw_path.name),
                content_type=str(source.get("content_type") or ""),
            )
            chunks = _chunk_text_content(text)
            source_dir = _source_job_root(job_id) / "chunks"
            source_dir.mkdir(parents=True, exist_ok=True)
            manifest_path = source_dir / f"{source_id}.json"
            manifest = {
                "job_id": job_id,
                "source_id": source_id,
                "file_name": source.get("file_name") or raw_path.name,
                "chunk_count": len(chunks),
                "chunks": chunks,
                "updated_at": datetime.now(timezone.utc).isoformat(),
            }
            manifest_path.write_text(json.dumps(manifest, indent=2, sort_keys=True), encoding="utf-8")
            source.update(
                {
                    "status": "ready",
                    "chunk_count": len(chunks),
                    "chunk_manifest_path": str(manifest_path),
                    "content_excerpt": (chunks[0]["text"] if chunks else text[:280]).strip(),
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                    "completed_at": datetime.now(timezone.utc).isoformat(),
                }
            )
            processed += 1
        except Exception as exc:
            source.update(
                {
                    "status": "failed",
                    "error_message": str(exc),
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                }
            )
            current_state["sources"] = _upsert_control_plane_record(_as_dict_list(current_state.get("sources")), "source_id", source)
            current_state_job = _load_control_plane_state()
            job_update = next((item for item in _source_jobs_from_state(current_state_job) if str(item.get("job_id") or "").strip() == job_id), None)
            if isinstance(job_update, dict):
                job_update.update(
                    {
                        "status": "failed",
                        "failure_message": str(exc),
                        "updated_at": datetime.now(timezone.utc).isoformat(),
                    }
                )
                current_state_job["source_jobs"] = _upsert_control_plane_record(_as_dict_list(current_state_job.get("source_jobs")), "job_id", job_update)
                _save_control_plane_state(current_state_job)
            return
        current_state["sources"] = _upsert_control_plane_record(_as_dict_list(current_state.get("sources")), "source_id", source)
        _save_control_plane_state(current_state)

    final_state = _load_control_plane_state()
    final_job = next((item for item in _source_jobs_from_state(final_state) if str(item.get("job_id") or "").strip() == job_id), None)
    if isinstance(final_job, dict):
        final_job.update(
            {
                "status": "completed",
                "progress_done": processed,
                "progress_total": len(source_ids),
                "completed_at": datetime.now(timezone.utc).isoformat(),
                "updated_at": datetime.now(timezone.utc).isoformat(),
            }
        )
        final_state["source_jobs"] = _upsert_control_plane_record(_as_dict_list(final_state.get("source_jobs")), "job_id", final_job)
        _save_control_plane_state(final_state)


def _parse_timestamp(value: Any) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        normalized = text.replace("Z", "+00:00")
        parsed = datetime.fromisoformat(normalized)
    except Exception:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _normalize_benchmark_publication_payload(payload: Any) -> dict[str, Any]:
    phase_1_activation: dict[str, Any] = {}
    operator_publication: dict[str, Any] = {}
    canonical_publication_source: dict[str, Any] = {}
    if isinstance(payload, dict):
        runs = payload.get("runs")
        publication_note = str(payload.get("note") or "").strip()
        phase_1_activation = _as_dict(payload.get("phase_1_activation"))
        operator_publication = _as_dict(payload.get("operator_publication"))
        canonical_publication_source = _as_dict(payload.get("canonical_publication_source"))
    elif isinstance(payload, list):
        runs = payload
        publication_note = ""
    else:
        return {"status": "error", "runs": [], "detail": "Benchmark publication must be a list or an object with a runs array."}
    normalized_runs = [item for item in runs if isinstance(item, dict)] if isinstance(runs, list) else []
    normalized_runs.sort(
        key=lambda item: _parse_timestamp(item.get("executed_at")) or datetime.min.replace(tzinfo=timezone.utc),
        reverse=True,
    )
    if not normalized_runs:
        return {
            "status": "empty",
            "runs": [],
            "detail": publication_note or "Benchmark publication contains no runs.",
            "phase_1_activation": phase_1_activation,
            "operator_publication": operator_publication,
            "canonical_publication_source": canonical_publication_source,
        }
    return {
        "status": "ok",
        "runs": normalized_runs,
        "detail": publication_note,
        "phase_1_activation": phase_1_activation,
        "operator_publication": operator_publication,
        "canonical_publication_source": canonical_publication_source,
    }


def _load_benchmark_publication() -> dict[str, Any]:
    try:
        raw = BENCHMARK_PUBLICATION_PATH.read_text(encoding="utf-8")
    except FileNotFoundError:
        return {"status": "empty", "runs": [], "detail": "No benchmark publication file is available yet."}
    except Exception as exc:
        return {"status": "error", "runs": [], "detail": f"Unable to read benchmark publication: {exc}"}
    try:
        payload = json.loads(raw)
    except Exception as exc:
        return {"status": "error", "runs": [], "detail": f"Benchmark publication is not valid JSON: {exc}"}
    return _normalize_benchmark_publication_payload(payload)


def _load_benchmark_visualizations() -> dict[str, Any]:
    try:
        raw = BENCHMARK_VISUALIZATIONS_PATH.read_text(encoding="utf-8")
    except FileNotFoundError:
        return {}
    except Exception as exc:
        return {"error": f"Unable to read benchmark visualizations: {exc}"}
    try:
        return json.loads(raw)
    except Exception as exc:
        return {"error": f"Benchmark visualizations are not valid JSON: {exc}"}


async def _load_backend_benchmark_publication(request: Request) -> dict[str, Any]:
    status_code, body = await _backend_admin_get(
        "/api/control-plane/benchmarks/publication",
        extra_headers=_backend_admin_auth_headers_from_request(request),
    )
    if status_code >= 400:
        detail = str(
            body.get("message")
            or body.get("failure_message")
            or body.get("reason")
            or body.get("detail")
            or body.get("error")
            or BENCHMARK_FAILED_LOAD_COPY
        ).strip() or BENCHMARK_FAILED_LOAD_COPY
        return {
            "status": "error",
            "runs": [],
            "detail": detail,
            "phase_1_activation": _as_dict(body.get("phase_1_activation")),
            "operator_publication": _as_dict(body.get("operator_publication")),
            "canonical_publication_source": _as_dict(body.get("source_contract")),
            "publication_config": _as_dict(body.get("config")),
        }
    publication = _as_dict(body.get("publication"))
    normalized = _normalize_benchmark_publication_payload(publication)
    normalized["canonical_publication_source"] = _as_dict(
        body.get("source_contract") or normalized.get("canonical_publication_source")
    )
    normalized["publication_config"] = _as_dict(body.get("config"))
    return normalized


def _benchmark_dataset_signature(run: Mapping[str, Any]) -> tuple[str, str, str]:
    datasets = run.get("datasets")
    if isinstance(datasets, list) and datasets:
        first = datasets[0] if isinstance(datasets[0], dict) else {}
    else:
        first = {}
    return (
        str(first.get("name") or "").strip(),
        str(first.get("version") or "").strip(),
        str(first.get("split") or "").strip(),
    )


def _select_benchmark_baseline(runs: list[dict[str, Any]], latest: Mapping[str, Any]) -> dict[str, Any] | None:
    latest_signature = _benchmark_dataset_signature(latest)
    latest_mode = str(latest.get("mode") or "").strip()
    latest_schema = str(latest.get("artefact_schema_version") or "").strip()
    latest_suite = str(latest.get("suite_id") or "").strip()
    for candidate in runs[1:]:
        if str(candidate.get("suite_id") or "").strip() != latest_suite:
            continue
        if str(candidate.get("artefact_schema_version") or "").strip() != latest_schema:
            continue
        if _benchmark_dataset_signature(candidate) != latest_signature:
            continue
        candidate_mode = str(candidate.get("mode") or "").strip()
        if candidate_mode and candidate_mode != latest_mode:
            return candidate
    return runs[1] if len(runs) > 1 else None


def _benchmark_metric_groups(run: Mapping[str, Any]) -> dict[str, Any]:
    metrics = run.get("metrics")
    return metrics if isinstance(metrics, dict) else {}


def _render_metric_group_list(run: Mapping[str, Any], group_names: list[str]) -> str:
    metrics = _benchmark_metric_groups(run)
    parts: list[str] = []
    for group_name in group_names:
        group = metrics.get(group_name)
        if not isinstance(group, dict):
            parts.append(f"<div><strong>{html.escape(group_name.title())}</strong><p class=\"muted\">{html.escape(BENCHMARK_UNPUBLISHED_COPY)}</p></div>")
            continue
        group_status = str(group.get("status") or "absent").strip().lower()
        if group_status == "absent":
            parts.append(
                f"<div><strong>{html.escape(group_name.title())}</strong><p class=\"muted\">{html.escape(BENCHMARK_UNPUBLISHED_COPY)}</p></div>"
            )
            continue
        if group_status == "failed":
            reason = str(group.get("failure_reason") or group.get("absence_reason") or "Metric publication failed for this run.").strip()
            parts.append(
                f"<div><strong>{html.escape(group_name.title())}</strong><p class=\"muted\">Failed: {html.escape(reason)}</p></div>"
            )
            continue
        group_metrics = group.get("metrics")
        if not isinstance(group_metrics, dict) or not group_metrics:
            parts.append(f"<div><strong>{html.escape(group_name.title())}</strong><p class=\"muted\">{html.escape(BENCHMARK_UNPUBLISHED_COPY)}</p></div>")
            continue
        rows: list[str] = []
        for key, value in group_metrics.items():
            if not isinstance(value, dict):
                continue
            metric_value = value.get("value")
            unit = str(value.get("unit") or "").strip()
            statistics = _as_dict(value.get("statistics"))
            plain_english = ""
            metric_key = str(key).strip().lower()
            if group_name == "retrieval" and metric_key == "recall_at_10":
                plain_english = "Shows whether the right evidence was found within the first ten results."
            elif group_name == "retrieval" and metric_key == "mrr":
                plain_english = "Shows how strongly the right evidence was ranked near the top of the result list."
            elif group_name == "latency" and metric_key == "avg_latency_ms":
                plain_english = "Shows how quickly the retrieval path completed on average in this run."
            elif group_name == "cost":
                plain_english = "Shows the current operational cost signal for this benchmark run."
            display_value = _as_float(metric_value) if metric_value is not None else None
            display_text = _benchmark_metric_display(display_value, unit=unit, statistics=statistics)
            error_bar = _render_metric_error_bar(statistics)
            rows.append(
                "<li class=\"benchmark-metric-row\">"
                f"<div class=\"benchmark-metric-name\">{html.escape(str(key))}</div>"
                f"<div class=\"benchmark-metric-value\">{html.escape(display_text)}</div>"
                f'{error_bar}'
                + (f'<p class="muted" style="margin:6px 0 0 0;">{html.escape(plain_english)}</p>' if plain_english else "")
                + "</li>"
            )
        content = "<ul>" + "".join(rows) + "</ul>" if rows else '<p class="muted">No metrics published.</p>'
        parts.append(f"<div><strong>{html.escape(group_name.title())}</strong>{content}</div>")
    return "".join(parts)


def _benchmark_run_flags(run: Mapping[str, Any]) -> list[str]:
    flags: list[str] = []
    status = str(run.get("status") or "").strip().lower()
    if status == "partial":
        flags.append("Partial results")
    elif status == "failed":
        flags.append("Failed run")
    freshness = run.get("freshness")
    if isinstance(freshness, dict) and str(freshness.get("status") or "").strip().lower() == "stale":
        flags.append("Stale publication")
    return flags


def _benchmark_status_label(run: Mapping[str, Any]) -> str:
    status = str(run.get("status") or "unknown").strip().lower()
    mapping = {
        "complete": "Complete run",
        "partial": "Partial run",
        "pending": "Pending run",
        "failed": "Failed run",
    }
    return mapping.get(status, "Unknown run status")


def _benchmark_status_tone(run: Mapping[str, Any]) -> str:
    status = str(run.get("status") or "").strip().lower()
    if status == "complete":
        return "success"
    if status == "failed":
        return "danger"
    return "pending"


def _benchmark_mode_label(mode: str) -> str:
    normalized = mode.strip().lower()
    labels = {
        "full_dss": "DSS full mode",
        "semantic_only": "Standard semantic retrieval",
        "coordinate_guided": "DSS coordinate-guided mode",
    }
    return labels.get(normalized, mode.replace("_", " ").strip().title() or "Unknown mode")


