    summary = (
        f"<p class=\"muted\">Phase 1 suite status as of {html.escape(checked_at)}.</p>"
        if checked_at
        else "<p class=\"muted\">Phase 1 suite activation is derived from published benchmark artefacts.</p>"
    )
    rows = []
    for item in suite_activation:
        suite_name = str(item.get("suite_name") or "").strip()
        family = str(item.get("family") or "").strip().replace("_", " ")
        status = BENCHMARK_SUITE_STATUS_COPY.get(str(item.get("status") or "").strip(), str(item.get("status") or "").strip())
        freshness = str(item.get("freshness_status") or "").strip().replace("_", " ").title()
        published_modes = ", ".join(str(mode) for mode in _as_list(item.get("published_modes"))) or "None"
