def _run_has_statistics(run: Mapping[str, Any]) -> bool:
    """Return True if any metric in the run carries aggregate statistics."""
    metrics = _benchmark_metric_groups(run)
    for group in metrics.values():
        if not isinstance(group, dict) or group.get("status") != "present":
            continue
        group_metrics = group.get("metrics")
        if not isinstance(group_metrics, dict):
            continue
        for entry in group_metrics.values():
            if isinstance(entry, dict) and isinstance(entry.get("statistics"), dict):
                return True
    return False


def _run_is_blocked(run: Mapping[str, Any]) -> bool:
    """Return True if the run was explicitly blocked (e.g., missing API key)."""
    run_config = _as_dict(run.get("run_config"))
    return bool(run_config.get("blocked"))


def _render_benchmark_averaged_results(page_data: Mapping[str, Any]) -> str:
    """Render aggregate runs with statistics and error bars."""
    runs = _as_dict_list(page_data.get("recent_runs"))
    aggregate_runs = [run for run in runs if _run_has_statistics(run) and not _run_is_blocked(run)]
    display_runs = aggregate_runs[:2] if len(aggregate_runs) >= 2 else (aggregate_runs[:1] if aggregate_runs else runs[:1])
    if not display_runs:
        return ""
    columns: list[str] = []
    for run in display_runs:
        title = f"{_benchmark_mode_label(str(run.get('mode') or ''))} — {html.escape(str(run.get('suite_id') or 'unknown'))}"
        metrics_html = _render_metric_group_list(run, ["retrieval", "latency", "cost"])
        columns.append(
            f"""
            <div class="benchmark-averaged-column">
              <h3>{html.escape(title)}</h3>
              {metrics_html}
            </div>
            """
        )
    if len(columns) == 1:
        columns.append(
            '<div class="benchmark-averaged-column"><p class="muted">No comparable baseline aggregate run is published yet.</p></div>'
        )
    return f"""
    <section class="card benchmark-section benchmark-averaged">
      <h2>Averaged results with error bars</h2>
      <p class="muted">Aggregate runs report mean ± standard deviation and 95% confidence intervals across random seeds.</p>
      <div class="grid benchmark-averaged-grid">
        {"".join(columns)}
      </div>
    </section>
    """


def _render_benchmark_visualizations() -> str:
    """Render recall-vs-context and latency-trade-off SVG charts."""
    data = _load_benchmark_visualizations()
    if not isinstance(data, dict) or "error" in data:
        return ""
    recall_ctx = _as_dict_list(data.get("recall_vs_context"))
    latency_trade = _as_dict_list(data.get("latency_tradeoff"))
    if not recall_ctx and not latency_trade:
        return ""

    def _mode_color(mode: str) -> str:
        mode_norm = mode.strip().lower()
        if mode_norm == "full_dss":
            return "#2563eb"
        if mode_norm == "coordinate_guided":
            return "#0ea5e9"
        return "#94a3b8"

    charts: list[str] = []

    if recall_ctx:
        width, height = 600, 320
        margin = {"top": 30, "right": 30, "bottom": 70, "left": 60}
        inner_w = width - margin["left"] - margin["right"]
        inner_h = height - margin["top"] - margin["bottom"]
        n = len(recall_ctx)
        band = inner_w / max(n, 1)
        bar_w = band * 0.5
        y_max = 1.0
        y_scale = inner_h / y_max
        bars = []
        labels = []
        for i, item in enumerate(recall_ctx):
            mode = str(item.get("mode") or f"mode-{i}")
            val = _as_float(item.get("recall_at_k"))
            if val is None:
                val = 0.0
            x = margin["left"] + i * band + (band - bar_w) / 2
            y = margin["top"] + inner_h - val * y_scale
            h = val * y_scale
            bars.append(
                f'<rect x="{x:.1f}" y="{y:.1f}" width="{bar_w:.1f}" height="{h:.1f}" fill="{_mode_color(mode)}" rx="4"/>'
            )
            labels.append(
                f'<text x="{x + bar_w / 2:.1f}" y="{margin["top"] + inner_h + 20:.1f}" text-anchor="middle" class="benchmark-chart-label">{html.escape(mode)}</text>'
            )
            labels.append(
                f'<text x="{x + bar_w / 2:.1f}" y="{y - 8:.1f}" text-anchor="middle" class="benchmark-chart-value">{val:.2f}</text>'
            )
        # Axis ticks for y
        y_ticks = []
        for tick in [0.0, 0.25, 0.5, 0.75, 1.0]:
            y = margin["top"] + inner_h - tick * y_scale
            y_ticks.append(f'<line x1="{margin["left"]:.1f}" y1="{y:.1f}" x2="{margin["left"] + inner_w:.1f}" y2="{y:.1f}" class="benchmark-chart-grid"/>')
            y_ticks.append(f'<text x="{margin["left"] - 10:.1f}" y="{y + 4:.1f}" text-anchor="end" class="benchmark-chart-label">{tick:.2f}</text>')
        total_tokens = int(recall_ctx[0].get("context_tokens") or 0) if recall_ctx else 0
        charts.append(f"""
        <div class="benchmark-chart-card">
          <h3>Recall vs context length</h3>
          <p class="muted">Long-context retrieval at {total_tokens:,} tokens.</p>
          <svg viewBox="0 0 {width} {height}" class="benchmark-chart">
            {"".join(y_ticks)}
            {"".join(bars)}
            {"".join(labels)}
            <line x1="{margin['left']:.1f}" y1="{margin['top'] + inner_h:.1f}" x2="{margin['left'] + inner_w:.1f}" y2="{margin['top'] + inner_h:.1f}" class="benchmark-chart-axis"/>
            <line x1="{margin['left']:.1f}" y1="{margin['top']:.1f}" x2="{margin['left']:.1f}" y2="{margin['top'] + inner_h:.1f}" class="benchmark-chart-axis"/>
            <text x="{width / 2:.1f}" y="{height - 10:.1f}" text-anchor="middle" class="benchmark-chart-label">DSS mode</text>
            <text x="{18:.1f}" y="{height / 2:.1f}" text-anchor="middle" transform="rotate(-90 {18} {height / 2:.1f})" class="benchmark-chart-label">Recall@k</text>
          </svg>
        </div>
        """)

    if latency_trade:
        width, height = 600, 320
        margin = {"top": 30, "right": 30, "bottom": 70, "left": 70}
        inner_w = width - margin["left"] - margin["right"]
        inner_h = height - margin["top"] - margin["bottom"]
        x_vals = [_as_float(item.get("avg_latency_ms")) for item in latency_trade]
        y_vals = [_as_float(item.get("recall_at_k")) for item in latency_trade]
        x_min = 0.0
        x_max = max([v for v in x_vals if v is not None] or [1.0]) * 1.15
        y_min = 0.0
        y_max = max([v for v in y_vals if v is not None] or [1.0]) * 1.15
        if y_max < 1.0:
            y_max = 1.0
        if x_max == 0:
            x_max = 1.0
        x_scale = inner_w / x_max
        y_scale = inner_h / y_max
        points = []
        labels = []
        for item in latency_trade:
            condition = str(item.get("condition") or item.get("mode") or "")
            x = _as_float(item.get("avg_latency_ms"))
            y = _as_float(item.get("recall_at_k"))
            if x is None or y is None:
                continue
            px = margin["left"] + x * x_scale
            py = margin["top"] + inner_h - y * y_scale
            mode = str(item.get("mode") or "")
            points.append(f'<circle cx="{px:.1f}" cy="{py:.1f}" r="6" fill="{_mode_color(mode)}" stroke="#fff" stroke-width="2"/>')
            labels.append(f'<text x="{px + 10:.1f}" y="{py + 4:.1f}" class="benchmark-chart-label">{html.escape(condition)}</text>')
        # Axes
        x_ticks = []
        for tick in [0, x_max / 2, x_max]:
            tx = margin["left"] + tick * x_scale
            x_ticks.append(f'<line x1="{tx:.1f}" y1="{margin["top"]:.1f}" x2="{tx:.1f}" y2="{margin["top"] + inner_h:.1f}" class="benchmark-chart-grid"/>')
            x_ticks.append(f'<text x="{tx:.1f}" y="{margin["top"] + inner_h + 20:.1f}" text-anchor="middle" class="benchmark-chart-label">{tick:.2f}</text>')
        y_ticks = []
        for tick in [0, y_max / 2, y_max]:
            ty = margin["top"] + inner_h - tick * y_scale
            y_ticks.append(f'<line x1="{margin["left"]:.1f}" y1="{ty:.1f}" x2="{margin["left"] + inner_w:.1f}" y2="{ty:.1f}" class="benchmark-chart-grid"/>')
            y_ticks.append(f'<text x="{margin["left"] - 10:.1f}" y="{ty + 4:.1f}" text-anchor="end" class="benchmark-chart-label">{tick:.2f}</text>')
        charts.append(f"""
        <div class="benchmark-chart-card">
          <h3>Latency vs recall trade-off</h3>
          <p class="muted">Each point is an ablation condition averaged across 3 seeds.</p>
          <svg viewBox="0 0 {width} {height}" class="benchmark-chart">
            {"".join(x_ticks)}
            {"".join(y_ticks)}
            {"".join(points)}
            {"".join(labels)}
            <line x1="{margin['left']:.1f}" y1="{margin['top'] + inner_h:.1f}" x2="{margin['left'] + inner_w:.1f}" y2="{margin['top'] + inner_h:.1f}" class="benchmark-chart-axis"/>
            <line x1="{margin['left']:.1f}" y1="{margin['top']:.1f}" x2="{margin['left']:.1f}" y2="{margin['top'] + inner_h:.1f}" class="benchmark-chart-axis"/>
            <text x="{width / 2:.1f}" y="{height - 10:.1f}" text-anchor="middle" class="benchmark-chart-label">Avg latency (ms)</text>
            <text x="{18:.1f}" y="{height / 2:.1f}" text-anchor="middle" transform="rotate(-90 {18} {height / 2:.1f})" class="benchmark-chart-label">Recall@k</text>
          </svg>
        </div>
        """)

    return f"""
    <section class="card benchmark-section benchmark-visualizations">
      <h2>Visualisations</h2>
      <div class="grid benchmark-charts-grid">
        {"".join(charts)}
      </div>
    </section>
    """


