def _about_section_tabs(current_section: str) -> str:
    tabs = [
        ("about", "About"),
        ("overview", "Overview"),
    ]
    links: list[str] = []
    for value, label in tabs:
        href = f"/benchmarks?section={quote(value, safe='')}"
        cls = "page-tab active" if value == current_section else "page-tab"
        links.append(f'<a class="{cls}" href="{href}">{html.escape(label)}</a>')
    return f'<nav class="page-tabs" aria-label="About sections">{"".join(links)}</nav>'


def _render_about_overview_content() -> str:
    return """
    <section class="card benchmark-about-intro">
      <p><strong>DSS</strong> is a coordinate-guided memory architecture for long-context AI systems. Unlike standard semantic retrieval, every memory access is bound to a verifiable coordinate path — you can inspect, challenge, and replay any retrieval decision.</p>
      <p>This benchmark suite tests whether that structure actually wins: multi-session memory continuity, reasoning over retrieved context, and traceable provenance.</p>
    </section>
    """


def render_about_benchmarks_page(*, publication: Mapping[str, Any], current_section: str) -> str:
    section = _normalize_benchmark_about_section(current_section)
    breadcrumbs_html = render_breadcrumbs([("Home", "/"), ("About", None)])
    if section == "about":
        header_html = render_page_header(
            title="DSS Benchmark Suite v0.3",
            description="Coordinate-guided memory vs. semantic-only retrieval",
        )
        content_html = _render_benchmark_about_content()
    else:
        header_html = render_page_header(
            title="DSS Benchmark Suite v0.3 — Full Results",
            description="",
        )
        content_html = render_benchmarks_page(publication=publication)
    tabs_html = _about_section_tabs(section)
    return f"""
      {breadcrumbs_html}
      {header_html}
      {tabs_html}
      {content_html}
      """


def _coalesce(*values: Any) -> str:
    for value in values:
        text = str(value or "").strip()
        if text:
            return text
    return ""


def _as_dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


def _as_list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


def _as_dict_list(value: Any) -> list[dict[str, Any]]:
    return [item for item in value if isinstance(item, dict)] if isinstance(value, list) else []


async def _shared_http_client() -> httpx.AsyncClient:
    global _SHARED_HTTP_CLIENT
    if _SHARED_HTTP_CLIENT is None:
        _SHARED_HTTP_CLIENT = httpx.AsyncClient(
            timeout=20.0,
            limits=httpx.Limits(max_connections=100, max_keepalive_connections=20),
            headers={"accept": "application/json"},
        )
    return _SHARED_HTTP_CLIENT


async def _startup_http_client() -> None:
    await _shared_http_client()


async def _shutdown_http_client() -> None:
    global _SHARED_HTTP_CLIENT
    if _SHARED_HTTP_CLIENT is not None:
        await _SHARED_HTTP_CLIENT.aclose()
        _SHARED_HTTP_CLIENT = None


@asynccontextmanager
async def _app_lifespan(_: Starlette):
    await _startup_http_client()
    try:
        yield
    finally:
        await _shutdown_http_client()


def _normalized_principal_record(record: dict[str, Any]) -> dict[str, Any]:
    normalized = dict(record)
    metadata = dict(_as_dict(normalized.get("metadata")))
    actor_type = str(metadata.get("actor_type") or normalized.get("principal_type") or "").strip().lower()
    if actor_type == "model":
        provider_type = str(metadata.get("provider_type") or "openrouter").strip().lower() or "openrouter"
        model_id = str(metadata.get("model_id") or metadata.get("model_name") or "").strip()
        if model_id:
            canonical_did = _frontend_model_principal_did(provider_type, model_id)
            normalized["principal_did"] = canonical_did
            normalized["canonical_subject"] = canonical_did
            normalized["canonical_subject_source"] = "did:web:model-principal"
            metadata["provider_type"] = str(metadata.get("provider_type") or "OpenRouter").strip() or "OpenRouter"
            metadata["model_id"] = model_id
    elif str(normalized.get("principal_did") or "").strip().startswith("did:"):
        normalized["canonical_subject"] = str(normalized.get("canonical_subject") or normalized.get("principal_did") or "").strip()
        normalized["canonical_subject_source"] = str(normalized.get("canonical_subject_source") or "principal_did").strip()
    if metadata:
        normalized["metadata"] = metadata
    return normalized


def _canonical_subject_for_record(entity_type: str, entity_id: str, candidate: Any) -> str:
    value = str(candidate or "").strip()
    if value and not value.startswith("did:web:legacy.local:"):
        return value
    return _canonical_entity_subject(entity_type, entity_id)


def _normalized_control_plane_state(payload: dict[str, Any]) -> dict[str, Any]:
    normalized = _default_control_plane_state()
    for item in _as_dict_list(payload.get("providers")):
        provider_id = str(item.get("provider_id") or "").strip()
        if not provider_id:
            continue
        record = dict(item)
        record["canonical_subject"] = _canonical_subject_for_record("provider", provider_id, record.get("canonical_subject"))
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or "did:web:provider").strip()
        normalized["providers"] = _upsert_control_plane_record(normalized["providers"], "provider_id", record)
    for item in _as_dict_list(payload.get("model_bindings")):
        binding_id = str(item.get("binding_id") or "").strip()
        if not binding_id:
            continue
        record = dict(item)
        record["canonical_subject"] = _canonical_subject_for_record("binding", binding_id, record.get("canonical_subject"))
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or "did:web:binding").strip()
        normalized["model_bindings"] = _upsert_control_plane_record(normalized["model_bindings"], "binding_id", record)
    for item in _as_dict_list(payload.get("app_surfaces")):
        surface_id = str(item.get("surface_id") or "").strip()
        if not surface_id:
            continue
        record = dict(item)
        metadata = dict(_as_dict(record.get("metadata")))
        canonical_subject = _canonical_subject_for_record("surface", surface_id, record.get("canonical_subject") or metadata.get("canonical_subject"))
        record["canonical_subject"] = canonical_subject
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or metadata.get("canonical_subject_source") or "did:web:surface").strip()
        metadata["canonical_subject"] = canonical_subject
        metadata["canonical_subject_source"] = record["canonical_subject_source"]
        if metadata:
            record["metadata"] = metadata
        normalized["app_surfaces"] = _upsert_control_plane_record(normalized["app_surfaces"], "surface_id", record)
    for item in _as_dict_list(payload.get("manual_ledgers")):
        ledger_id = str(item.get("ledger_id") or "").strip()
        if not ledger_id:
            continue
        record = dict(item)
        record["namespace"] = str(record.get("namespace") or ledger_id).strip() or ledger_id
        record["canonical_subject"] = _canonical_subject_for_record("ledger", ledger_id, record.get("canonical_subject"))
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or "did:web:ledger").strip()
        normalized["manual_ledgers"] = _upsert_control_plane_record(normalized["manual_ledgers"], "ledger_id", record)
    for item in _as_dict_list(payload.get("manual_principals")):
        record = _normalized_principal_record(item)
        principal_did = str(record.get("principal_did") or "").strip()
        if not principal_did:
            continue
        normalized["manual_principals"] = _upsert_control_plane_record(normalized["manual_principals"], "principal_did", record)
    normalized["entity_settings"] = _as_dict_list(payload.get("entity_settings"))
    for item in _as_dict_list(payload.get("relationships")):
        relationship_id = str(item.get("relationship_id") or "").strip()
        if not relationship_id:
            continue
        record = dict(item)
        record["canonical_subject"] = _canonical_subject_for_record("relationship", relationship_id, record.get("canonical_subject"))
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or "did:web:relationship").strip()
        normalized["relationships"] = _upsert_control_plane_record(normalized["relationships"], "relationship_id", record)
    for item in _as_dict_list(payload.get("sources")):
        source_id = str(item.get("source_id") or "").strip()
        if not source_id:
            continue
        record = dict(item)
        record["canonical_subject"] = _canonical_subject_for_record("source", source_id, record.get("canonical_subject"))
        record["canonical_subject_source"] = str(record.get("canonical_subject_source") or "did:web:source").strip()
        normalized["sources"] = _upsert_control_plane_record(normalized["sources"], "source_id", record)
    for item in _as_dict_list(payload.get("source_jobs")):
        job_id = str(item.get("job_id") or "").strip()
        if not job_id:
            continue
        record = dict(item)
        normalized["source_jobs"] = _upsert_control_plane_record(normalized["source_jobs"], "job_id", record)
    return normalized


def _response_body_text(response: Response) -> str:
    body = response.body
    if isinstance(body, memoryview):
        return body.tobytes().decode("utf-8")
    if isinstance(body, (bytes, bytearray)):
        return bytes(body).decode("utf-8")
    return str(body)


def _upsert_control_plane_record(records: list[dict[str, Any]], key: str, payload: dict[str, Any]) -> list[dict[str, Any]]:
    record_id = str(payload.get(key) or "").strip()
    if not record_id:
        return records
    updated = False
    next_records: list[dict[str, Any]] = []
    for item in records:
        if not isinstance(item, dict):
            continue
        if str(item.get(key) or "").strip() == record_id:
            merged = dict(item)
            merged.update(payload)
            next_records.append(merged)
            updated = True
        else:
            next_records.append(item)
    if not updated:
        next_records.append(payload)
    return next_records


def _remove_control_plane_state_entity(entity_type: str, entity_id: str) -> None:
    state = _load_control_plane_state()
    entity_key = str(entity_type or "").strip().lower()
    entity_value = str(entity_id or "").strip()
    if entity_key not in {"ledger", "principal", "surface"} or not entity_value:
        return

    state["relationships"] = [
        item for item in _as_dict_list(state.get("relationships"))
        if not (
            (str(item.get("subject_entity_type") or "").strip().lower() == entity_key and str(item.get("subject_entity_id") or "").strip() == entity_value)
            or (str(item.get("object_entity_type") or "").strip().lower() == entity_key and str(item.get("object_entity_id") or "").strip() == entity_value)
        )
    ]
    state["entity_settings"] = [
        item for item in _as_dict_list(state.get("entity_settings"))
        if not (str(item.get("entity_type") or "").strip().lower() == entity_key and str(item.get("entity_id") or "").strip() == entity_value)
    ]

    if entity_key == "ledger":
        state["manual_ledgers"] = [
            item for item in _as_dict_list(state.get("manual_ledgers"))
            if str(item.get("ledger_id") or "").strip() != entity_value
        ]
        updated_surfaces: list[dict[str, Any]] = []
        for item in _as_dict_list(state.get("app_surfaces")):
            record = dict(item)
            if str(record.get("ledger_id") or "").strip() == entity_value:
                record["ledger_id"] = None
            updated_surfaces.append(record)
        state["app_surfaces"] = updated_surfaces

        updated_principals: list[dict[str, Any]] = []
        for item in _as_dict_list(state.get("manual_principals")):
            record = dict(item)
            metadata = dict(_as_dict(record.get("metadata")))
            if str(record.get("ledger_id") or "").strip() == entity_value:
                record["ledger_id"] = None
            if str(metadata.get("ledger_id") or "").strip() == entity_value:
                metadata.pop("ledger_id", None)
                record["metadata"] = metadata
            updated_principals.append(record)
        state["manual_principals"] = updated_principals
        updated_sources: list[dict[str, Any]] = []
        for item in _as_dict_list(state.get("sources")):
            record = dict(item)
            if str(record.get("ledger_id") or "").strip() == entity_value:
                record["ledger_id"] = ""
            updated_sources.append(record)
        state["sources"] = updated_sources

    elif entity_key == "principal":
        state["manual_principals"] = [
            item for item in _as_dict_list(state.get("manual_principals"))
            if str(item.get("principal_did") or "").strip() != entity_value
        ]
        updated_surfaces = []
        for item in _as_dict_list(state.get("app_surfaces")):
            record = dict(item)
            if str(record.get("principal_did") or "").strip() == entity_value:
                record["principal_did"] = None
            updated_surfaces.append(record)
        state["app_surfaces"] = updated_surfaces

        updated_bindings: list[dict[str, Any]] = []
        for item in _as_dict_list(state.get("model_bindings")):
            record = dict(item)
            if str(record.get("linked_model_principal") or "").strip() == entity_value:
                record["linked_model_principal"] = None
            updated_bindings.append(record)
        state["model_bindings"] = updated_bindings
        updated_sources = []
        for item in _as_dict_list(state.get("sources")):
            record = dict(item)
            if str(record.get("principal_did") or "").strip() == entity_value:
                record["principal_did"] = ""
            updated_sources.append(record)
        state["sources"] = updated_sources

    elif entity_key == "surface":
        state["app_surfaces"] = [
            item for item in _as_dict_list(state.get("app_surfaces"))
            if str(item.get("surface_id") or "").strip() != entity_value
        ]
        updated_bindings = []
        for item in _as_dict_list(state.get("model_bindings")):
            record = dict(item)
            record["app_surfaces"] = [
                value for value in _as_list(record.get("app_surfaces"))
                if str(value).strip() and str(value).strip() != entity_value
            ]
            updated_bindings.append(record)
        state["model_bindings"] = updated_bindings

    _save_control_plane_state(state)


def _merged_control_plane_records(derived: list[dict[str, Any]], stored: list[dict[str, Any]], key: str) -> list[dict[str, Any]]:
    merged = [dict(item) for item in derived if isinstance(item, dict)]
    for item in stored:
        if not isinstance(item, dict):
            continue
        merged = _upsert_control_plane_record(merged, key, item)
    return merged


def _connection_settings_id(entity_type: str, entity_id: str) -> str:
    return f"{entity_type}:{entity_id}".strip(":")


def _connection_settings_defaults(entity_type: str, entity_id: str, label: str = "") -> dict[str, Any]:
    return {
        "settings_id": _connection_settings_id(entity_type, entity_id),
        "entity_type": entity_type,
        "entity_id": entity_id,
        "label": label,
        "enabled_state": "enabled",
        "permission_set": "default",
        "start_date": "",
        "end_date": "",
        "notes": "",
        "constraints": "",
        "metadata": "",
    }


def _relationship_record_id(subject_entity_type: str, subject_entity_id: str, object_entity_type: str, object_entity_id: str) -> str:
    return "::".join(
        [
            str(subject_entity_type or "").strip().lower(),
            str(subject_entity_id or "").strip(),
            str(object_entity_type or "").strip().lower(),
            str(object_entity_id or "").strip(),
        ]
    ).strip(":")


def _canonical_relationship_parts(
    owner_entity_type: str,
    owner_entity_id: str,
    related_entity_type: str,
    related_entity_id: str,
) -> tuple[str, str, str, str, str]:
    owner_type = str(owner_entity_type or "").strip().lower()
    related_type = str(related_entity_type or "").strip().lower()
    owner_id = str(owner_entity_id or "").strip()
    related_id = str(related_entity_id or "").strip()
    pair = {owner_type, related_type}
    if pair == {"principal", "ledger"}:
        if owner_type == "principal":
            return ("principal", owner_id, "ledger", related_id, "member_of_ledger")
        return ("principal", related_id, "ledger", owner_id, "member_of_ledger")
    if pair == {"principal", "surface"}:
        if owner_type == "principal":
            return ("principal", owner_id, "surface", related_id, "can_access_surface")
        return ("principal", related_id, "surface", owner_id, "can_access_surface")
    if pair == {"ledger", "surface"}:
        if owner_type == "surface":
            return ("surface", owner_id, "ledger", related_id, "surface_bound_to_ledger")
        return ("surface", related_id, "ledger", owner_id, "surface_bound_to_ledger")
    if pair == {"principal"}:
        return ("principal", owner_id, "principal", related_id, "acts_for_principal")
    return (owner_type, owner_id, related_type, related_id, "related_to")


def _relationship_defaults(
    subject_entity_type: str,
    subject_entity_id: str,
    object_entity_type: str,
    object_entity_id: str,
    relationship_type: str,
    label: str = "",
) -> dict[str, Any]:
    relationship_id = _relationship_record_id(subject_entity_type, subject_entity_id, object_entity_type, object_entity_id)
    return {
        "relationship_id": relationship_id,
        "subject_entity_type": str(subject_entity_type or "").strip().lower(),
        "subject_entity_id": str(subject_entity_id or "").strip(),
        "object_entity_type": str(object_entity_type or "").strip().lower(),
        "object_entity_id": str(object_entity_id or "").strip(),
        "relationship_type": str(relationship_type or "related_to").strip().lower() or "related_to",
        "canonical_subject": _canonical_entity_subject("relationship", relationship_id),
        "canonical_subject_source": "did:web:relationship",
        "label": label,
        "status": "active",
        "enabled_state": "enabled",
        "permission_scope": "full",
        "permission_payload": "",
        "start_date": "",
        "end_date": "",
        "notes": "",
        "constraints": "",
        "metadata": "",
    }


def _relationship_record(
    owner_entity_type: str,
    owner_entity_id: str,
    related_entity_type: str,
    related_entity_id: str,
    label: str = "",
    relationship_records: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    resolved_relationship_records = relationship_records if relationship_records is not None else _as_dict_list(_load_control_plane_state().get("relationships"))
    subject_type, subject_id, object_type, object_id, relationship_type = _canonical_relationship_parts(
        owner_entity_type,
        owner_entity_id,
        related_entity_type,
        related_entity_id,
    )
    relationship_id = _relationship_record_id(subject_type, subject_id, object_type, object_id)
    stored = next(
        (
            item for item in resolved_relationship_records
            if isinstance(item, dict) and str(item.get("relationship_id") or "").strip() == relationship_id
        ),
        None,
    )
    record = _relationship_defaults(subject_type, subject_id, object_type, object_id, relationship_type, label)
    if isinstance(stored, dict):
        record.update(stored)
    if label and not str(record.get("label") or "").strip():
        record["label"] = label
    return record


def _relationship_to_settings_projection(record: dict[str, Any], *, entity_type: str = "", entity_id: str = "", label: str = "") -> dict[str, Any]:
    projected = _connection_settings_defaults(entity_type, entity_id, label)
    projected.update(
        {
            "label": str(record.get("label") or label).strip(),
            "enabled_state": str(record.get("enabled_state") or "enabled").strip().lower() or "enabled",
            "permission_set": "custom" if str(record.get("permission_scope") or "full").strip().lower() == "custom" else "default",
            "start_date": str(record.get("start_date") or record.get("start_at") or "").strip(),
            "end_date": str(record.get("end_date") or record.get("end_at") or "").strip(),
            "notes": str(record.get("notes") or "").strip(),
            "constraints": str(record.get("constraints") or "").strip(),
            "metadata": str(record.get("metadata") or "").strip(),
            "updated_at": str(record.get("updated_at") or datetime.now(timezone.utc).isoformat()),
        }
    )
    return projected


def _slug_token(value: str, fallback: str) -> str:
    slug = re.sub(r"[^a-z0-9]+", "-", str(value or "").strip().lower()).strip("-")
    return slug or fallback


def _entity_settings_record(
    entity_type: str,
    entity_id: str,
    label: str = "",
    relationship_records: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    relationship = _relationship_record(
        entity_type,
        entity_id,
        entity_type,
        entity_id,
        label,
        relationship_records=relationship_records,
    )
    if isinstance(relationship, dict) and (
        str(relationship.get("enabled_state") or "").strip()
        or str(relationship.get("permission_scope") or "").strip()
        or str(relationship.get("notes") or "").strip()
    ):
        return _relationship_to_settings_projection(relationship, entity_type=entity_type, entity_id=entity_id, label=label)
    state = _load_control_plane_state()
    settings_records = _as_dict_list(state.get("entity_settings"))
    settings_id = _connection_settings_id(entity_type, entity_id)
    stored = next(
        (
            item for item in settings_records
            if isinstance(item, dict) and str(item.get("settings_id") or "").strip() == settings_id
        ),
        None,
    )
    record = _connection_settings_defaults(entity_type, entity_id, label)
    if isinstance(stored, dict):
        record.update(stored)
    if label and not str(record.get("label") or "").strip():
        record["label"] = label
    return record


