def _advance_surface_record(record: dict[str, Any], action: str) -> dict[str, Any]:
    next_record = dict(record)
    normalized = action.strip().lower()
    if normalized == "ledger_created":
        next_record["ledger_state"] = "ledger_created"
        next_record["onboarding_state"] = "onboarding_pending"
        next_record["status"] = "pending"
        next_record["next_action"] = "Complete connector, DSS API, and auth wiring."
        if str(next_record.get("ledger_id") or "").strip() in {"", "ledger:pending"}:
            surface_tail = str(next_record.get("surface_id") or "surface").split(":")[-1]
            next_record["ledger_id"] = f"ledger:{surface_tail}"
    elif normalized == "integration_configured":
        next_record["ledger_state"] = str(next_record.get("ledger_state") or "ledger_created")
        next_record["onboarding_state"] = "integration_configured"
        next_record["status"] = "pending"
        next_record["next_action"] = "Run final onboarding and activation checks."
    elif normalized == "activate":
        next_record["ledger_state"] = "active"
        next_record["onboarding_state"] = "active"
        next_record["status"] = "active"
        next_record["next_action"] = "Surface is active."
    elif normalized == "fail":
        next_record["status"] = "error"
        next_record["onboarding_state"] = "error"
        next_record["next_action"] = "Review deployment, auth, and ledger sync configuration."
    return next_record


def _app_surface_from_surface_record(record: dict[str, Any]) -> dict[str, Any]:
    metadata = _as_dict(record.get("metadata"))
    surface_id = str(record.get("surface_id") or "").strip()
    display_name = str(record.get("display_name") or record.get("name") or record.get("surface_id") or "Surface").strip()
    return {
        "surface_id": surface_id,
        "name": display_name,
        "label": display_name,
        "surface_type": str(record.get("surface_type") or metadata.get("surface_type") or "custom").strip() or "custom",
        "status": str(record.get("status") or "pending").strip() or "pending",
        "environment": str(metadata.get("environment") or "planned").strip() or "planned",
        "deployment_owner": str(metadata.get("deployment_owner") or "control-plane").strip() or "control-plane",
        "endpoint": str(record.get("endpoint") or "").strip() or "#",
        "dss_api_base": str(metadata.get("dss_api_base") or MIDDLEWARE_BASE_URL).strip() or MIDDLEWARE_BASE_URL,
        "dss_auth_mode": str(metadata.get("dss_auth_mode") or "linked-session").strip() or "linked-session",
        "mcp_detail": str(metadata.get("mcp_detail") or "not declared").strip() or "not declared",
        "default_binding_id": str(record.get("binding_ref") or metadata.get("default_binding_id") or "").strip(),
        "provider_type": str(metadata.get("provider_type") or "unknown").strip() or "unknown",
        "provider_ref": str(metadata.get("provider_ref") or "").strip(),
        "credential_ref": str(metadata.get("credential_ref") or "").strip(),
        "model_id": str(metadata.get("model_id") or "unknown").strip() or "unknown",
        "principal_did": str(record.get("principal_did") or "").strip(),
        "tenant_id": str(record.get("tenant_id") or metadata.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
        "ledger_id": str(record.get("ledger_id") or "ledger:pending").strip() or "ledger:pending",
        "ledger_state": str(metadata.get("ledger_state") or "planned").strip() or "planned",
        "onboarding_state": str(metadata.get("onboarding_state") or "planned").strip() or "planned",
        "next_action": str(metadata.get("next_action") or "").strip(),
        "notes": str(metadata.get("notes") or "").strip(),
        "created_at": str(record.get("created_at") or "").strip(),
        "updated_at": str(record.get("updated_at") or "").strip(),
        "canonical_subject": str(record.get("canonical_subject") or metadata.get("canonical_subject") or _canonical_entity_subject("surface", surface_id)).strip(),
        "canonical_subject_source": str(record.get("canonical_subject_source") or metadata.get("canonical_subject_source") or "did:web:surface").strip(),
    }


def _surface_control_plane_payload(record: dict[str, Any], *, existing: dict[str, Any] | None = None) -> dict[str, Any]:
    current = _as_dict(existing)
    current_metadata = _as_dict(current.get("metadata"))
    metadata = dict(current_metadata)
    metadata.update(
        {
            "environment": str(record.get("environment") or current_metadata.get("environment") or "planned").strip() or "planned",
            "deployment_owner": str(record.get("deployment_owner") or current_metadata.get("deployment_owner") or "control-plane").strip() or "control-plane",
            "dss_api_base": str(record.get("dss_api_base") or current_metadata.get("dss_api_base") or MIDDLEWARE_BASE_URL).strip() or MIDDLEWARE_BASE_URL,
            "dss_auth_mode": str(record.get("dss_auth_mode") or current_metadata.get("dss_auth_mode") or "linked-session").strip() or "linked-session",
            "mcp_detail": str(record.get("mcp_detail") or current_metadata.get("mcp_detail") or "not declared").strip() or "not declared",
            "default_binding_id": str(record.get("default_binding_id") or current.get("binding_ref") or current_metadata.get("default_binding_id") or "").strip(),
            "provider_type": str(record.get("provider_type") or current_metadata.get("provider_type") or "unknown").strip() or "unknown",
            "provider_ref": str(record.get("provider_ref") or current_metadata.get("provider_ref") or "").strip(),
            "credential_ref": str(record.get("credential_ref") or current_metadata.get("credential_ref") or "").strip(),
            "model_id": str(record.get("model_id") or current_metadata.get("model_id") or "unknown").strip() or "unknown",
            "ledger_state": str(record.get("ledger_state") or current_metadata.get("ledger_state") or "planned").strip() or "planned",
            "onboarding_state": str(record.get("onboarding_state") or current_metadata.get("onboarding_state") or "planned").strip() or "planned",
            "next_action": str(record.get("next_action") or current_metadata.get("next_action") or "").strip(),
            "notes": str(record.get("notes") or current_metadata.get("notes") or "").strip(),
            "tenant_id": str(record.get("tenant_id") or current.get("tenant_id") or current_metadata.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
        }
    )
    payload = {
        "surface_id": str(record.get("surface_id") or current.get("surface_id") or "").strip(),
        "display_name": str(record.get("name") or record.get("label") or current.get("display_name") or current.get("name") or "").strip(),
        "surface_type": str(record.get("surface_type") or current.get("surface_type") or "Custom").strip() or "Custom",
        "status": str(record.get("status") or current.get("status") or "pending").strip().lower() or "pending",
        "endpoint": str(record.get("endpoint") or current.get("endpoint") or "").strip(),
        "principal_did": str(record.get("principal_did") or current.get("principal_did") or "").strip(),
        "tenant_id": str(record.get("tenant_id") or current.get("tenant_id") or metadata.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
        "ledger_id": str(record.get("ledger_id") or current.get("ledger_id") or "ledger:pending").strip() or "ledger:pending",
        "binding_ref": str(record.get("default_binding_id") or current.get("binding_ref") or metadata.get("default_binding_id") or "").strip(),
        "provisioning_source": str(record.get("provisioning_source") or current.get("provisioning_source") or "control_plane_dashboard").strip() or "control_plane_dashboard",
        "metadata": metadata,
    }
    payload["canonical_subject"] = str(record.get("canonical_subject") or current.get("canonical_subject") or metadata.get("canonical_subject") or _canonical_entity_subject("surface", payload["surface_id"])).strip()
    metadata["canonical_subject"] = payload["canonical_subject"]
    metadata["canonical_subject_source"] = str(record.get("canonical_subject_source") or current.get("canonical_subject_source") or metadata.get("canonical_subject_source") or "did:web:surface").strip()
    return payload


async def _update_principal_ledger_metadata(
    principal_id: str,
    ledger_ids: list[str],
    context: dict[str, Any],
    request: Request,
) -> None:
    """Backfill the principal's canonical ledger_id when its ledger links change."""
    if not ledger_ids:
        return
    primary_ledger_id = str(ledger_ids[0] or "").strip()
    if not primary_ledger_id:
        return
    principal = _as_dict(context.get("principal_map", {}).get(principal_id))
    if not principal:
        return
    metadata = _as_dict(principal.get("metadata"))
    current_ledger = str(
        metadata.get("provisioned_ledger_id") or metadata.get("ledger_id") or ""
    ).strip()
    if current_ledger == primary_ledger_id:
        return
    updated_metadata = dict(metadata)
    updated_metadata["ledger_id"] = primary_ledger_id
    updated_metadata["provisioned_ledger_id"] = primary_ledger_id
    payload = {
        "principal_did": principal_id,
        "display_name": str(principal.get("display_name") or principal_id).strip() or principal_id,
        "status": str(principal.get("status") or "active").strip().lower() or "active",
        "tenant_id": str(principal.get("tenant_id") or metadata.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
        "principal_type": str(metadata.get("actor_type") or principal.get("principal_type") or "human").strip().lower() or "human",
        "provisioning_source": "control_plane_entity_link_editor",
        "metadata": updated_metadata,
    }
    await _control_plane_post("/api/control-plane/principals", payload, request)


async def _update_surface_canonical_metadata(
    surface_id: str,
    links: dict[str, list[str]],
    context: dict[str, Any],
    request: Request,
) -> None:
    """Backfill a surface's canonical ledger_id/principal_did when its links change."""
    surface = _as_dict(context.get("surface_map", {}).get(surface_id))
    if not surface:
        return
    primary_ledger_id = ""
    ledger_ids = _as_list(links.get("ledger"))
    if ledger_ids:
        primary_ledger_id = str(ledger_ids[0] or "").strip()
    primary_principal_id = ""
    principal_ids = _as_list(links.get("principal"))
    if principal_ids:
        primary_principal_id = str(principal_ids[0] or "").strip()
    current_ledger_id = str(surface.get("ledger_id") or "").strip()
    current_principal_did = str(surface.get("principal_did") or "").strip()
    if (primary_ledger_id and primary_ledger_id != current_ledger_id) or (
        primary_principal_id and primary_principal_id != current_principal_did
    ):
        payload = _surface_control_plane_payload(surface)
        if primary_ledger_id:
            payload["ledger_id"] = primary_ledger_id
        if primary_principal_id:
            payload["principal_did"] = primary_principal_id
        payload["governance_mode"] = "direct_write"
        await _control_plane_post("/api/control-plane/surfaces", payload, request)


def _surface_integration_plan(record: dict[str, Any]) -> dict[str, Any]:
    surface_type = str(record.get("surface_type") or "unknown").strip().lower()
    env_refs: list[str]
    external_actions: list[str]
    if "telegram" in surface_type:
        env_refs = ["TELEGRAM_BOT_TOKEN", "TELEGRAM_WEBHOOK_SECRET", "MIDDLEWARE_BASE_URL"]
        external_actions = [
            "Create or identify the Telegram bot and connector host.",
            "Configure the webhook target and secret.",
            "Create or confirm the DSS ledger for this surface.",
            "Bind the default model and verify inbound auth.",
        ]
    elif "mcp" in surface_type:
        env_refs = ["MCP_SERVER_URL", "MCP_AUTH_TOKEN", "MIDDLEWARE_BASE_URL"]
        external_actions = [
            "Declare the MCP server endpoint and transport.",
            "Record allowed capabilities and trust boundary.",
            "Bind the surface to a model binding or explicit no-model mode.",
            "Verify ledger sync and principal access boundary.",
        ]
    elif "local offline" in surface_type:
        env_refs = ["LOCAL_CHAT_BASE_URL", "LOCAL_CHAT_SYNC_MODE", "MIDDLEWARE_BASE_URL"]
        external_actions = [
            "Verify the local endpoint is reachable from the operator environment.",
            "Confirm shared-ledger sync or replay semantics.",
            "Check local auth mode and offline-to-online recovery path.",
        ]
    else:
        env_refs = ["CHAT_BASE_URL", "OPENROUTER_API_KEY", "LLM_PROVIDER", "LLM_MODEL"]
        external_actions = [
            "Verify deployment owner and runtime target.",
            "Confirm provider credential readiness and default model binding.",
            "Verify ledger activation and session handoff behavior.",
        ]
    env_status = []
    for name in env_refs:
        configured = bool(str(os.getenv(name) or "").strip())
        if name == "CHAT_BASE_URL":
            configured = bool(CHAT_BASE_URL)
        if name == "MIDDLEWARE_BASE_URL":
            configured = bool(MIDDLEWARE_BASE_URL)
        if name == "LOCAL_CHAT_BASE_URL":
            configured = bool(LOCAL_CHAT_BASE_URL)
        env_status.append({"name": name, "configured": configured})
    configured_count = sum(1 for item in env_status if item["configured"])
    return {
        "surface_id": str(record.get("surface_id") or "").strip(),
        "integration_kind": surface_type,
        "env_requirements": env_status,
        "external_actions": external_actions,
        "configured_count": configured_count,
        "required_count": len(env_status),
        "ready": configured_count == len(env_status) and str(record.get("ledger_state") or "").strip().lower() in {"active", "shared", "ledger_created"},
    }


def _surface_adapter_payload(record: dict[str, Any]) -> dict[str, Any]:
    surface_type = str(record.get("surface_type") or "unknown").strip().lower()
    surface_id = str(record.get("surface_id") or "").strip()
    base_payload = {
        "surface_id": surface_id,
        "surface_name": str(record.get("name") or "").strip(),
        "tenant_id": str(record.get("tenant_id") or "").strip(),
        "ledger_id": str(record.get("ledger_id") or "").strip(),
        "provider_type": str(record.get("provider_type") or "").strip(),
        "model_id": str(record.get("model_id") or "").strip(),
        "dss_api_base": str(record.get("dss_api_base") or "").strip(),
        "dss_auth_mode": str(record.get("dss_auth_mode") or "").strip(),
        "endpoint": str(record.get("endpoint") or "").strip(),
    }
    if "telegram" in surface_type:
        return {
            "adapter_type": "telegram",
            "platform": "Telegram",
            "mutation_boundary": "operator-guided",
            "required_env": ["TELEGRAM_BOT_TOKEN", "TELEGRAM_WEBHOOK_SECRET", "MIDDLEWARE_BASE_URL"],
            "payload": {
                **base_payload,
                "webhook_target": str(record.get("endpoint") or "").strip(),
                "bot_token_ref": "TELEGRAM_BOT_TOKEN",
                "webhook_secret_ref": "TELEGRAM_WEBHOOK_SECRET",
            },
        }
    if "mcp" in surface_type:
        return {
            "adapter_type": "mcp",
            "platform": "MCP / third-party app",
            "mutation_boundary": "operator-guided",
            "required_env": ["MCP_SERVER_URL", "MCP_AUTH_TOKEN", "MIDDLEWARE_BASE_URL"],
            "payload": {
                **base_payload,
                "mcp_endpoint": str(record.get("endpoint") or "").strip(),
                "mcp_detail": str(record.get("mcp_detail") or "").strip(),
                "capability_contract": "declare in control-plane notes or downstream connector",
            },
        }
    if "local offline" in surface_type:
        return {
            "adapter_type": "local_offline_sync",
            "platform": "Local offline chat",
            "mutation_boundary": "operator-guided",
            "required_env": ["LOCAL_CHAT_BASE_URL", "LOCAL_CHAT_SYNC_MODE", "MIDDLEWARE_BASE_URL"],
            "payload": {
                **base_payload,
                "local_endpoint": str(record.get("endpoint") or "").strip(),
                "sync_mode": LOCAL_CHAT_SYNC_MODE,
                "shared_ledger_expected": True,
            },
        }
    return {
        "adapter_type": "vercel",
        "platform": "Vercel",
        "mutation_boundary": "operator-guided",
        "required_env": ["OPENROUTER_API_KEY", "LLM_PROVIDER", "LLM_MODEL", "CHAT_BASE_URL"],
        "payload": {
            **base_payload,
            "project_hint": os.getenv("DEFAULT_CHAT_HOST", ""),
            "env_map": {
                "OPENROUTER_API_KEY": "secret-ref",
                "LLM_PROVIDER": str(record.get("provider_type") or "").strip().lower() or "unknown",
                "LLM_MODEL": str(record.get("model_id") or "").strip(),
                "CHAT_BASE_URL": CHAT_BASE_URL,
            },
        },
    }


def build_did_document() -> dict[str, Any]:
    verification_method, _ = load_verification_method()
    verification_method_id = str(verification_method.get("id") or f"{ISSUER_DID}#v1")
    vms = [verification_method]
    ams = [verification_method_id]
    auths = [verification_method_id]
    # Optional secondary verification method (e.g. for walt.id issuance key)
    raw_secondary = (os.getenv("DID_SECONDARY_PUBLIC_JWK_JSON") or _FALLBACK_SECONDARY_JWK).strip()
    if raw_secondary:
        try:
            secondary_jwk = json.loads(raw_secondary)
            if isinstance(secondary_jwk, dict) and secondary_jwk.get("kid"):
                secondary_vm = {
                    "id": str(secondary_jwk["kid"]),
                    "type": "JsonWebKey2020",
                    "controller": ISSUER_DID,
                    "publicKeyJwk": {k: v for k, v in secondary_jwk.items() if k != "kid"},
                }
                vms.append(secondary_vm)
                ams.append(str(secondary_jwk["kid"]))
                auths.append(str(secondary_jwk["kid"]))
        except Exception:
            pass
    # Walt.id issuer verification method
    raw_walt = (os.getenv("WALT_ID_ISSUER_PUBLIC_JWK_JSON") or _WALT_ID_ISSUER_PUBLIC_JWK).strip()
    if raw_walt:
        try:
            walt_jwk = json.loads(raw_walt)
            if isinstance(walt_jwk, dict) and walt_jwk.get("kid"):
                walt_vm = {
                    "id": str(walt_jwk["kid"]),
                    "type": "JsonWebKey2020",
                    "controller": ISSUER_DID,
                    "publicKeyJwk": {k: v for k, v in walt_jwk.items() if k != "kid"},
                }
                vms.append(walt_vm)
                ams.append(str(walt_jwk["kid"]))
                auths.append(str(walt_jwk["kid"]))
        except Exception:
            pass
    return {
        "@context": ["https://www.w3.org/ns/did/v1"],
        "id": ISSUER_DID,
        "verificationMethod": vms,
        "assertionMethod": ams,
        "authentication": auths,
        "service": [
            {
                "id": f"{ISSUER_DID}#resolver",
                "type": "DSSResolverService",
                "serviceEndpoint": PUBLIC_BASE_URL + "/v1/resolve",
            },
            {
                "id": f"{ISSUER_DID}#profile",
                "type": "DSSProfileService",
                "serviceEndpoint": PUBLIC_BASE_URL + "/v1/profile",
            },
            {
                "id": f"{ISSUER_DID}#status",
                "type": "CredentialStatusService",
                "serviceEndpoint": PUBLIC_BASE_URL + "/v1/status",
            },
            {
                "id": f"{ISSUER_DID}#trust-panel",
                "type": "DssTrustPanel",
                "serviceEndpoint": PUBLIC_BASE_URL + "/",
            },
            {
                "id": f"{ISSUER_DID}#trust-anchor-status",
                "type": "DssTrustAnchorStatus",
                "serviceEndpoint": PUBLIC_BASE_URL + "/api/trust-anchor/status",
            },
            {
                "id": f"{ISSUER_DID}#trust-anchor-bundle",
                "type": "DssTrustAnchorBundle",
                "serviceEndpoint": PUBLIC_BASE_URL + TRUST_BUNDLE_PATH,
            },
            {
                "id": f"{ISSUER_DID}#issuer-authority",
                "type": "DssIssuerAuthority",
                "serviceEndpoint": PUBLIC_BASE_URL + ISSUER_AUTHORITY_PATH,
            },
            {
                "id": f"{ISSUER_DID}#issuer-authority-status",
                "type": "DssIssuerAuthorityStatus",
                "serviceEndpoint": PUBLIC_BASE_URL + ISSUER_AUTHORITY_STATUS_PATH,
            },
            {
                "id": f"{ISSUER_DID}#verifier-policy",
                "type": "DssVerifierPolicy",
                "serviceEndpoint": PUBLIC_BASE_URL + VERIFIER_POLICY_PATH,
            },
        ],
    }


def _request_host(request: Request) -> str:
    forwarded_host = str(request.headers.get("x-forwarded-host") or "").split(",")[0].strip()
    host = forwarded_host or str(getattr(request.url, "hostname", "") or "").strip()
    if ":" in host:
        host = host.split(":", 1)[0].strip()
    return host or os.getenv("DEFAULT_HOST", "")


def _request_origin(request: Request) -> str:
    parsed = urlparse(str(request.url))
    return f"{parsed.scheme}://{parsed.netloc}"


def _cookie_secure(request: Request) -> bool:
    forwarded_proto = str(request.headers.get("x-forwarded-proto") or "").split(",")[0].strip().lower()
    return forwarded_proto == "https" or request.url.scheme == "https"


def _cookie_domain(request: Request) -> str | None:
    configured = str(os.getenv("DUALSUBSTRATE_COOKIE_DOMAIN") or "").strip()
    if configured:
        return configured
    host = _request_host(request).lower()
    base_domain = os.getenv("BASE_DOMAIN", "").strip().lower()
    if base_domain and (host == base_domain or host.endswith("." + base_domain)):
        return "." + base_domain
    return ""
    return None


def _request_rp_id(request: Request) -> str:
    configured = str(os.getenv("AUTH_WEBAUTHN_RP_ID") or "").strip()
    if configured:
        return configured
    host = _request_host(request).lower()
    base_domain = os.getenv("BASE_DOMAIN", "").strip().lower()
    if base_domain and (host == base_domain or host.endswith("." + base_domain)):
        return base_domain
    return ""
    return host or os.getenv("DEFAULT_HOST", "")


def _safe_next_path(value: str) -> str:
    next_path = (value or "/").strip() or "/"
    parsed = urlparse(next_path)
    if parsed.scheme or parsed.netloc:
        if parsed.scheme not in {"http", "https"}:
            return "/"
        allowed_hosts = {
            str(urlparse(PUBLIC_BASE_URL).hostname or "").strip().lower(),
            str(urlparse(CHAT_BASE_URL).hostname or "").strip().lower(),
        }
        if LOCAL_CHAT_BASE_URL:
            allowed_hosts.add(str(urlparse(LOCAL_CHAT_BASE_URL).hostname or "").strip().lower())
        host = str(parsed.hostname or "").strip().lower()
        if host and host in {candidate for candidate in allowed_hosts if candidate}:
            return next_path
        return "/"
    if not next_path.startswith("/") or next_path.startswith("//"):
        return "/"
    return next_path


def _frontdoor_cookie_signature() -> str:
    secret = str(os.getenv("FASTHTML_SECRET_KEY", ""))
    payload = f"id-dashboard:{ISSUER_DID}:frontdoor".encode("utf-8")
    return hmac.new(secret.encode("utf-8"), payload, "sha256").hexdigest()


async def fetch_json(path: str, headers: dict[str, str] | None = None) -> dict[str, Any] | None:
    status_code, body = await _middleware_json_request(
        method="GET",
        path=path,
        timeout=8.0,
        error_prefix="middleware_fetch",
        headers=headers,
    )
    return body if status_code < 400 else None


async def _middleware_json_request(
    *,
    method: str,
    path: str,
    payload: dict[str, Any] | None = None,
    headers: dict[str, str] | None = None,
    cookies: dict[str, str] | None = None,
    params: dict[str, Any] | None = None,
    timeout: float = 20.0,
    error_prefix: str,
) -> tuple[int, dict[str, Any]]:
    request_headers = dict(headers or {})
    # Middleware routes such as /api/models switch between HTML and JSON based
    # on the Accept header. Ensure JSON consumers always request JSON.
    if "accept" not in {k.lower() for k in request_headers}:
        request_headers["Accept"] = "application/json"
    client = await _shared_http_client()
    try:
        resp = await client.request(
            method.upper(),
            f"{MIDDLEWARE_BASE_URL}{path}",
            json=payload if method.upper() != "GET" else None,
            params=params,
            headers=request_headers,
            cookies=cookies,
            timeout=timeout,
        )
        try:
            data = resp.json()
            body = data if isinstance(data, dict) else {"data": data}
        except Exception:
            body = {"error": "upstream_invalid_json", "path": path, "text": resp.text[:1000]}
        return resp.status_code, body
    except httpx.HTTPError as exc:
        return 503, {"error": f"{error_prefix}_http_error", "detail": str(exc)}
    except Exception as exc:
        return 503, {"error": f"{error_prefix}_unavailable", "detail": str(exc)}


async def _auth_proxy_get(path: str, headers: dict[str, str] | None = None) -> tuple[int, dict[str, Any]]:
    request_headers = dict(headers or {})
    try:
        async with httpx.AsyncClient(timeout=20.0) as client:
            resp = await client.get(f"{AUTH_BASE_URL}{path}", headers=request_headers)
            try:
                data = resp.json()
                body = data if isinstance(data, dict) else {"data": data}
            except Exception:
                body = {"error": "upstream_invalid_json", "text": resp.text[:1000]}
            return resp.status_code, body
    except httpx.HTTPError as exc:
        return 503, {"error": "auth_upstream_http_error", "detail": str(exc)}
    except Exception as exc:
        return 503, {"error": "auth_upstream_unavailable", "detail": str(exc)}


async def _fetch_setup_checklist(principal_did: str) -> dict[str, Any]:
    """Fetch the authenticated user's account setup checklist from the auth service."""
    status_code, body = await _auth_proxy_get(
        "/account/current/setup-checklist",
        headers={"x-principal-id": principal_did},
    )
    if status_code >= 400 or not isinstance(body, dict):
        return {}
    return _as_dict(body.get("setup_checklist"))


def _render_setup_guide_banner(checklist: dict[str, Any]) -> str:
    """Render a 'Continue setup' banner when required checklist items remain."""
    if not isinstance(checklist, dict):
        return ""
    items = _as_dict_list(checklist.get("items"))
    required_items = [item for item in items if isinstance(item, dict) and item.get("required")]
    incomplete = [
        item
        for item in required_items
        if str(item.get("state") or "").lower() not in {"complete", "completed"}
    ]
    if not incomplete:
        return ""
    summary = _as_dict(checklist.get("summary"))
    completed = int(summary.get("required_complete") or 0)
    total = int(summary.get("required") or len(required_items))
    remaining = max(total - completed, len(incomplete))
    return (
        '<div class="banner warn" style="margin:0 0 16px;">'
        "<strong>Finish setting up your account</strong>"
        f'<div style="margin-top:6px;">{remaining} required setup step(s) remain. '
        "Complete them to unlock the full Control Plane.</div>"
        '<div style="margin-top:12px;">'
        '<a class="btn primary" href="/connections/setup-guide">Continue setup</a>'
        "</div>"
        "</div>"
    )


