async def _fetch_provider_models(provider_type: str, api_key: str) -> tuple[list[dict[str, str]], str | None]:
    provider_key = str(provider_type or "").strip().lower()
    key_text = str(api_key or "").strip()
    if not key_text:
        return [], "api_key_required"
    if provider_key != "openrouter":
        return [], "unsupported_provider"
    try:
        async with httpx.AsyncClient(timeout=20.0) as client:
            resp = await client.get(
                "https://openrouter.ai/api/v1/models",
                headers={
                    "Authorization": f"Bearer {key_text}",
                    "Accept": "application/json",
                },
            )
            resp.raise_for_status()
            body = resp.json()
    except httpx.HTTPError as exc:
        return [], str(exc)
    except Exception as exc:
        return [], str(exc)
    records: list[dict[str, str]] = []
    for item in _as_list(_as_dict(body).get("data")):
        record = _as_dict(item)
        model_id = str(record.get("id") or "").strip()
        if not model_id:
            continue
        label = str(record.get("name") or model_id).strip() or model_id
        records.append({"id": model_id, "label": label})
    return records, None


