async def _fetch_ledger_attachments(
    ledger_id: str,
    auth_headers: dict[str, str] | None = None,
) -> list[dict[str, Any]]:
    """Query backend ledger entries for attachments belonging to a ledger.

    Tries both namespace=<ledger_id> and namespace=chat-<ledger_id> since the
    backend prepends 'chat-' to bare entity identifiers.
    """
    namespaces = [ledger_id]
    if not ledger_id.startswith("chat-"):
        namespaces.append(f"chat-{ledger_id}")

    request_headers = {"accept": "application/json"}
    request_headers.update(auth_headers or {})

    async def _fetch_namespace(ns: str) -> list[dict[str, Any]]:
        try:
            status_code, body = await _middleware_json_request(
                method="GET",
                path="/ledger/all",
                headers=request_headers,
                error_prefix="ledger_attachments",
                params={"namespace": ns, "limit": 200},
            )
            if status_code < 400 and isinstance(body, dict):
                return _as_dict_list(body.get("entries"))
        except Exception:
            pass
        return []

    namespace_results = await asyncio.gather(*[_fetch_namespace(ns) for ns in namespaces])
    all_entries: list[dict[str, Any]] = []
    for entries in namespace_results:
        all_entries.extend(entries)

    attachments: list[dict[str, Any]] = []
    seen_coords: set[str] = set()
    for entry in all_entries:
        if not isinstance(entry, dict):
            continue
        meta = _as_dict(entry.get("state", {})).get("metadata")
        if not isinstance(meta, dict):
            continue
        if not (meta.get("attachment") or meta.get("kind") == "attachment"):
            continue
        # Skip individual part entries; only list parent/summary entries
        if meta.get("attachment_part"):
            continue
        coord = str(entry.get("coordinate") or "").strip()
        if not coord:
            key = _as_dict(entry.get("key"))
            if isinstance(key, dict):
                ns_part = str(key.get("namespace") or "").strip()
                id_part = str(key.get("identifier") or "").strip()
                if ns_part and id_part:
                    coord = f"{ns_part}:{id_part}"
        if coord in seen_coords:
            continue
        seen_coords.add(coord)

        attachment_meta = _as_dict(meta.get("attachment"))
        filename = (
            str(attachment_meta.get("filename") or "").strip()
            or str(meta.get("filename") or "").strip()
            or coord
        )
        content_type = (
            str(attachment_meta.get("content_type") or "").strip()
            or str(meta.get("content_type") or "").strip()
            or "application/octet-stream"
        )
        size_bytes = int(
            attachment_meta.get("size_bytes")
            or meta.get("size_bytes")
            or 0
        )
        created_at = str(entry.get("created_at") or "").strip()
        part_count = int(meta.get("part_count") or 0)
        part_coords = [str(c) for c in _as_list(meta.get("part_coordinates")) if str(c).strip()]
        projection_coords = [str(c) for c in _as_list(meta.get("kernel_projections")) if str(c).strip()]
        full_payload_coord = str(meta.get("full_payload_coord") or "").strip() or coord
        summary = str(meta.get("summary") or "").strip()
        payload_state = _payload_state_for_meta(meta)

        attachments.append({
            "source_id": f"backend-{coord.replace(':', '-').replace('/', '-')}",
            "job_id": "",
            "ledger_id": ledger_id,
            "principal_did": "",
            "batch_label": "",
            "file_name": filename,
            "original_file_name": filename,
            "content_type": content_type,
            "size_bytes": size_bytes,
            "status": "completed",
            "uploaded_at": created_at,
            "updated_at": created_at,
            "storage_path": "",
            "chunk_manifest_path": "",
            "chunk_count": part_count,
            "canonical_subject": coord,
            "canonical_subject_source": "did:web:source",
            "coordinate": coord,
            "parent_coordinate": coord,
            "part_coordinates": part_coords,
            "summary": summary,
            "payload_state": payload_state,
            "full_payload_coord": full_payload_coord,
            "projection_coordinates": projection_coords,
        })
    return attachments


async def _load_activity_control_plane_state(
    auth_headers: dict[str, str] | None = None,
) -> dict[str, Any]:
    local_state = _load_control_plane_state()
    state = _normalized_control_plane_state({})
    endpoints = {
        "providers": "/api/control-plane/providers",
        "model_bindings": "/api/control-plane/model-bindings",
        "app_surfaces": "/api/control-plane/surfaces",
        "relationships": "/api/control-plane/relationships",
    }
    loaded_any = False
    for key, path in endpoints.items():
        status_code, body = await _control_plane_get(path, headers=auth_headers)
        if status_code >= 400 or not isinstance(body, dict):
            state[key] = _as_dict_list(local_state.get(key))
            continue
        if key == "providers":
            state[key] = _as_dict_list(body.get("providers"))
        elif key == "model_bindings":
            state[key] = _as_dict_list(body.get("model_bindings"))
        elif key == "app_surfaces":
            surfaces = body.get("surfaces")
            if not isinstance(surfaces, list):
                surfaces = body.get("app_surfaces")
            state[key] = _as_dict_list(surfaces)
        elif key == "relationships":
            state[key] = _as_dict_list(body.get("relationships"))
        loaded_any = True
    if not loaded_any:
        return local_state
    state["entity_settings"] = _as_dict_list(local_state.get("entity_settings"))
    state["manual_ledgers"] = _as_dict_list(local_state.get("manual_ledgers"))
    state["manual_principals"] = _as_dict_list(local_state.get("manual_principals"))
    return _normalized_control_plane_state(state)


