async def _backend_admin_fetch_account_request(signup_id: str) -> dict[str, Any] | None:
    """Fetch a single wizard signup by id via the backend admin list endpoint."""
    if not BACKEND_ADMIN_TOKEN:
        return None
    status_code, body = await _backend_admin_get("/admin/account-requests")
    if status_code >= 400 or not isinstance(body, dict):
        return None
    for req in _as_list(body.get("requests")):
        if not isinstance(req, dict):
            continue
        if str(req.get("signup_id") or "").strip() == signup_id:
            return req
    return None


