def _entity_link_editor_modal_id(owner_entity_type: str, owner_entity_id: str) -> str:
    """Return the modal id used by the entity link editor for an owner."""
    owner_type = str(owner_entity_type or "").strip().lower()
    owner_id = str(owner_entity_id or "").strip()
    return f"edit-links-{owner_type}-{_slug_token(owner_id, owner_type)}"


def _derived_model_binding_id(model_id: str) -> str:
    slug = re.sub(r"[^a-z0-9]+", "-", str(model_id or "").strip().lower()).strip("-") or "model"
    return f"binding:chat:{slug}"


def _link_editor_checkbox_list(
    owner_entity_type: str,
    owner_entity_id: str,
    items: list[tuple[str, dict[str, Any]]],
    current_links: dict[str, set[str]],
    model_bindings: list[dict[str, Any]] | None = None,
    base_model_ids: set[str] | None = None,
    owner_ledger_id: str = "",
) -> str:
    """Render a two-column (Name / Type+DID) switch list for the link editor modal."""
    if not items:
        return '<p class="muted">No available items.</p>'
    model_bindings = model_bindings or []
    base_model_ids = base_model_ids or set()
    binding_by_principal: dict[str, dict[str, Any]] = {}
    binding_by_model_id: dict[str, dict[str, Any]] = {}
    for binding in model_bindings:
        if not isinstance(binding, dict):
            continue
        linked = str(binding.get("linked_model_principal") or "").strip()
        if linked:
            binding_by_principal[linked] = binding
        mid = str(binding.get("model_id") or "").strip().lower()
        if mid:
            binding_by_model_id[mid] = binding

    rows: list[str] = []
    for linked_type, item in items:
        if not isinstance(item, dict):
            continue
        item_id = str(
            item.get("ledger_id") or item.get("principal_did") or item.get("surface_id") or ""
        ).strip()
        if not item_id:
            continue
        if linked_type == owner_entity_type and item_id == owner_entity_id:
            continue
        label = _display_label_for_entity(linked_type, item_id, item)
        secondary = _entity_trust_identifier(linked_type, item_id, item)
        type_label = _entity_type_label(linked_type, item)
        safe_id = html.escape(item_id)
        safe_label = html.escape(label or item_id)
        safe_secondary = html.escape(secondary)
        safe_type = html.escape(type_label)
        secondary_short = f"{safe_secondary[:50]}{'...' if len(safe_secondary) > 50 else ''}"
        metadata = _as_dict(item.get("metadata"))
        is_model = (
            linked_type == "principal"
            and str(metadata.get("actor_type") or "").strip().lower() == "model"
        )
        if is_model:
            model_id = str(metadata.get("model_id") or item_id).strip()
            binding = binding_by_principal.get(item_id) or binding_by_model_id.get(model_id.lower()) or {}
            binding_id = str(binding.get("binding_id") or "").strip() or _derived_model_binding_id(model_id)
            linked_principal = item_id
            binding_source = str(binding.get("source") or "").strip().lower()
            is_explicit = binding_source and binding_source != "runtime-model-catalogue"
            if is_explicit:
                is_on = str(binding.get("status") or "").strip().lower() not in {"disabled", "retired", "inactive"}
            else:
                is_on = model_id.lower() in base_model_ids
            toggle_text = "On" if is_on else "Off"
            toggle_checked = "checked" if is_on else ""
            rows.append(
                f"""
                <div class="collection-list-row no-extended">
                  <span class="collection-list-cell-name">
                    <strong>{safe_label}</strong>
                  </span>
                  <span class="relationship-cell-title">
                    <strong>{safe_type}</strong>
                    <span class="relationship-cell-meta" title="{safe_secondary}">{secondary_short}</span>
                  </span>
                  <span class="collection-list-meta">
                    <label class="relationship-toggle">
                      <span class="relationship-switch">
                        <input type="checkbox" role="switch" aria-label="Show {safe_label} in connections" data-is-model="true" data-binding-id="{html.escape(binding_id)}" data-model-id="{html.escape(model_id)}" data-linked-principal="{html.escape(linked_principal)}" {toggle_checked}>
                        <span class="relationship-switch-ui" aria-hidden="true"></span>
                      </span>
                      <span class="toggle-label">{toggle_text}</span>
                    </label>
                  </span>
                </div>
                """
            )
        else:
            is_selected = item_id in current_links.get(linked_type, set())
            toggle_checked = " checked" if is_selected else ""
            toggle_text = "On" if is_selected else "Off"
            rows.append(
                f"""
                <div class="collection-list-row no-extended">
                  <span class="collection-list-cell-name">
                    <strong>{safe_label}</strong>
                  </span>
                  <span class="relationship-cell-title">
                    <strong>{safe_type}</strong>
                    <span class="relationship-cell-meta" title="{safe_secondary}">{secondary_short}</span>
                  </span>
                  <span class="collection-list-meta">
                    <label class="relationship-toggle">
                      <span class="relationship-switch">
                        <input type="checkbox" role="switch" aria-label="Show {safe_label} in connections" data-link-type="{html.escape(linked_type)}" value="{safe_id}" data-is-model="false"{toggle_checked}>
                        <span class="relationship-switch-ui" aria-hidden="true"></span>
                      </span>
                      <span class="toggle-label">{toggle_text}</span>
                    </label>
                  </span>
                </div>
                """
            )
    if not rows:
        return '<p class="muted">No available items.</p>'
    return (
        '<div class="collection-list entity-link-editor-list">'
        + '<div class="collection-list-head no-extended"><span>Name</span><span>Type</span><span>Connection</span></div>'
        + "".join(rows)
        + '</div>'
    )


def _render_entity_link_editor_modal(
    *,
    owner_entity_type: str,
    owner_entity_id: str,
    owner_name: str,
    connection_context: _ConnectionLookupContext,
    current_links: dict[str, set[str]],
) -> str:
    """Render a modal for adding/removing links to existing ledgers/principals/surfaces."""
    owner_type = str(owner_entity_type or "").strip().lower()
    owner_id = str(owner_entity_id or "").strip()
    modal_id = _entity_link_editor_modal_id(owner_type, owner_id)
    items: list[tuple[str, dict[str, Any]]] = []
    for linked_type in ("ledger", "principal", "surface"):
        if linked_type == owner_type:
            continue
        for item in connection_context.get(f"{linked_type}s", []):
            if isinstance(item, dict):
                items.append((linked_type, item))
    owner_ledger_id = ""
    if owner_type == "ledger":
        owner_ledger_id = owner_id
    elif owner_type == "surface":
        surface_record = connection_context.get("surface_map", {}).get(owner_id, {})
        owner_ledger_id = str(_as_dict(surface_record).get("ledger_id") or "").strip()
    model_bindings = connection_context.get("model_bindings", [])
    base_model_ids = {
        str(b.get("model_id") or "").strip().lower()
        for b in model_bindings
        if isinstance(b, dict)
        and str(b.get("source") or "").strip().lower() == "runtime-model-catalogue"
        and str(b.get("status") or "").strip().lower() == "derived"
    }
    initial_links = json.dumps({k: sorted(v) for k, v in current_links.items()})
    body = f"""
    <div class="entity-link-editor" data-owner-type="{html.escape(owner_type)}" data-owner-id="{html.escape(owner_id)}" data-owner-ledger-id="{html.escape(owner_ledger_id)}" data-initial-links="{html.escape(initial_links)}">
      <p class="muted">Toggle items On to link them to <strong>{html.escape(owner_name)}</strong>. Toggle Off to remove the link. New entities can be created from Manage Connections.</p>
      {_link_editor_checkbox_list(owner_type, owner_id, items, current_links, model_bindings, base_model_ids, owner_ledger_id)}
      <p class="muted" style="margin-top:10px;"><span id="entity-link-editor-summary"></span></p>
    </div>
    """
    actions = """
    <button type="button" class="btn" data-close-modal="true">Cancel</button>
    <button type="button" class="btn primary" id="entity-link-editor-update">Update</button>
    """
    return render_modal(
        modal_id=modal_id,
        title="Edit connections",
        description=f"Add or remove links for {owner_name}.",
        body=body,
        actions=actions,
    )


def _render_connection_rows(links: list[tuple[str, str]], prefix: str, relation_copy: str) -> str:
    if not links:
        return '<li class="muted">None</li>'
    rows: list[str] = []
    for label, item_id in links:
        label_text = str(label).strip() or str(item_id).strip()
        detail_path = f"/{prefix}/{quote(item_id, safe='')}"
        entity_type = prefix[:-1] if prefix.endswith("s") else prefix
        settings = _entity_settings_record(entity_type, item_id, label_text)
        rows.append(
            f"""
            <li class="connection-row">
              <span class="connection-row-title"><a href="{detail_path}">{html.escape(label_text)}</a></span>
              <span class="connection-row-actions">
                <a class="btn small" href="{detail_path}">Open</a>
                <button type="button" class="btn small" data-open-modal="connection-settings-modal" data-modal-mode="settings"
                  data-connection-kind="{html.escape(entity_type)}"
                  data-entity-type="{html.escape(entity_type)}"
                  data-entity-id="{html.escape(item_id)}"
                  data-connection-label="{html.escape(label_text)}"
                  data-connection-relation="{html.escape(relation_copy)}"
                  data-enabled-state="{html.escape(str(settings.get('enabled_state') or 'enabled'))}"
                  data-permission-set="{html.escape(str(settings.get('permission_set') or 'default'))}"
                  data-start-date="{html.escape(str(settings.get('start_date') or ''))}"
                  data-end-date="{html.escape(str(settings.get('end_date') or ''))}"
                  data-notes="{html.escape(str(settings.get('notes') or ''))}"
                  data-constraints="{html.escape(str(settings.get('constraints') or ''))}"
                  data-metadata="{html.escape(str(settings.get('metadata') or ''))}">Settings</button>
                <button type="button" class="btn small danger" data-open-modal="connection-confirmation-modal"
                  data-connection-kind="{html.escape(entity_type)}"
                  data-connection-label="{html.escape(label_text)}"
                  data-connection-relation="{html.escape(relation_copy)}">Remove</button>
              </span>
            </li>
            """
        )
    return "".join(rows)


def _permission_scope_from_settings(settings: dict[str, Any]) -> str:
    permission_scope = str(settings.get("permission_scope") or "").strip().lower()
    if permission_scope in {"full", "custom"}:
        return permission_scope
    permission_set = str(settings.get("permission_set") or "default").strip().lower()
    return "custom" if permission_set == "custom" else "full"


def _relationship_permission_payload(settings: dict[str, Any]) -> dict[str, Any]:
    raw_payload = settings.get("permission_payload")
    if isinstance(raw_payload, dict):
        return raw_payload
    payload_text = str(raw_payload or "").strip()
    if not payload_text:
        return {}
    try:
        parsed = json.loads(payload_text)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def _permission_preset_from_settings(settings: dict[str, Any]) -> str:
    payload = _relationship_permission_payload(settings)
    permission_scope = _permission_scope_from_settings(settings)
    if permission_scope == "custom":
        return "custom"
    payload_preset = str(payload.get("preset") or "").strip().lower()
    if payload_preset in {"view", "contribute", "manage", "custom"}:
        return payload_preset
    if any(bool(payload.get(key)) for key in ("custom", "custom_capabilities", "permission_overrides")):
        return "custom"
    if bool(payload.get("can_manage_permissions")) or bool(payload.get("can_approve_submissions")):
        return "manage"
    if bool(payload.get("can_contribute")) or bool(payload.get("direct_write")) or bool(payload.get("requires_approval_for_writes")):
        return "contribute"
    if bool(payload.get("can_view")):
        return "view"
    return "manage"


def _permission_execution_mode_from_settings(settings: dict[str, Any]) -> str:
    execution_mode = str(settings.get("execution_mode") or "").strip().lower()
    if execution_mode in {"direct_write", "submitted_for_approval"}:
        return execution_mode
    payload = _relationship_permission_payload(settings)
    payload_mode = str(payload.get("execution_mode") or "").strip().lower()
    if payload_mode in {"direct_write", "submitted_for_approval"}:
        return payload_mode
    if bool(payload.get("requires_approval_for_writes")):
        return "submitted_for_approval"
    return "direct_write"


def _relationship_supports_scope_mode(relationship: dict[str, Any]) -> bool:
    subject_type = str(relationship.get("subject_entity_type") or "").strip().lower()
    object_type = str(relationship.get("object_entity_type") or "").strip().lower()
    pair = {subject_type, object_type}
    return bool(pair & {"ledger", "surface"})


def _permission_preset_blurb(preset: str) -> str:
    blurbs = {
        "view": "Inspect this connection without changing anything.",
        "contribute": "Use the connection and submit bounded updates.",
        "manage": "Change settings, review changes, and manage access.",
        "custom": "Use a tailored capability set for this connection.",
    }
    return blurbs.get(preset, blurbs["custom"])


def _permission_summary_for_relationship(*, preset: str, relationship: dict[str, Any], entity_type: str, label: str) -> str:
    related_type = str(entity_type or relationship.get("object_entity_type") or "connection").strip().lower() or "connection"
    related_label = label or related_type.title()
    pair = {
        str(relationship.get("subject_entity_type") or "").strip().lower(),
        str(relationship.get("object_entity_type") or "").strip().lower(),
    }
    if pair == {"principal", "surface"}:
        summaries = {
            "view": f"Can inspect {related_label} and open linked records, but cannot use or change it.",
            "contribute": f"Can use {related_label} and submit updates within current policy.",
            "manage": f"Can configure {related_label}, manage access, and review linked changes.",
            "custom": f"Custom capabilities apply to how {related_label} is accessed and governed.",
        }
    elif pair == {"principal", "ledger"}:
        summaries = {
            "view": f"Can inspect {related_label} and its records, but cannot write or approve changes.",
            "contribute": f"Can add records or submit changes to {related_label} within the allowed scope.",
            "manage": f"Can manage access to {related_label}, review submissions, and update settings.",
            "custom": f"Custom capabilities apply to how {related_label} is inspected, updated, and governed.",
        }
    elif pair == {"surface", "ledger"}:
        summaries = {
            "view": f"Can read from {related_label} but cannot write.",
            "contribute": f"Can submit writes to {related_label} for approval.",
            "manage": f"Can manage how {related_label} is used and update the connection settings.",
            "custom": f"Custom capabilities apply to how this surface interacts with {related_label}.",
        }
    else:
        related_copy = related_type.replace("_", " ") or "connection"
        summaries = {
            "view": f"Can inspect this {related_copy}, but cannot change it.",
            "contribute": f"Can use this {related_copy} and submit bounded updates.",
            "manage": f"Can update this {related_copy}, review changes, and manage access.",
            "custom": f"Custom capabilities apply to this {related_copy}.",
        }
    return summaries.get(preset, summaries["custom"])


def _access_status_from_settings(settings: dict[str, Any]) -> str:
    today = datetime.now(timezone.utc).date().isoformat()
    enabled = str(settings.get("enabled_state") or "enabled").strip().lower() != "disabled"
    start = str(settings.get("start_date") or settings.get("start_at") or "").strip()
    end = str(settings.get("end_date") or settings.get("end_at") or "").strip()
    if not enabled or (start and start > today) or (end and end < today):
        return "Access disabled"
    return "Access enabled"


def _trust_class_blurb(entity_type: str, entity_id: str, context: dict[str, Any]) -> str:
    """Return a plain-English trust-class sentence for a related entity."""
    record_map = _as_dict(context.get(f"{entity_type}_map") or {})
    record = _as_dict(record_map.get(entity_id))
    standing = _as_dict(record.get("standing_view"))
    trust_class = str(standing.get("trust_class") or "").strip()
    posture_class = str(standing.get("posture_class") or "").strip()
    if not trust_class and entity_type == "ledger":
        return "This ledger connection is governed under the default ledger trust boundary."
    if not trust_class:
        return "This connection is governed under the default trust boundary for its type."
    meaning = {
        "T0": "foundational system operator",
        "T1": "high-trust operator",
        "T2": "trusted operator",
        "T3": "standard member",
        "T4": "limited or probationary member",
        "T5": "unverified or restricted connection",
    }.get(trust_class.upper(), "governed connection")
    return (
        f"This {entity_type} is classified as {trust_class} ({meaning}). "
        f"Access below follows this trust boundary unless explicitly disabled."
    )


def _mutation_banner_payload(request: Request) -> tuple[str, str]:
    direct_banner = str(request.query_params.get("banner") or "").strip()
    direct_banner_kind = str(request.query_params.get("banner_kind") or "ok").strip().lower() or "ok"
    if direct_banner:
        return direct_banner, direct_banner_kind
    execution_mode = str(request.query_params.get("execution_mode") or "").strip()
    submission_status = str(request.query_params.get("submission_status") or "").strip()
    mutation_ref = str(request.query_params.get("mutation_ref") or "").strip()
    if not execution_mode and not submission_status:
        return "", "ok"
    if execution_mode == "submitted_for_approval":
        if submission_status == "failed":
            return "Mutation submission failed. Access is unchanged until the request is applied.", "warn"
        return "Mutation submitted for approval. Access is unchanged until the request is applied.", "ok"
    summary = "Mutation applied."
    if mutation_ref:
        summary = f"Mutation applied. Ref: {mutation_ref}"
    return summary, "ok"


def _mutation_redirect_path(base_path: str, body: dict[str, Any]) -> str:
    params: dict[str, str] = {}
    for key in ("execution_mode", "submission_status", "mutation_ref", "submission_ref"):
        value = str(body.get(key) or "").strip()
        if value:
            params[key] = value
    if not params:
        return base_path
    return f"{base_path}?{urlencode(params)}"


def _activity_href_for_entity(entity_type: str, entity_id: str, *, principal_did: str = "") -> str:
    params = {"entity_type": entity_type, "q": entity_id}
    if principal_did:
        params["principal_did"] = principal_did
    return f"/activity?{urlencode(params)}"


def _codex_principal_did() -> str:
    return os.getenv("CODEX_PRINCIPAL_DID", "")


def _snapshot_active_surface_id(snapshot: dict[str, Any], active_ledger_id: str) -> str:
    surfaces = _as_dict_list(snapshot.get("app_surfaces")) or _as_dict_list(snapshot.get("surfaces"))
    preferred = ""
    fallback = ""
    for item in surfaces:
        surface_id = str(item.get("surface_id") or "").strip()
        if not surface_id:
            continue
        status = str(item.get("status") or "").strip().lower()
        if not fallback and status in {"active", "configured", "derived", "planned"}:
            fallback = surface_id
        if (
            str(item.get("ledger_id") or "").strip() == active_ledger_id
            and status in {"active", "configured", "derived", "planned"}
        ):
            if surface_id == "surface:chat:primary":
                return surface_id
            if not preferred:
                preferred = surface_id
    return preferred or fallback


def _codex_provision_defaults(identity_card: dict[str, Any] | None, snapshot: dict[str, Any]) -> dict[str, str]:
    identity_vc = _as_dict(_as_dict(identity_card).get("identity_vc"))
    tenant_id = str(identity_vc.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID
    delegated_by_principal_did = str(identity_vc.get("principal_did") or "").strip()
    active_ledger_id = str(identity_vc.get("ledger_id") or "").strip()
    active_surface_id = _snapshot_active_surface_id(snapshot, active_ledger_id) if active_ledger_id else ""
    return {
        "tenant_id": tenant_id,
        "delegated_by_principal_did": delegated_by_principal_did,
        "active_ledger_id": active_ledger_id,
        "active_surface_id": active_surface_id,
        "delegation_mode": "delegated_only",
    }


def _recent_events_for_entity(
    entity_type: str,
    entity_id: str,
    *,
    connection_context: _ConnectionLookupContext,
    control_plane_state: dict[str, Any] | None = None,
) -> list[dict[str, Any]]:
    try:
        effective_control_plane_state = control_plane_state if isinstance(control_plane_state, dict) else _load_control_plane_state()
        events = _normalize_event_stream(
            connection_context.get("principals", []),
            "",
            {},
            connection_context,
            effective_control_plane_state,
        )
        matched: list[dict[str, Any]] = []
        for event in events:
            event_entity_type = str(event.get("entity_type") or "").strip().lower()
            event_entity_id = str(event.get("entity_id") or "").strip()
            event_ledger_id = str(event.get("ledger_id") or "").strip()
            if entity_type == "ledger":
                if entity_id not in {event_entity_id, event_ledger_id}:
                    continue
            elif event_entity_type != entity_type or event_entity_id != entity_id:
                continue
            matched.append(event)
        return matched[:5]
    except Exception:
        return []


def _render_activity_list(events: list[dict[str, Any]], *, href: str) -> str:
    items = "".join(
        f"""
        <li>
          <strong>{html.escape(str(event.get("summary") or "Activity event"))}</strong>
          <span class="relationship-activity-time">{html.escape(str(event.get("timestamp") or "unknown"))}</span>
        </li>
        """
        for event in events
    ) or '<li class="muted">No recent events are visible yet.</li>'
    return f"""
    <ul class="relationship-activity-list">{items}</ul>
    <div class="inline-actions" style="margin-top:12px;">
      <a class="btn small" href="{html.escape(href)}">Full activity list</a>
    </div>
    """


def _render_relationship_table(
    rows: list[dict[str, str]],
    *,
    connection_context: _ConnectionLookupContext,
    owner_entity_type: str,
    owner_entity_id: str,
    principal_focus: str = "",
    current_principal_did: str = "",
) -> str:
    if not rows:
        return '<p class="muted">No governed relationships are available yet.</p>'
    relationship_records = _as_dict_list(connection_context.get("relationships"))
    row_html: list[str] = []
    for row in rows:
        entity_type = str(row.get("entity_type") or "").strip().lower()
        entity_id = str(row.get("entity_id") or "").strip()
        label = str(row.get("label") or entity_id).strip() or entity_id
        secondary = str(row.get("secondary") or entity_id).strip() or entity_id
        secondary_truncated = secondary if len(secondary) <= 25 else f"{secondary[:22]}..."
        status = str(row.get("status") or "Unknown").strip().title()
        status_class = ""
        if status.lower() not in {"active", "enabled", "ready", "connected"}:
            status_class = "error" if status.lower() in {"error", "failed", "blocked", "revoked"} else "pending"
        relationship = _as_dict(row.get("relationship_record"))
        if not relationship:
            relationship = _relationship_record(
                owner_entity_type,
                owner_entity_id,
                entity_type,
                entity_id,
                label,
                relationship_records=relationship_records,
            )
        access_status = _access_status_from_settings(relationship)
        permission_payload = _relationship_permission_payload(relationship)
        preset = _permission_preset_from_settings(relationship)
        execution_mode = _permission_execution_mode_from_settings(relationship)
        supports_scope = _relationship_supports_scope_mode(relationship)
        advanced_open = preset == "custom"
        enabled = str(relationship.get("enabled_state") or "enabled").strip().lower() != "disabled"
        start_date = str(relationship.get("start_date") or relationship.get("start_at") or "").strip()
        end_date = str(relationship.get("end_date") or relationship.get("end_at") or "").strip()
        custom_payload_text = json.dumps(permission_payload, sort_keys=True, indent=2) if permission_payload else ""
        activity_href = _activity_href_for_entity(entity_type, entity_id, principal_did=principal_focus)
        activity_html = _render_activity_list(
            _recent_events_for_entity(entity_type, entity_id, connection_context=connection_context),
            href=activity_href,
        )
        remove_button_html = ""
        if owner_entity_type == "ledger":
            remove_button_html = f"""
            <div class="relationship-inline-actions">
              <button type="button" class="btn danger relationship-remove-trigger"
                data-remove-entity-type="{html.escape(entity_type)}"
                data-remove-entity-id="{html.escape(entity_id)}"
                data-remove-ledger-id="{html.escape(owner_entity_id)}">
                Remove from ledger
              </button>
            </div>
            """
        row_html.append(
            f"""
            <details class="relationship-row" data-filter-name="{html.escape(f'{label} {secondary}'.lower())}" data-relationship-type="{html.escape(entity_type)}" data-pageable-item data-pageable-kind="connections" data-accordion-group="control-plane-relationships">
              <summary class="relationship-row-summary">
                <span class="relationship-cell-title">
                  <strong>{_relationship_label_html(label, entity_type=entity_type, entity_id=entity_id, current_principal_did=current_principal_did)}</strong>
                </span>
                <span class="relationship-cell-meta-wrap">
                  <span class="relationship-cell-meta" title="{html.escape(secondary)}">{html.escape(secondary_truncated)}</span>
                  <button type="button" class="relationship-copy-btn" data-copy-value="{html.escape(secondary)}" aria-label="Copy full Verified ID">⧉</button>
                </span>
                <span>{html.escape(str(row.get("kind_label") or entity_type.title()))}</span>
                <span><span class="status-dot {status_class}" style="margin-right:5px;"></span>{html.escape(status)}</span>
              </summary>
              <div class="relationship-row-panel">
                <details class="relationship-subpanel" open>
                  <summary>Access</summary>
                  <div class="relationship-subpanel-body">
                    <form class="relationship-settings-form"
                      data-subject-entity-type="{html.escape(str(relationship.get('subject_entity_type') or ''))}"
                      data-subject-entity-id="{html.escape(str(relationship.get('subject_entity_id') or ''))}"
                      data-object-entity-type="{html.escape(str(relationship.get('object_entity_type') or ''))}"
                      data-object-entity-id="{html.escape(str(relationship.get('object_entity_id') or ''))}"
                      data-relationship-type="{html.escape(str(relationship.get('relationship_type') or 'related_to'))}"
                      data-entity-type="{html.escape(entity_type)}"
                      data-entity-id="{html.escape(entity_id)}"
                      data-supports-scope="{'true' if supports_scope else 'false'}"
                      data-label="{html.escape(label)}">
                      <p class="muted" style="margin:0 0 12px;">{html.escape(_trust_class_blurb(entity_type, entity_id, connection_context))}</p>
                      <div class="relationship-settings-top">
                        <div class="relationship-settings-heading">
                          <strong>Access</strong>
                          <span>Enable or disable this connection.</span>
                        </div>
                        <span class="relationship-cell-meta" data-access-status>{html.escape(access_status)}</span>
                      </div>
                      <div class="relationship-access-fields">
                        <label class="relationship-toggle">
                          <span class="relationship-switch">
                            <input type="checkbox" name="access_enabled" role="switch" aria-label="Access enabled"{" checked" if enabled else ""}>
                            <span class="relationship-switch-ui" aria-hidden="true"></span>
                          </span>
                          <span>Access enabled</span>
                        </label>
                        <div class="relationship-inline-grid">
                          <label class="relationship-inline-field">
                            <span>Start date</span>
                            <input type="date" name="start_date" value="{html.escape(start_date)}">
                          </label>
                          <label class="relationship-inline-field">
                            <span>End date</span>
                            <input type="date" name="end_date" value="{html.escape(end_date)}">
                          </label>
                        </div>
                      </div>
                      <input type="hidden" name="permission_preset" value="{html.escape(preset)}">
                      <input type="hidden" name="execution_mode" value="{html.escape(execution_mode)}">
                      <details class="relationship-subpanel relationship-advanced-panel"{" open" if advanced_open else ""}>
                        <summary><span class="relationship-advanced-toggle">Advanced options</span></summary>
                        <div class="relationship-subpanel-body">
                          <div class="relationship-advanced-fields">
                            <label class="relationship-inline-field" data-custom-payload-field{" hidden" if preset != 'custom' else ""}>
                              <span>Custom permission payload</span>
                              <textarea class="relationship-custom-payload" name="permission_payload_custom" placeholder='{{"capability":"override"}}'>{html.escape(custom_payload_text)}</textarea>
                            </label>
                          </div>
                        </div>
                      </details>
                      <div class="relationship-settings-actions">
                        <button type="button" class="btn" data-relationship-cancel="true">Cancel</button>
                        <button type="button" class="btn primary" data-relationship-update="true">Update</button>
                      </div>
                    </form>
                  </div>
                </details>
                <details class="relationship-subpanel">
                  <summary>Activity</summary>
                  <div class="relationship-subpanel-body">
                    {activity_html}
                  </div>
                </details>
                {remove_button_html}
              </div>
            </details>
            """
        )
    return f"""
    <div class="pageable-group" data-pageable-group data-page-size="10" data-pageable-label="connections">
    <div class="relationship-table">
      <div class="relationship-table-head">
        <span>Name</span>
        <span>Verified ID</span>
        <span>Type</span>
        <span>Status</span>
      </div>
      {"".join(row_html)}
    </div>
    <div class="pageable-actions">
      <button type="button" class="btn pageable-load-more" data-pageable-trigger>Load more connections</button>
    </div>
    </div>
    """


def _render_summary_inner_table(
    col_headers: list[str],
    rows: list[tuple[str, ...]],
    grid_columns_style: str = "",
) -> str:
    """Render just the inner table for a summary section (no section wrapper)."""
    head_cells = "".join(f'<span>{html.escape(h)}</span>' for h in col_headers)
    grid_override = f' style="{html.escape(grid_columns_style)}"' if grid_columns_style else ""
    row_grid = f' style="border-bottom:1px solid var(--border);{html.escape(grid_columns_style)}"' if grid_columns_style else ' style="border-bottom:1px solid var(--border);"'
    col_count = len(col_headers)
    row_html = ""
    if rows:
        for row in rows:
            cells = ""
            for i, cell in enumerate(row):
                if i == col_count - 1:
                    # Last column gets status dot treatment
                    cells += f'<span style="padding:10px 12px;"><span class="status-dot" style="margin-right:5px;"></span>{html.escape(str(cell))}</span>'
                elif i == 0:
                    cells += f'<span style="padding:10px 12px; font-weight:500;">{html.escape(str(cell))}</span>'
                else:
                    cells += f'<span style="padding:10px 12px;">{html.escape(str(cell))}</span>'
            row_html += f'<div class="relationship-row-summary"{row_grid}>{cells}</div>'
    else:
        row_html = f'<div class="relationship-row-summary"><span class="muted" style="padding:10px 12px; grid-column:1/-1;">No entries yet.</span></div>'
    return f"""
    <div class="relationship-table">
        <div class="relationship-table-head"{grid_override}>
            {head_cells}
        </div>
        {row_html}
    </div>
    """


def _render_summary_card_stack(
    rows: list[tuple[str, str, str, str]],
) -> str:
    """Render summary rows as a stack of card panels instead of a nested table.

    Each row: (label, value, type_tag, status)
    """
    if not rows:
        return '<p class="muted">No entries yet.</p>'
    cards = "".join(
        f"""
        <div class="summary-card">
            <div class="summary-card-header">
                <span class="summary-card-title">{html.escape(label)}</span>
                <span class="summary-card-status"><span class="status-dot" style="margin-right:5px;"></span>{html.escape(status)}</span>
            </div>
            <div class="summary-card-body">
                <div class="summary-card-value">{html.escape(value)}</div>
                <div class="summary-card-meta">{html.escape(type_tag)}</div>
            </div>
        </div>
        """
        for label, value, type_tag, status in rows
    )
    return f"""
    <div class="summary-card-stack">
        {cards}
    </div>
    """


def _render_ledger_document_archive_inner(
    ledger_id: str,
    current_principal_did: str,
    sources: list[dict[str, Any]],
    source_jobs: list[dict[str, Any]],
    backend_attachments: list[dict[str, Any]] | None = None,
) -> tuple[str, int]:
    """Render Document Archive inner table + upload form. Returns (html, source_count)."""
    ledger_sources = [
        s for s in sources
        if str(s.get("ledger_id") or "").strip() == ledger_id
    ]
    backend_sources = list(backend_attachments or [])
    # Merge backend attachments with local sources, deduping by coordinate
    seen_coords: set[str] = set()
    merged_sources: list[dict[str, Any]] = []
    for src in backend_sources + ledger_sources:
        coord = str(src.get("coordinate") or "").strip()
        if coord and coord in seen_coords:
            continue
        if coord:
            seen_coords.add(coord)
        merged_sources.append(src)
    ledger_sources = merged_sources
    recent_jobs = [j for j in source_jobs if str(j.get("ledger_id") or "").strip() == ledger_id][:3]
    latest_job = recent_jobs[0] if recent_jobs else None
    latest_job_status = str(latest_job.get("status") or "idle").title() if isinstance(latest_job, dict) else "Idle"
    latest_job_ref = str(latest_job.get("job_id") or "") if isinstance(latest_job, dict) else ""

    source_rows = []
    for src in ledger_sources[:20]:
        fname = str(src.get("file_name") or src.get("original_file_name") or src.get("coordinate") or src.get("source_id") or "Unnamed").strip()
        summary = str(src.get("summary") or "").strip()
        ctype = str(src.get("content_type") or "unknown").strip()
        src_status = str(src.get("status") or "queued").strip().title()
        coord = str(src.get("coordinate") or "").strip()
        source_rows.append((fname, summary, coord, ctype, src_status))

    archive_row_html = "".join(
        f"""
        <div class="doc-archive-row">
            <span class="doc-archive-name" title="{html.escape(fname)}">{html.escape(fname)}</span>
            <span class="doc-archive-summary" title="{html.escape(summary)}">{html.escape(summary or '—')}</span>
            <span class="doc-archive-coord" title="{html.escape(coord)}">{html.escape(coord or '—')}</span>
            <span class="doc-archive-type">{html.escape(ctype)}</span>
            <span><span class="status-dot" style="margin-right:5px;"></span>{html.escape(src_status)}</span>
        </div>
        """
        for fname, summary, coord, ctype, src_status in source_rows
    )
    table_html = f"""
    <div class="doc-archive-list">
        {archive_row_html or '<div class="doc-archive-row"><span class="muted" style="grid-column:1/-1;">No documents archived yet.</span></div>'}
    </div>
    """

    upload_extra = f"""
    <div style="margin-top:16px;">
        <form class="ledger-doc-upload-form" method="post" action="/api/control-plane/sources/upload" enctype="multipart/form-data" data-ledger-id="{html.escape(ledger_id)}">
            <input type="hidden" name="ledger_id" value="{html.escape(ledger_id)}">
            <input type="hidden" name="principal_did" value="{html.escape(current_principal_did)}">
            <input type="hidden" name="batch_label" value="Ledger document archive">
            <div class="doc-upload-dropzone" data-dropzone>
                <input id="ledger-doc-files-{html.escape(ledger_id)}" class="doc-upload-input" type="file" name="source_files" accept=".txt,.md,.json,.csv,.html,.xml,.pdf,.doc,.docx" multiple required>
                <p class="doc-upload-hint">Drag and drop files here, or</p>
                <button type="button" class="btn primary" data-browse>Browse files</button>
                <p class="muted doc-upload-formats">txt, md, json, csv, html, xml, pdf, doc, docx</p>
            </div>
        </form>
        <div class="ledger-doc-progress" data-ledger-doc-progress="{html.escape(ledger_id)}" style="margin-top:10px; display:none;">
            <div style="background:var(--surface-muted); border-radius:6px; overflow:hidden; height:18px;">
                <div data-ledger-doc-bar="{html.escape(ledger_id)}" style="width:0%; height:100%; background:var(--ok); transition:width 0.3s;"></div>
            </div>
            <p class="muted" data-ledger-doc-status="{html.escape(ledger_id)}" style="margin-top:6px; font-size:0.85rem;">Preparing upload...</p>
        </div>
        {f'<p class="muted" style="margin-top:8px; font-size:0.85rem;">Latest job: {html.escape(latest_job_ref)} is {html.escape(latest_job_status.lower())}.</p>' if latest_job_ref else ''}
    </div>
    """

    return table_html + upload_extra, len(ledger_sources)


def _render_ledger_summary_accordion(
    sections: list[tuple[str, str, str, str]],
) -> str:
    """Render all summary sections as one expandable accordion table.

    Each section: (title, overview, status_label, inner_html)
    Columns: Summary Section | Overview | Status
    """
    row_html = "".join(
        f"""
        <details class="relationship-row" data-accordion-group="ledger-summary">
            <summary class="relationship-row-summary" style="grid-template-columns:minmax(200px,1.5fr) minmax(300px,2fr) minmax(120px,1fr);">
                <span><strong>{html.escape(title)}</strong></span>
                <span class="muted">{html.escape(overview)}</span>
                <span><span class="status-dot" style="margin-right:5px;"></span>{html.escape(status_label)}</span>
            </summary>
            <div class="relationship-row-panel">
                {inner_html}
            </div>
        </details>
        """
        for title, overview, status_label, inner_html in sections
    )
    return f"""
    <div class="relationship-table">
        <div class="relationship-table-head" style="grid-template-columns:minmax(200px,1.5fr) minmax(300px,2fr) minmax(120px,1fr);">
            <span>Summary Section</span>
            <span>Overview</span>
            <span>Status</span>
        </div>
        {row_html}
    </div>
    """


def render_ledger_detail_page(
    ledger: _LedgerDetailData,
    *,
    connection_context: _ConnectionLookupContext,
    profile_name: str = "Profile",
    current_principal_did: str = "",
    banner: str = "",
    banner_kind: str = "ok",
    backend_attachments: list[dict[str, Any]] | None = None,
) -> str:
    link_editor_modal_id = _entity_link_editor_modal_id("ledger", ledger["ledger_id"])
    current_links = {
        "principal": {link_id for _, link_id in ledger.get("principal_links", [])},
        "surface": {link_id for _, link_id in ledger.get("surface_links", [])},
    }
    link_editor_html = _render_entity_link_editor_modal(
        owner_entity_type="ledger",
        owner_entity_id=ledger["ledger_id"],
        owner_name=ledger["name"],
        connection_context=connection_context,
        current_links=current_links,
    )
    modal_html = (
        render_connection_settings_modal()
        + render_confirmation_dialog()
        + render_entity_removal_dialog()
        + render_removal_impact_modal()
        + link_editor_html
    )
    banner_html = f'<div class="banner {banner_kind}" style="margin:0 0 16px;">{html.escape(banner)}</div>' if banner else ""
    all_rows = list(ledger.get("related_rows") or [])
    filter_counts = _relationship_filter_counts(all_rows)
    summary_panel_id = f"ledger-summary-panel-{_slug_token(ledger['ledger_id'], 'ledger')}"
    action_menu_html = render_toolbar_menu_cta(
        label="Add / Edit",
        items_html=(
            f'<button type="button" data-open-modal="{html.escape(link_editor_modal_id)}">Edit connections</button>'
            f'<a href="/connections/add/ledger?ledger_id={quote(ledger["ledger_id"], safe="")}">Edit ledger</a>'
            f'<button type="button" data-open-modal="entity-removal-modal" data-connection-kind="ledger" data-connection-label="{html.escape(ledger["name"])}" data-connection-relation="linked principals and surfaces" data-remove-entity-type="ledger" data-remove-entity-id="{html.escape(ledger["ledger_id"])}" data-remove-redirect="/connections">Remove ledger</button>'
        ),
    )
    founding_constitution = _as_dict(ledger.get("metadata")).get("founding_constitution") if isinstance(_as_dict(ledger.get("metadata")).get("founding_constitution"), dict) else {}
    constitution_name = str(_as_dict(founding_constitution).get("name") or "").strip()
    constitution_personality = str(_as_dict(founding_constitution).get("personality") or "").strip()
    constitution_purpose = str(_as_dict(founding_constitution).get("purpose") or "").strip()
    alias_history = [str(item).strip() for item in _as_list(_as_dict(ledger.get("metadata")).get("ledger_alias_history")) if str(item).strip()]
    supersession_history = [str(item).strip() for item in _as_list(_as_dict(ledger.get("metadata")).get("ledger_supersession_history")) if str(item).strip()]
    consolidation_history = [item for item in _as_list(_as_dict(ledger.get("metadata")).get("ledger_consolidation_history")) if item]
    self_description = _as_dict(ledger.get("ledger_self_description"))
    verified_traits = [item for item in _as_list(self_description.get("verified_ledger_traits")) if isinstance(item, dict)]
    resolved_constitution_context = _as_dict(self_description.get("resolved_constitution_context"))
    runtime_foundation_identity = _as_dict(self_description.get("runtime_foundation_identity"))
    speculative_overlay = _as_dict(self_description.get("speculative_overlay"))

    # Load sources for this ledger
    control_plane_state = _load_control_plane_state()
    sources_data = _source_records_from_state(control_plane_state)
    source_jobs_data = _source_jobs_from_state(control_plane_state)

    # Build summary sections
    founding_charter_rows: list[tuple[str, str, str, str]] = []
    if constitution_name:
        founding_charter_rows.append(("Ledger self-name", constitution_name, "Charter | Name", "Immutable"))
    if constitution_personality:
        founding_charter_rows.append(("Starter personality", constitution_personality, "Charter | Personality", "Governed"))
    if constitution_purpose:
        founding_charter_rows.append(("Purpose", constitution_purpose, "Charter | Purpose", "Immutable"))

    identity_rows: list[tuple[str, str, str, str]] = [
        ("Display label", ledger["name"], "Identity | Display", ledger["status"]),
        ("Canonical subject", ledger["canonical_subject"], "Identity | Canonical", "Active"),
        ("Canonical ledger ID", ledger["ledger_id"], "Identity | DID", "Resolved"),
    ]
    if str(ledger.get("display_subtitle") or "").strip():
        identity_rows.append(("Runtime namespace", ledger["display_subtitle"], "Identity | Namespace", "Bound"))

    operational_rows: list[tuple[str, str, str, str]] = [
        ("Connected principals", str(len(ledger["principal_links"])), "Count | Principals", "Active"),
        ("Connected surfaces", str(len(ledger["surface_links"])), "Count | Surfaces", "Active"),
    ]

    technical_rows: list[tuple[str, str, str, str]] = [
        ("Ledger identifier", ledger["ledger_id"], "Config | Identifier", "Verified"),
        ("Canonical subject", ledger["canonical_subject"], "Config | Subject", "Bound"),
    ]
    if constitution_name and constitution_name != ledger["name"]:
        technical_rows.append(("Self-name override", constitution_name, "Config | Alias", "Governed"))

    runtime_foundation_fields = _as_dict(runtime_foundation_identity.get("fields"))
    runtime_foundation_rows: list[tuple[str, str, str, str]] = []
    if runtime_foundation_identity:
        available = bool(runtime_foundation_identity.get("available"))
        runtime_foundation_rows.append(("Available", str(available), "Runtime | Availability", "Active" if available else "Inactive"))
        if runtime_foundation_fields.get("name"):
            runtime_foundation_rows.append(("Name", str(runtime_foundation_fields["name"]), "Runtime | Name", "Resolved"))
        if runtime_foundation_fields.get("personality"):
            runtime_foundation_rows.append(("Personality", str(runtime_foundation_fields["personality"]), "Runtime | Personality", "Resolved"))
        if runtime_foundation_fields.get("purpose"):
            runtime_foundation_rows.append(("Purpose", str(runtime_foundation_fields["purpose"]), "Runtime | Purpose", "Resolved"))
        if runtime_foundation_fields.get("source"):
            runtime_foundation_rows.append(("Source", str(runtime_foundation_fields["source"]), "Runtime | Source", "Verified"))
        if "structured_runtime_surface_required" in runtime_foundation_identity:
            required = bool(runtime_foundation_identity["structured_runtime_surface_required"])
            runtime_foundation_rows.append(("Structured runtime surface required", str(required), "Runtime | Surface", "Required" if required else "Optional"))

    resolved_constitution_rows: list[tuple[str, str, str, str]] = []
    if resolved_constitution_context:
        present = bool(resolved_constitution_context.get("present"))
        resolved_constitution_rows.append(("Present", str(present), "Constitution | Present", "Active" if present else "Inactive"))
        basis = [str(item) for item in _as_list(resolved_constitution_context.get("basis")) if str(item).strip()]
        if basis:
            resolved_constitution_rows.append(("Basis", ", ".join(basis), "Constitution | Basis", "Recorded"))
        if "coord_resolved_access_is_not_runtime_foundation_identity" in resolved_constitution_context:
            resolved_constitution_rows.append((
                "COORD resolved access is not runtime foundation identity",
                str(resolved_constitution_context["coord_resolved_access_is_not_runtime_foundation_identity"]),
                "Constitution | Identity",
                "Verified",
            ))

    verified_traits_rows: list[tuple[str, str, str, str]] = []
    for trait_item in verified_traits:
        trait_name = str(trait_item.get("trait") or "").strip()
        trait_summary = str(trait_item.get("summary") or "").strip()
        if not trait_name:
            continue
        label = trait_name.replace("_", " ").title()
        evidence_parts = [
            f"{str(ev.get('field') or '').replace('_', ' ').title()}: {str(ev.get('value') or '')}"
            for ev in _as_list(trait_item.get("evidence"))
            if isinstance(ev, dict)
        ]
        evidence_text = "; ".join(evidence_parts) or trait_summary
        verified_traits_rows.append((f"{label}:", evidence_text, "Trait | " + label, "Verified"))

    speculative_overlay_rows: list[tuple[str, str, str, str]] = []
    if speculative_overlay:
        overlay_summary = str(speculative_overlay.get("summary") or "").strip()
        if overlay_summary:
            speculative_overlay_rows.append(("Summary", overlay_summary, "Overlay | Summary", "Optional"))

    alias_consolidation_rows: list[tuple[str, str, str, str]] = []
    if alias_history:
        alias_consolidation_rows.append(("Alias history", ", ".join(alias_history), "History | Alias", "Recorded"))
    if supersession_history:
        alias_consolidation_rows.append(("Superseded ledgers", ", ".join(supersession_history), "History | Supersession", "Recorded"))
    if consolidation_history:
        alias_consolidation_rows.append(("Consolidation events", f"{len(consolidation_history)} event(s)", "History | Consolidation", "Recorded"))

    provenance_rows: list[tuple[str, str, str, str]] = []
    if constitution_name or constitution_purpose:
        provenance_rows.append(("Founding constitution", "Operator-seeded", "Event | Seed", "Governed"))
    if alias_history:
        provenance_rows.append(("Alias history", f"{len(alias_history)} reference(s)", "Context | Alias", "Recorded"))
    if supersession_history:
        provenance_rows.append(("Superseded ledgers", f"{len(supersession_history)} ledger(s)", "Context | Supersession", "Recorded"))
    if consolidation_history:
        provenance_rows.append(("Consolidation events", f"{len(consolidation_history)} event(s)", "Event | Consolidation", "Recorded"))

    # Build summary section inner card stacks
    founding_charter_inner = _render_summary_card_stack(founding_charter_rows)
    identity_inner = _render_summary_card_stack(identity_rows)
    operational_inner = _render_summary_card_stack(operational_rows)
    technical_inner = _render_summary_card_stack(technical_rows)
    runtime_foundation_inner = _render_summary_card_stack(runtime_foundation_rows)
    resolved_constitution_inner = _render_summary_card_stack(resolved_constitution_rows)
    verified_traits_inner = _render_summary_card_stack(verified_traits_rows)
    speculative_overlay_inner = _render_summary_card_stack(speculative_overlay_rows)
    alias_consolidation_inner = _render_summary_card_stack(alias_consolidation_rows) + (
        f"""
        <div style="margin-top:12px; padding:12px 14px; border:1px solid var(--border); border-radius:10px; background:var(--surface); font-size:0.875rem;">
            <p class="muted" style="margin:0 0 8px;">Alias-aware runtime history continuity and foundation identity availability should remain preserved for the surviving ledger.</p>
            <p class="muted" style="margin:0;">Visible name changes append alias history only. New COORDs continue on the canonical runtime namespace until a dedicated migration workflow exists.</p>
        </div>
        """
        if alias_history or supersession_history or consolidation_history
        else ""
    )
    provenance_inner = _render_summary_card_stack(provenance_rows)
    document_archive_inner, doc_count = _render_ledger_document_archive_inner(
        ledger_id=ledger["ledger_id"],
        current_principal_did=current_principal_did,
        sources=sources_data,
        source_jobs=source_jobs_data,
        backend_attachments=backend_attachments,
    )

    summary_sections_html = _render_ledger_summary_accordion([
        (
            "Founding Charter",
            "Operator-seeded governing text that defines the ledger's bounded identity and purpose.",
            "Immutable" if founding_charter_rows else "Empty",
            founding_charter_inner,
        ),
        (
            "Identity & Addressing",
            "Stable identifiers, display names, and namespace bindings for this ledger.",
            ledger["status"],
            identity_inner,
        ),
        (
            "Document Archive",
            "Foundational documents attached to this ledger. Uploads are processed asynchronously and chunked for retrieval.",
            f"{doc_count} document{'s' if doc_count != 1 else ''}" if doc_count else "Empty",
            document_archive_inner,
        ),
    ])

    relationship_table_html = _render_relationship_table(
        all_rows,
        connection_context=connection_context,
        owner_entity_type="ledger",
        owner_entity_id=ledger["ledger_id"],
        current_principal_did=current_principal_did,
    )

    header_html = render_connection_detail_header(
        title=ledger["name"],
        status=ledger["status"],
        description=(
            f"Review ledger identity {ledger['canonical_subject']} and the governed relationships it holds across principals and surfaces. Runtime namespace: {ledger['display_subtitle']}."
            if str(ledger.get("display_subtitle") or "").strip()
            else f"Review ledger identity {ledger['canonical_subject']} and the governed relationships it holds across principals and surfaces."
        ),
    )

    list_html = f"""
    {banner_html}
    <div class="ledger-detail-views">
        <div class="ledger-relationship-view" data-ledger-relationship-view>
            {relationship_table_html}
        </div>
        <div class="ledger-summary-view" id="{html.escape(summary_panel_id)}" data-ledger-summary-view>
            {summary_sections_html}
        </div>
    </div>
    {modal_html}
    <style>
        .ledger-detail-views {{ display: grid; gap: 24px; }}
        .ledger-relationship-view {{ display: grid; }}
        .ledger-relationship-view.hidden {{ display: none; }}
        .ledger-summary-view {{ display: none; }}
        .ledger-summary-view.open {{ display: grid; gap: 24px; }}
    </style>
    <script>
        (function() {{
            const relationshipView = document.querySelector('[data-ledger-relationship-view]');
            const summaryView = document.querySelector('[data-ledger-summary-view]');

            function syncViews() {{
                if (summaryView && summaryView.classList.contains('open')) {{
                    if (relationshipView) relationshipView.classList.add('hidden');
                }} else {{
                    if (relationshipView) relationshipView.classList.remove('hidden');
                }}
            }}

            // Observe class changes on the summary panel so we stay in sync
            // with the existing data-detail-panel-toggle handler without fighting it
            if (summaryView) {{
                const observer = new MutationObserver(function() {{ syncViews(); }});
                observer.observe(summaryView, {{ attributes: true, attributeFilter: ['class'] }});
            }}

            // Initial sync
            syncViews();

            // Document drop-zone: browse button, drag-and-drop, and file selection
            document.querySelectorAll('.doc-upload-dropzone').forEach((zone) => {{
                const form = zone.closest('.ledger-doc-upload-form');
                const input = zone.querySelector('.doc-upload-input');
                const browseBtn = zone.querySelector('[data-browse]');

                if (browseBtn && input) {{
                    browseBtn.addEventListener('click', () => input.click());
                }}

                if (input && form) {{
                    input.addEventListener('change', () => {{
                        if (input.files && input.files.length) {{
                            form.dispatchEvent(new Event('submit'));
                        }}
                    }});
                }}

                ['dragenter', 'dragover', 'dragleave', 'drop'].forEach((eventName) => {{
                    zone.addEventListener(eventName, (e) => {{
                        e.preventDefault();
                        e.stopPropagation();
                    }}, false);
                }});

                ['dragenter', 'dragover'].forEach((eventName) => {{
                    zone.addEventListener(eventName, () => zone.classList.add('active'), false);
                }});

                ['dragleave', 'drop'].forEach((eventName) => {{
                    zone.addEventListener(eventName, () => zone.classList.remove('active'), false);
                }});

                zone.addEventListener('drop', (e) => {{
                    const files = e.dataTransfer.files;
                    if (input && files.length) {{
                        input.files = files;
                        if (form) form.dispatchEvent(new Event('submit'));
                    }}
                }});
            }});

            // Document upload with progress
            document.querySelectorAll('.ledger-doc-upload-form').forEach((form) => {{
                form.addEventListener('submit', async (event) => {{
                    event.preventDefault();
                    const ledgerId = form.getAttribute('data-ledger-id') || '';
                    const progressWrap = document.querySelector('[data-ledger-doc-progress="' + ledgerId + '"]');
                    const progressBar = document.querySelector('[data-ledger-doc-bar="' + ledgerId + '"]');
                    const statusNode = document.querySelector('[data-ledger-doc-status="' + ledgerId + '"]');
                    const button = form.querySelector('[data-browse]');
                    const fileInput = form.querySelector('.doc-upload-input');
                    if (button) button.disabled = true;
                    if (progressWrap) progressWrap.style.display = 'block';
                    if (progressBar) progressBar.style.width = '10%';
                    if (statusNode) statusNode.textContent = 'Uploading documents...';

                    try {{
                        const response = await fetch(form.action, {{
                            method: 'POST',
                            headers: {{ 'accept': 'application/json' }},
                            credentials: 'same-origin',
                            body: new FormData(form),
                        }});
                        const payload = await response.json().catch(() => ({{}}));
                        const job = payload && typeof payload === 'object' ? payload.job : null;
                        if (!response.ok) {{
                            const detail = payload && (payload.detail || payload.error) ? (typeof payload.detail === 'string' ? payload.detail : (payload.detail.reason || payload.detail.error || payload.error)) : 'Upload failed';
                            if (statusNode) statusNode.textContent = 'Unable to queue upload: ' + detail;
                            if (progressBar) progressBar.style.width = '0%';
                            return;
                        }}
                        const jobId = job && job.job_id ? String(job.job_id) : 'unknown';
                        const jobState = job && job.status ? String(job.status) : 'queued';
                        if (jobState === 'completed') {{
                            if (progressBar) progressBar.style.width = '100%';
                            if (statusNode) statusNode.textContent = 'Upload complete. Job ref: ' + jobId + '.';
                            window.setTimeout(() => window.location.reload(), 800);
                            return;
                        }}
                        if (progressBar) progressBar.style.width = '30%';
                        if (statusNode) statusNode.textContent = 'Queued as ' + jobState + '. Job ref: ' + jobId + '.';
                        if (!jobId || jobId === 'unknown') return;

                        const poll = async () => {{
                            try {{
                                const statusResponse = await fetch('/api/control-plane/source-jobs/' + encodeURIComponent(jobId), {{
                                    headers: {{ 'accept': 'application/json' }},
                                    credentials: 'same-origin',
                                }});
                                const statusPayload = await statusResponse.json().catch(() => ({{}}));
                                if (!statusResponse.ok) {{
                                    if (statusNode) statusNode.textContent = 'Status refresh unavailable for job ' + jobId;
                                    return;
                                }}
                                const statusJob = statusPayload && typeof statusPayload === 'object' ? statusPayload.job : null;
                                const nextState = statusJob && statusJob.status ? String(statusJob.status) : 'unknown';
                                const progressDone = parseInt(statusJob && statusJob.progress_done ? String(statusJob.progress_done) : '0', 10);
                                const progressTotal = parseInt(statusJob && statusJob.progress_total ? String(statusJob.progress_total) : '0', 10);
                                const pct = progressTotal > 0 ? Math.max(10, Math.min(95, Math.round((progressDone / progressTotal) * 100))) : 50;
                                if (progressBar) progressBar.style.width = pct + '%';
                                if (nextState === 'queued' || nextState === 'running') {{
                                    if (statusNode) statusNode.textContent = 'Job ' + jobId + ' is ' + nextState + '. Progress ' + progressDone + ' / ' + progressTotal + '.';
                                    window.setTimeout(poll, 1200);
                                    return;
                                }}
                                if (nextState === 'completed') {{
                                    if (progressBar) progressBar.style.width = '100%';
                                    if (statusNode) statusNode.textContent = 'Upload complete. Job ref: ' + jobId + '.';
                                    window.setTimeout(() => window.location.reload(), 800);
                                    return;
                                }}
                                if (nextState === 'failed') {{
                                    const failureMessage = statusJob && statusJob.failure_message ? String(statusJob.failure_message) : '';
                                    if (statusNode) statusNode.textContent = 'Upload failed. Job ref: ' + jobId + '. ' + (failureMessage || 'Review backend job detail.');
                                    if (progressBar) progressBar.style.width = '0%';
                                    return;
                                }}
                                if (statusNode) statusNode.textContent = 'Job state: ' + nextState + '.';
                            }} catch (_pollError) {{
                                if (statusNode) statusNode.textContent = 'Queued. Job ref: ' + jobId + '. Status refresh unavailable right now.';
                            }}
                        }};
                        window.setTimeout(poll, 600);
                    }} catch (_error) {{
                        if (statusNode) statusNode.textContent = 'Unable to queue upload right now.';
                        if (progressBar) progressBar.style.width = '0%';
                    }} finally {{
                        if (button) button.disabled = false;
                        if (fileInput) fileInput.value = '';
                    }}
                }});
            }});
        }})();
    </script>
    """

    body_html = render_connections_page_content(
        breadcrumbs_html=render_breadcrumbs([
            ("Home", "/"),
            ("Manage Connections", "/connections"),
            ("Ledgers", "/connections?type=ledgers"),
            (ledger["name"], None),
        ]),
        header_html=header_html,
        toolbar_html=render_page_toolbar(
            search_placeholder="Filter connections by keyword",
            search_action=f"/ledgers/{quote(ledger['ledger_id'], safe='')}",
            primary_cta_html=action_menu_html,
        ),
        tabs_html=render_relationship_filter_tabs("all", counts=filter_counts, summary_panel_id=summary_panel_id, summary_active=False),
        list_html=list_html,
    )
    return _layout_with_nav(
        f"{html.escape(ledger['name'])} | {APP_TITLE}",
        body_html,
        f"/ledgers/{ledger['ledger_id']}",
        profile_name=profile_name,
    )


def render_principal_detail_page(
    principal: _PrincipalDetailData,
    *,
    connection_context: _ConnectionLookupContext,
    profile_name: str = "Profile",
    current_principal_did: str = "",
    banner: str = "",
    banner_kind: str = "ok",
) -> str:
    principal_metadata = _as_dict(principal.get("metadata"))
    delegated_authority = _as_dict(principal_metadata.get("delegated_authority"))
    delegated_action = "restore" if str(principal.get("status") or "").strip().lower() == "disabled" else "revoke"
    delegated_action_label = "Restore delegated access" if delegated_action == "restore" else "Revoke delegated access"
    delegated_action_reason = "delegated_access_restored_by_control_plane" if delegated_action == "restore" else "delegated_access_revoked_by_control_plane"
    delegated_action_copy = (
        "Re-enable this delegated principal for explicit CLI-requested prompts."
        if delegated_action == "restore"
        else "Disable this delegated principal so Codex can no longer prompt DSS until restored."
    )
    delegated_action_form = (
        f"""
        <form method="post" action="/principals/{quote(principal['principal_id'], safe='')}/delegated-access" class="stack" style="margin-top:16px;">
          <input type="hidden" name="action" value="{html.escape(delegated_action)}">
          <input type="hidden" name="reason" value="{html.escape(delegated_action_reason)}">
          <button type="submit" class="btn {'danger' if delegated_action == 'revoke' else 'primary'}">{html.escape(delegated_action_label)}</button>
          <p class="mini-note">{html.escape(delegated_action_copy)}</p>
        </form>
        """
        if delegated_authority and bool(delegated_authority.get("revocable"))
        else ""
    )
    link_editor_modal_id = _entity_link_editor_modal_id("principal", principal["principal_id"])
    current_links = {
        "ledger": {link_id for _, link_id in principal.get("ledger_links", [])},
        "surface": {link_id for _, link_id in principal.get("surface_links", [])},
    }
    link_editor_html = _render_entity_link_editor_modal(
        owner_entity_type="principal",
        owner_entity_id=principal["principal_id"],
        owner_name=principal["name"],
        connection_context=connection_context,
        current_links=current_links,
    )
    modal_html = (
        render_connection_settings_modal()
        + render_confirmation_dialog()
        + render_entity_removal_dialog()
        + render_removal_impact_modal()
        + link_editor_html
    )
    banner_html = f'<div class="banner {banner_kind}" style="margin:0 0 16px;">{html.escape(banner)}</div>' if banner else ""
    all_rows = list(principal.get("related_rows") or [])
    filter_counts = _relationship_filter_counts(all_rows)
    summary_panel_id = f"principal-summary-panel-{_slug_token(principal['principal_id'], 'principal')}"
    action_menu_html = render_toolbar_menu_cta(
        label="Add / Edit",
        items_html=(
            f'<button type="button" data-open-modal="{html.escape(link_editor_modal_id)}">Edit connections</button>'
            f'<a href="/connections/add/principal?principal_id={quote(principal["principal_id"], safe="")}">Edit principal</a>'
            f'<button type="button" data-open-modal="entity-removal-modal" data-connection-kind="principal" data-connection-label="{html.escape(principal["name"])}" data-connection-relation="linked ledgers and surfaces" data-remove-entity-type="principal" data-remove-entity-id="{html.escape(principal["principal_id"])}" data-remove-redirect="/connections">Remove principal</button>'
        ),
    )
    header_html = render_connection_detail_header(
        title=principal["name"],
        status=principal["status"],
        description="Review this principal identity and the ledgers and surfaces it can govern or access.",
    )

    # Build Summary tab accordion sections mirroring the ledger detail pattern.
    identity_rows: list[tuple[str, str, str, str]] = [
        ("Display label", principal["name"], "Identity | Display", principal["status"]),
        ("Canonical subject", principal["canonical_subject"], "Identity | Canonical", "Active"),
        ("Principal DID", principal["principal_id"], "Identity | DID", "Resolved"),
    ]
    actor_type = str(principal.get("actor_type") or "principal").strip() or "principal"
    identity_rows.append(("Actor type", actor_type, "Identity | Actor", principal["status"]))

    authority_rows: list[tuple[str, str, str, str]] = []
    if delegated_authority:
        if "delegated_prompt_execution" in delegated_authority:
            authority_rows.append(("Prompt execution", str(delegated_authority["delegated_prompt_execution"]), "Delegation | Execution", "Governed"))
        if "revocation_mode" in delegated_authority:
            authority_rows.append(("Revocation mode", str(delegated_authority["revocation_mode"]), "Delegation | Revocation", "Governed"))
        if "hidden_operator_alias" in delegated_authority:
            authority_rows.append(("Hidden operator alias", str(delegated_authority["hidden_operator_alias"]), "Delegation | Alias", "Governed"))
        if "revocable" in delegated_authority:
            authority_rows.append(("Revocable", str(delegated_authority["revocable"]), "Delegation | Revocable", "Governed"))
        if delegated_authority.get("delegated_by_principal_did"):
            authority_rows.append(("Delegated by DID", str(delegated_authority["delegated_by_principal_did"]), "Delegation | Source", "Resolved"))
        if delegated_authority.get("delegated_by_principal_id"):
            authority_rows.append(("Delegated by id", str(delegated_authority["delegated_by_principal_id"]), "Delegation | Source ID", "Resolved"))

    ledger_scope = [str(item) for item in _as_list(delegated_authority.get("ledger_scope")) if str(item).strip()]
    surface_scope = [str(item) for item in _as_list(delegated_authority.get("surface_scope")) if str(item).strip()]
    scope_rows: list[tuple[str, str, str, str]] = []
    if ledger_scope:
        scope_rows.append(("Ledger scope", ", ".join(ledger_scope), "Scope | Ledger", "Active"))
    if surface_scope:
        scope_rows.append(("Surface scope", ", ".join(surface_scope), "Scope | Surface", "Active"))

    provenance_rows: list[tuple[str, str, str, str]] = []
    tenant_id = str(principal_metadata.get("tenant_id") or "").strip()
    if tenant_id:
        provenance_rows.append(("Tenant", tenant_id, "Provenance | Tenant", "Active"))
    metadata_keys = [k for k in principal_metadata.keys() if k != "delegated_authority"]
    if metadata_keys:
        provenance_rows.append(("Metadata fields", f"{len(metadata_keys)} field(s)", "Provenance | Metadata", "Recorded"))

    identity_inner = _render_summary_inner_table(
        ["Name", "Verified ID", "Type", "Status"],
        identity_rows,
    )
    authority_inner = _render_summary_inner_table(
        ["Field", "Value", "Type", "Status"],
        authority_rows,
    )
    scope_inner = _render_summary_inner_table(
        ["Resource", "Scope", "Type", "Status"],
        scope_rows,
    )
    provenance_inner = _render_summary_inner_table(
        ["Record", "Reference", "Type", "Status"],
        provenance_rows,
    )

    authority_overview = "Delegated agent authority is configured."
    if delegated_authority:
        authority_overview = f"Mode: {str(delegated_authority.get('delegation_mode') or 'unknown').strip()}"

    summary_sections_html = _render_ledger_summary_accordion([
        (
            "Identity & Addressing",
            "Stable identifiers, display names, and actor classification for this principal.",
            principal["status"],
            identity_inner,
        ),
        (
            "Authority & Delegation",
            authority_overview,
            "Governed" if authority_rows else "Empty",
            authority_inner + delegated_action_form,
        ),
        (
            "Scope & Revocation",
            f"{len(ledger_scope)} ledger(s), {len(surface_scope)} surface(s)",
            "Active" if scope_rows else "Empty",
            scope_inner,
        ),
        (
            "Provenance & Governance",
            "Tenant attribution and metadata context.",
            "Recorded" if provenance_rows else "Empty",
            provenance_inner,
        ),
    ])

    relationship_table_html = _render_relationship_table(
        all_rows,
        connection_context=connection_context,
        owner_entity_type="principal",
        owner_entity_id=principal["principal_id"],
        principal_focus=principal["principal_id"],
        current_principal_did=current_principal_did,
    )

    cards_html = f"""
    <div class="principal-detail-views">
        <div class="principal-relationship-view" data-principal-relationship-view>
            {relationship_table_html}
        </div>
        <div class="principal-summary-view" id="{html.escape(summary_panel_id)}" data-principal-summary-view>
            {summary_sections_html}
        </div>
    </div>
    <style>
        .principal-detail-views {{ display: grid; gap: 24px; }}
        .principal-relationship-view {{ display: grid; }}
        .principal-relationship-view.hidden {{ display: none; }}
        .principal-summary-view {{ display: none; }}
        .principal-summary-view.open {{ display: grid; gap: 24px; }}
    </style>
    <script>
        (function() {{
            const relationshipView = document.querySelector('[data-principal-relationship-view]');
            const summaryView = document.querySelector('[data-principal-summary-view]');

            function syncViews() {{
                if (summaryView && summaryView.classList.contains('open')) {{
                    if (relationshipView) relationshipView.classList.add('hidden');
                }} else {{
                    if (relationshipView) relationshipView.classList.remove('hidden');
                }}
            }}

            if (summaryView) {{
                const observer = new MutationObserver(function() {{ syncViews(); }});
                observer.observe(summaryView, {{ attributes: true, attributeFilter: ['class'] }});
            }}

            syncViews();
        }})();
    </script>
    """
    body_html = render_connections_page_content(
        breadcrumbs_html=render_breadcrumbs([
            ("Home", "/"),
            ("Manage Connections", "/connections"),
            ("Principals", "/connections?type=principals"),
            (principal["name"], None),
        ]),
        header_html=header_html,
        toolbar_html=render_page_toolbar(
            search_placeholder="Filter connections by keyword",
            search_action=f"/principals/{quote(principal['principal_id'], safe='')}",
            primary_cta_html=action_menu_html,
        ),
        tabs_html=render_relationship_filter_tabs("all", counts=filter_counts, summary_panel_id=summary_panel_id, summary_active=False),
        list_html=f"""
        {banner_html}
        {cards_html}
        {modal_html}
        """,
    )
    return _layout_with_nav(
        f"{html.escape(principal['name'])} | {APP_TITLE}",
        body_html,
        f"/principals/{principal['principal_id']}",
        profile_name=profile_name,
    )


