async def ledger_detail_page(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    profile_name = _profile_name_from_identity_card(identity_card)
    current_principal_did = str(_as_dict(identity_card).get("principal_did") or "").strip()
    ledger_id = str(request.path_params.get("ledger_id") or "").strip()
    context = await _load_connection_lookup_context(request, identity_card=identity_card)
    detail = _lookup_ledger_detail_data(ledger_id, context)
    banner, banner_kind = _mutation_banner_payload(request)
    if detail is None:
        body_html = f"""
        <div class="page-header"><h1>Ledger Not Found</h1><p>No ledger with id '{html.escape(ledger_id)}' was located.</p></div>
        """
        return HTMLResponse(_layout_with_nav(f"Ledger Not Found | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)
    # If the caller is linked to this ledger but their principal metadata still
    # points elsewhere (e.g. the legacy LOAM ledger), backfill the correct ledger
    # id so chat and the identity card use the right scope.
    # Operators/admin viewers should keep their own ledger scope and not inherit
    # the ledger of a user whose detail page they are inspecting.
    if current_principal_did and detail.get("principal_links") and not _is_operator_identity_card(identity_card):
        linked_principal_ids = {str(link[1]).strip() for link in detail["principal_links"]}
        if current_principal_did in linked_principal_ids:
            self_principal = context.get("principal_map", {}).get(current_principal_did)
            if isinstance(self_principal, dict):
                current_metadata = _as_dict(self_principal.get("metadata"))
                current_ledger = str(
                    current_metadata.get("provisioned_ledger_id")
                    or current_metadata.get("ledger_id")
                    or ""
                ).strip()
                if current_ledger != ledger_id:
                    updated_metadata = dict(current_metadata)
                    updated_metadata["ledger_id"] = ledger_id
                    updated_metadata["provisioned_ledger_id"] = ledger_id
                    await _control_plane_post(
                        "/api/control-plane/principals",
                        {
                            "principal_did": current_principal_did,
                            "display_name": str(self_principal.get("display_name") or profile_name or current_principal_did).strip() or current_principal_did,
                            "status": "active",
                            "tenant_id": str(self_principal.get("tenant_id") or _tenant_id_from_identity_card(identity_card) or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
                            "principal_type": str(updated_metadata.get("actor_type") or "human").strip().lower() or "human",
                            "provisioning_source": "control_plane_ledger_detail_backfill",
                            "metadata": updated_metadata,
                        },
                        request,
                    )
    backend_attachments = await _fetch_ledger_attachments(
        ledger_id, auth_headers=_auth_headers_from_request(request)
    )
    return HTMLResponse(
        render_ledger_detail_page(
            detail,
            connection_context=context,
            profile_name=profile_name,
            current_principal_did=current_principal_did,
            banner=banner,
            banner_kind=banner_kind,
            backend_attachments=backend_attachments,
        )
    )


async def principal_detail_page(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    profile_name = _profile_name_from_identity_card(identity_card)
    current_principal_did = str(_as_dict(identity_card).get("principal_did") or "").strip()
    principal_id = str(request.path_params.get("principal_id") or "").strip()
    context = await _load_connection_lookup_context(request, identity_card=identity_card)
    detail = _lookup_principal_detail_data(principal_id, context)
    banner, banner_kind = _mutation_banner_payload(request)
    if detail is None:
        body_html = f"""
        <div class="page-header"><h1>Principal Not Found</h1><p>No principal with did '{html.escape(principal_id)}' was located.</p></div>
        """
        return HTMLResponse(_layout_with_nav(f"Principal Not Found | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)
    return HTMLResponse(
        render_principal_detail_page(
            detail,
            connection_context=context,
            profile_name=profile_name,
            current_principal_did=current_principal_did,
            banner=banner,
            banner_kind=banner_kind,
        )
    )


async def principal_delegated_access_update(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    principal_id = str(request.path_params.get("principal_id") or "").strip()
    form = await request.form()
    action = str(form.get("action") or "").strip().lower()
    reason = str(form.get("reason") or "").strip()
    if not principal_id or action not in {"revoke", "restore"}:
        return RedirectResponse(url=f"/principals/{quote(principal_id, safe='')}", status_code=303)

    target_status = "disabled" if action == "revoke" else "active"
    status_code, body = await _backend_admin_post(
        f"/principals/{quote(principal_id, safe='')}/status",
        {"status": target_status, "reason": reason or None},
        extra_headers=_backend_admin_auth_headers_from_request(request),
    )
    if status_code >= 400:
        detail = body.get("detail") or body.get("error") or body
        banner = f"Unable to update delegated access ({status_code}): {detail}"
        return RedirectResponse(
            url=f"/principals/{quote(principal_id, safe='')}?{urlencode({'banner': banner, 'banner_kind': 'warn'})}",
            status_code=303,
        )

    banner = (
        "Delegated access restored. Codex can resume explicit CLI-requested prompting within the governed scope."
        if action == "restore"
        else "Delegated access revoked. Codex can no longer prompt DSS until restored."
    )
    return RedirectResponse(
        url=f"/principals/{quote(principal_id, safe='')}?{urlencode({'banner': banner, 'banner_kind': 'ok'})}",
        status_code=303,
    )


async def codex_principal_provision_submit(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    form = await request.form()
    if str(form.get("confirm_delegated_only") or "").strip().lower() != "yes":
        return RedirectResponse(
            url="/principals?banner=Confirm+delegated-only+posture+before+provisioning+Codex.&banner_kind=warn",
            status_code=303,
        )
    snapshot = await build_dashboard_snapshot(request)
    defaults = _codex_provision_defaults(identity_card, snapshot)
    active_ledger_id = str(form.get("ledger_id") or defaults.get("active_ledger_id") or "").strip()
    if not active_ledger_id:
        return RedirectResponse(
            url="/principals?banner=Unable+to+provision+Codex+without+an+active+ledger+scope.&banner_kind=warn",
            status_code=303,
        )
    active_surface_id = str(form.get("surface_id") or defaults.get("active_surface_id") or "").strip()
    if not active_surface_id:
        return RedirectResponse(
            url="/principals?banner=Unable+to+provision+Codex+without+an+active+chat+surface+scope.&banner_kind=warn",
            status_code=303,
        )
    payload: dict[str, Any] = {
        "tenant_id": defaults.get("tenant_id") or FRONTEND_TENANT_ID,
        "delegated_by_principal_did": defaults.get("delegated_by_principal_did") or None,
        "ledger_id": active_ledger_id,
        "surface_ids": [active_surface_id],
    }
    status_code, body = await _control_plane_post("/api/control-plane/principals/codex/provision", payload)
    codex_did = _codex_principal_did()
    if status_code >= 400:
        detail = str(_as_dict(body).get("detail") or _as_dict(body).get("error") or "Unable to provision Codex principal.").strip()
        return RedirectResponse(
            url=f"/principals?{urlencode({'banner': f'Unable to provision Codex principal: {detail}', 'banner_kind': 'warn'})}",
            status_code=303,
        )
    principal = _as_dict(_as_dict(body).get("principal"))
    principal_id = str(principal.get("principal_did") or codex_did).strip() or codex_did
    return RedirectResponse(
        url=f"/principals/{quote(principal_id, safe='')}?{urlencode({'banner': 'Codex principal provisioned.', 'banner_kind': 'ok'})}",
        status_code=303,
    )


