async def entity_trust_panel_page(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    profile_name = _profile_name_from_identity_card(identity_card)
    entity_type = str(request.path_params.get("entity_type") or "").strip().lower()
    entity_id = str(request.path_params.get("entity_id") or "").strip()
    context = await _load_connection_lookup_context(request, identity_card=identity_card)
    if entity_type == "ledger":
        detail = _lookup_ledger_detail_data(entity_id, context)
        if detail is None:
            body_html = render_not_found_content("The requested ledger trust panel could not be found.")
            return HTMLResponse(_layout_with_nav(f"Trust Panel | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)
        related_rows = list(detail.get("related_rows") or [])
        return HTMLResponse(
            render_entity_trust_panel_page(
                entity_type="ledger",
                entity_id=detail["ledger_id"],
                title=detail["name"],
                status=detail["status"],
                trust_identifier=_entity_trust_identifier("ledger", detail["ledger_id"], context["ledger_map"].get(detail["ledger_id"])),
                summary_rows=[
                    ("Ledger", detail["name"]),
                    *([("Operational ID", detail["display_subtitle"])] if str(detail.get("display_subtitle") or "").strip() else []),
                    ("Status", detail["status"]),
                    ("Connected principals", str(len(detail["principal_links"]))),
                    ("Connected surfaces", str(len(detail["surface_links"]))),
                ],
                trust_rows=[
                    ("Entity type", _ledger_type_label()),
                    ("Operational identifier", detail["ledger_id"]),
                    ("Trust reference", _entity_trust_identifier("ledger", detail["ledger_id"], context["ledger_map"].get(detail["ledger_id"]))),
                    ("Governance host", PUBLIC_BASE_URL),
                ],
                related_rows=related_rows,
                connection_context=context,
                profile_name=profile_name,
                back_href=f"/ledgers/{quote(detail['ledger_id'], safe='')}",
            )
        )
    if entity_type == "principal":
        detail = _lookup_principal_detail_data(entity_id, context)
        if detail is None:
            body_html = render_not_found_content("The requested principal trust panel could not be found.")
            return HTMLResponse(_layout_with_nav(f"Trust Panel | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)
        principal_record = _as_dict(context["principal_map"].get(detail["principal_id"]))
        metadata = _as_dict(principal_record.get("metadata"))
        standing = _as_dict(principal_record.get("standing_view"))
        related_rows = list(detail.get("related_rows") or [])
        trust_identifier = _entity_trust_identifier("principal", detail["principal_id"], principal_record)
        return HTMLResponse(
            render_entity_trust_panel_page(
                entity_type="principal",
                entity_id=detail["principal_id"],
                title=detail["name"],
                status=detail["status"],
                trust_identifier=trust_identifier,
                summary_rows=[
                    ("Principal", detail["name"]),
                    ("Status", detail["status"]),
                    ("Connected ledgers", str(len(detail["ledger_links"]))),
                    ("Connected surfaces", str(len(detail["surface_links"]))),
                ],
                trust_rows=[
                    ("Entity type", _principal_type_label(principal_record)),
                    ("Operational identifier", detail["principal_id"]),
                    ("Trust reference", trust_identifier),
                    ("Canonical subject", str(principal_record.get("canonical_subject") or trust_identifier)),
                    ("Trust class", str(standing.get("trust_class") or "unknown")),
                    ("Posture class", str(standing.get("posture_class") or "unknown")),
                    ("Provider type", str(metadata.get("provider_type") or "n/a")),
                    ("Model id", str(metadata.get("model_id") or "n/a")),
                ],
                related_rows=related_rows,
                connection_context=context,
                profile_name=profile_name,
                back_href=f"/principals/{quote(detail['principal_id'], safe='')}",
            )
        )
    if entity_type == "surface":
        detail = _lookup_surface_detail_data(entity_id, context)
        if detail is None:
            body_html = render_not_found_content("The requested surface trust panel could not be found.")
            return HTMLResponse(_layout_with_nav(f"Trust Panel | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)
        related_rows = list(detail.get("related_rows") or [])
        return HTMLResponse(
            render_entity_trust_panel_page(
                entity_type="surface",
                entity_id=detail["surface_id"],
                title=detail["name"],
                status=detail["status"],
                trust_identifier=_entity_trust_identifier("surface", detail["surface_id"], context["surface_map"].get(detail["surface_id"])),
                summary_rows=[
                    ("Surface", detail["name"]),
                    ("Status", detail["status"]),
                    ("Related ledgers", str(len(detail["ledger_links"]))),
                    ("Related principals", str(len(detail["principal_links"]))),
                ],
                trust_rows=[
                    ("Entity type", _surface_type_label(context["surface_map"].get(detail["surface_id"]) or {"surface_type": detail["surface_type"]})),
                    ("Operational identifier", detail["surface_id"]),
                    ("Trust reference", _entity_trust_identifier("surface", detail["surface_id"], context["surface_map"].get(detail["surface_id"]))),
                    ("Endpoint", detail["endpoint"] or "not configured"),
                    ("Provider type", detail["provider_type"] or "unknown"),
                    ("Default model", detail["model_id"] or "unknown"),
                ],
                related_rows=related_rows,
                connection_context=context,
                profile_name=profile_name,
                back_href=f"/surfaces/{quote(detail['surface_id'], safe='')}",
            )
        )
    body_html = render_not_found_content("The requested trust panel could not be found.")
    return HTMLResponse(_layout_with_nav(f"Trust Panel | {APP_TITLE}", body_html, "/connections", profile_name=profile_name), status_code=404)


async def entity_descriptor_document(request: Request) -> JSONResponse:
    entity_type = str(request.path_params.get("entity_type") or "").strip().lower()
    entity_id = str(request.path_params.get("entity_id") or "").strip()
    if entity_type not in {"ledger", "principal", "surface", "provider", "binding"} or not entity_id:
        return JSONResponse({"error": "entity_not_found"}, status_code=404)
    descriptor = {
        "id": _canonical_entity_subject(entity_type, entity_id),
        "type": f"Dss{entity_type.title()}Entity",
        "entity_type": entity_type,
        "entity_id": entity_id,
        "trust_panel": f"{PUBLIC_BASE_URL}/trust-panel/{quote(entity_type, safe='')}/{quote(entity_id, safe='')}",
        "issuer_did": ISSUER_DID,
        "published_at": datetime.now(timezone.utc).isoformat(),
        "identifier_strategy": "untp-compatible-uri",
    }
    return JSONResponse(descriptor, status_code=200)


