def _collection_toolbar(
    *,
    search_placeholder: str = "Search...",
    cta_label: str = "Add New",
    cta_href: str = "#",
    view: str = "card",
    view_card_href: str = "?view=card",
    view_list_href: str = "?view=list",
    extra_controls: str = "",
) -> str:
    """Legacy toolbar helper kept for non-connections pages."""
    card_cls = " active" if view == "card" else ""
    list_cls = " active" if view == "list" else ""
    return f"""
    <div class="collection-toolbar">
      <div class="toolbar-search">
        <span class="toolbar-search-icon">&#9906;</span>
        <input type="text" placeholder="{html.escape(search_placeholder)}"
               oninput="filterCollection(this.value)" aria-label="Search">
      </div>
      {extra_controls}
      <div class="toolbar-right">
        <span class="toolbar-divider"></span>
        <div class="toolbar-view-toggle">
          <a href="{html.escape(view_card_href)}" class="toolbar-view-btn{card_cls}" title="Card view">&#8862;</a>
          <a href="{html.escape(view_list_href)}" class="toolbar-view-btn{list_cls}" title="List view">&#8801;</a>
        </div>
        <a class="toolbar-btn primary" href="{html.escape(cta_href)}">{html.escape(cta_label)}</a>
      </div>
    </div>
    <script>
    function filterCollection(q) {{
      document.querySelectorAll("[data-filter-name]").forEach(function(el) {{
        el.style.display = el.dataset.filterName.toLowerCase().includes(q.toLowerCase()) ? "" : "none";
      }});
    }}
    </script>
    """


def render_entity_cards(conn_items: list[dict[str, Any]]) -> str:
    def _status_class(value: str) -> str:
        normalized = str(value or "").strip().lower()
        if normalized in {"active", "enabled", "ready", "connected"}:
            return ""
        if normalized in {"error", "failed", "blocked", "revoked"}:
            return "error"
        return "pending"

    cards: list[str] = []
    for item in conn_items:
        status_class = _status_class(str(item.get("status") or ""))
        icon_text = str(item.get("name") or "")[:2].upper()
        detail_path = f"/connections/{quote(str(item.get('type') or ''), safe='')}/{quote(str(item.get('id') or ''), safe='')}"
        subtitle = str(item.get("subtitle") or "").strip()
        cards.append(
            f"""
            <a class="collection-card" href="{detail_path}" data-filter-name="{html.escape(str(item.get('name') or '')).lower()}">
              <div class="collection-card-top">
                <div>
                  <div class="collection-card-name">{html.escape(str(item.get('name') or ''))}</div>
                  {f'<div class="collection-card-sub">Operational ID: {html.escape(subtitle)}</div>' if subtitle else ''}
                  <div class="collection-card-sub">{html.escape(str(item.get('did') or ''))}</div>
                </div>
                <div class="collection-card-icon">{html.escape(icon_text)}</div>
              </div>
              <div class="collection-card-meta">
                <span class="status-dot {status_class}"></span>
                {html.escape(str(item.get('status') or 'Unknown'))}
              </div>
            </a>
            """
        )
    return '<div class="collection-grid">' + "".join(cards) + "</div>"


def _layout_with_nav(title: str, body: str, current_path: str, *, profile_name: str = "Profile") -> str:
    """Standard page with top shell and padded page body."""
    inner = f'<div class="page-body">{body}</div>'
    return _layout(title, inner, shell=True, current_path=current_path, profile_name=profile_name)


def _layout_with_nav_and_toolbar(
    title: str,
    body: str,
    current_path: str,
    *,
    profile_name: str = "Profile",
    toolbar: str = "",
    subnav: str = "",
) -> str:
    """Page with top shell + optional subnav + optional toolbar + padded body."""
    inner = subnav + toolbar + f'<div class="page-body">{body}</div>'
    return _layout(title, inner, shell=True, current_path=current_path, profile_name=profile_name, approval_count=len(_pending_profile_requests))


def _render_placeholder_section(
    *,
    title: str,
    intro: str,
    current_path: str,
    status_lines: list[str],
    next_lines: list[str],
) -> str:
    status_html = "".join(f"<li>{html.escape(line)}</li>" for line in status_lines)
    next_html = "".join(f"<li>{html.escape(line)}</li>" for line in next_lines)
    return _layout_with_nav_and_toolbar(
        f"{title} | {APP_TITLE}",
        f"""
        <div class="page-header">
            <h1>{html.escape(title)}</h1>
            <p>{html.escape(intro)}</p>
        </div>
        <div class="grid">
          <div class="card">
            <h2>Current State</h2>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              {status_html}
            </ul>
          </div>
          <div class="card">
            <h2>Next To Complete</h2>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              {next_html}
            </ul>
          </div>
        </div>
        """,
        current_path,
    )


def _current_relative_url(request: Request) -> str:
    path = str(request.url.path or "/").strip() or "/"
    query = str(request.url.query or "").strip()
    return f"{path}?{query}" if query else path


async def _require_control_plane_auth(request: Request) -> tuple[dict[str, Any] | None, RedirectResponse | None]:
    identity_card = await _build_identity_card(request)
    identity_vc = _as_dict(identity_card.get("identity_vc"))
    if bool(identity_vc.get("verified")):
        return identity_card, None
    next_path = _safe_next_path(_current_relative_url(request))
    return None, RedirectResponse(url=f"/login?next={quote(next_path, safe='/?=&')}", status_code=303)


def _label_with_plain(term: str, plain: str) -> str:
    return f"{term} ({plain})"


def _simple_mode_enabled(request: Request) -> bool:
    value = str(request.query_params.get("simple") or "").strip().lower()
    return value in {"1", "true", "yes", "on"}


def _profile_name_from_identity_card(identity_card: dict[str, Any] | None) -> str:
    card = _as_dict(identity_card)
    identity_vc = _as_dict(card.get("identity_vc"))
    principal_record = _as_dict(card.get("principal"))
    display_name = str(
        identity_vc.get("principal_display_name")
        or principal_record.get("display_name")
        or identity_vc.get("display_name")
        or identity_vc.get("operator_profile")
        or identity_vc.get("canonical_subject")
        or card.get("principal_display_name")
        or card.get("display_name")
        or card.get("canonical_subject")
        or ""
    ).strip()
    if display_name:
        return display_name
    principal_did = str(identity_vc.get("principal_did") or "").strip()
    if principal_did:
        return principal_did
    return "Profile"


def _with_simple(path: str, enabled: bool) -> str:
    separator = "&" if "?" in path else "?"
    return f"{path}{separator}simple=1" if enabled else path


def _activation_banner(identity_vc: dict[str, Any], identity_ui: dict[str, Any], linked_env_count: int) -> tuple[str, str, str]:
    activation_state = str(identity_vc.get("activation_state") or "").strip().lower()
    verified = bool(identity_vc.get("verified"))
    ledger_ready = bool(identity_vc.get("ledger_access_ready"))
    provisioning_copy = str(identity_ui.get("provisioning_copy") or "").strip()
    if ledger_ready or activation_state == "active":
        headline = "Ready to use apps"
        copy = f"Your identity is active and linked environments are available now. {linked_env_count} linked environment{'s are' if linked_env_count != 1 else ' is'} currently visible."
        return headline, copy, "ok"
    if activation_state == "pending_provisioning":
        headline = "Activation in progress"
        copy = provisioning_copy or "Your identity is verified, and app access is being activated now. This usually clears shortly after verification."
        return headline, copy, "warn"
    if activation_state == "pending_wallet_proof":
        headline = "Finish identity activation"
        copy = provisioning_copy or "Your identity is approved, but app access stays locked until Microsoft Verified ID proof completes."
        return headline, copy, "warn"
    if activation_state == "pending_onboarding":
        headline = "Finish onboarding"
        copy = provisioning_copy or "Your identity is approved, but app access stays locked until you complete onboarding (wallet proof and ledger selection)."
        return headline, copy, "warn"
    if verified:
        headline = "Complete setup to unlock apps"
        copy = provisioning_copy or "Your session is active, but app access still depends on identity setup and provisioning."
        return headline, copy, "warn"
    headline = "Sign in to continue"
    copy = "Authenticate here first, then DSS will guide you through identity verification and app access."
    return headline, copy, "warn"


def _wallet_status_copy(status: str) -> str:
    normalized = status.strip().lower()
    if normalized in {"", "not_started", "request_created", "created"}:
        return "Waiting for scan..."
    if normalized in {"request_retrieved", "scan_detected", "request_viewed"}:
        return "Scan detected..."
    if normalized in {"presentation_verified", "verified", "complete", "ok"}:
        return "Signing you in..."
    if normalized in {"expired", "failed", "error", "poll_error"}:
        return "That sign-in attempt did not complete. Start a fresh attempt or use passkey instead."
    return f"Current sign-in state: {status or 'unknown'}."


