def render_trust_page(snapshot: dict[str, Any], request: Request) -> str:
    trust_status = _as_dict(snapshot.get("trust_anchor"))
    trust_bundle = _as_dict(snapshot.get("trust_bundle"))
    identity_card = _as_dict(snapshot.get("identity_card"))
    identity_vc = _as_dict(identity_card.get("identity_vc"))
    trust_anchor_meta = _as_dict(trust_status.get("trust_anchor"))
    checks = _as_dict(trust_status.get("checks"))
    warnings = _as_list(trust_status.get("warnings"))
    public_authority = _as_dict(trust_bundle.get("public_issuer_authority"))
    public_authority_status = _as_dict(trust_bundle.get("public_issuer_authority_status"))
    public_verifier_policy = _as_dict(trust_bundle.get("public_verifier_policy"))
    verifier_instructions = _as_dict(trust_bundle.get("verifier_instructions"))
    publication_intent = _as_dict(trust_bundle.get("publication_intent"))
    warnings_html = "".join(f"<li>{html.escape(str(item))}</li>" for item in warnings if str(item).strip()) or "<li>No trust warnings are currently reported.</li>"
    verifier_notes = _as_list(verifier_instructions.get("notes"))
    verifier_notes_html = "".join(f"<li>{html.escape(str(item))}</li>" for item in verifier_notes if str(item).strip()) or "<li>No verifier notes published.</li>"
    published_now = _as_list(publication_intent.get("published_now"))
    published_html = "".join(f"<li>{html.escape(str(item))}</li>" for item in published_now if str(item).strip()) or "<li>No published surfaces declared.</li>"
    profile_name = _profile_name_from_identity_card(identity_card)
    actor_type = str(identity_vc.get("actor_type") or "").strip().lower()
    principal_did_label = "Human DID" if actor_type == "human" else "Principal DID"
    return _layout_with_nav_and_toolbar(
        f"Trust & Identity | {APP_TITLE}",
        f"""
        <div class="page-header">
            <h1>Trust &amp; Identity</h1>
            <p>This is the verifier-facing trust workspace for DSS. Use it to confirm who is publishing, what is currently verifiable, and whether this control plane is safe to rely on.</p>
        </div>
        <div class="banner ok" style="margin:0 0 20px;">
          <strong>Trust is a product surface here</strong>
          <div style="margin-top:6px;">DSS publishes its DID, issuer authority, authority status, and verifier policy directly on this host so operators and third parties can verify the system without hidden steps.</div>
        </div>
        <div class="grid">
          <div class="card">
            <h2>Trust Publication</h2>
            <p><strong>Issuer DID:</strong> {html.escape(str(trust_anchor_meta.get('issuer_did') or ISSUER_DID))}</p>
            <p><strong>Public base URL:</strong> {html.escape(str(trust_anchor_meta.get('public_base_url') or PUBLIC_BASE_URL))}</p>
            <p><strong>Status:</strong> {html.escape(str(trust_status.get('status') or 'unknown'))}</p>
            <p><strong>Publication state:</strong> {html.escape(str(publication_intent.get('current_publication_state') or 'unknown'))}</p>
          </div>
          <div class="card">
            <h2>Identity State</h2>
            <p><strong>Verified:</strong> {html.escape(str(bool(identity_vc.get('verified'))).lower())}</p>
            <p><strong>{_label_with_plain(principal_did_label, 'Identity')}</strong>: {html.escape(str(identity_vc.get('principal_did') or 'unverified'))}</p>
            <p><strong>Wallet DID:</strong> {html.escape(str(identity_vc.get('wallet_did') or 'none'))}</p>
            <p><strong>{_label_with_plain('Activation state', 'Access readiness')}</strong>: {html.escape(str(identity_vc.get('activation_state') or 'unknown'))}</p>
          </div>
          <div class="card">
            <h2>Quick Actions</h2>
            <a class="btn primary" href="/verified-id">Open Verified ID</a>
            <a class="btn" href="/login/passkey">Open Passkey</a>
            <a class="btn" href="/profile/setup">Profile Setup</a>
            <a class="btn" href="/.well-known/trust-anchor.json">Trust Bundle</a>
          </div>
        </div>
        <div class="grid">
          <div class="card">
            <h2>Trust Checks</h2>
            <p><strong>Public DID resolves:</strong> {html.escape(str(bool(checks.get('public_did_resolves'))).lower())}</p>
            <p><strong>DID id matches:</strong> {html.escape(str(bool(checks.get('public_did_id_match'))).lower())}</p>
            <p><strong>Issuer binding anchored:</strong> {html.escape(str(bool(checks.get('issuer_binding_anchored'))).lower())}</p>
            <p><strong>Issuer VC verified:</strong> {html.escape(str(bool(checks.get('issuer_vc_verified'))).lower())}</p>
            <p><strong>Live identity verified:</strong> {html.escape(str(bool(checks.get('live_resolution_verified'))).lower())}</p>
          </div>
          <div class="card">
            <h2>Warnings</h2>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              {warnings_html}
            </ul>
          </div>
          <div class="card">
            <h2>Verifier Notes</h2>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              {verifier_notes_html}
            </ul>
          </div>
        </div>
        <div class="grid">
          <div class="card">
            <h2>Authority Objects</h2>
            <p><strong>Authority statement:</strong> {html.escape(str(public_authority.get('type') or 'unknown'))}</p>
            <p><strong>Authority status:</strong> {html.escape(str(public_authority_status.get('type') or 'unknown'))}</p>
            <p><strong>Verifier policy:</strong> {html.escape(str(public_verifier_policy.get('type') or 'unknown'))}</p>
            <div class="trust-links">
              <a class="btn" href="/.well-known/issuer-authority.json">Authority</a>
              <a class="btn" href="/.well-known/issuer-authority-status.json">Authority Status</a>
              <a class="btn" href="/.well-known/verifier-policy.json">Verifier Policy</a>
            </div>
          </div>
          <div class="card">
            <h2>Published Now</h2>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              {published_html}
            </ul>
          </div>
          <div class="card">
            <h2>Diagnostics</h2>
            <a class="btn" href="/api/trust-anchor/status">Trust Anchor Status</a>
            <a class="btn" href="/.well-known/did.json">DID Document</a>
            <a class="btn" href="/.well-known/trust-anchor.json">Trust Bundle</a>
          </div>
        </div>
        """,
        "/trust",
        profile_name=profile_name,
    )

def render_login(request: Request) -> str:
    next_path = _safe_next_path(str(request.query_params.get("next") or "/"))
    simple_mode = _simple_mode_enabled(request)
    wallet_login_href = _with_simple(f"/login/wallet?next={quote(next_path, safe='/?=&')}", simple_mode)
    profile_setup_href = _with_simple("/profile/setup", simple_mode)
    wizard_href = "/wizard"
    login_toggle_href = "/login?simple=1" if not simple_mode else "/login"
    simple_banner = """
        <div class="banner ok" style="margin:0 0 16px;">
          <strong>Simple mode</strong>
          <div style="margin-top:6px;">Step 1: sign in. Step 2: verify identity only if DSS asks for it. Step 3: enter your app.</div>
        </div>
    """ if simple_mode else ""
    return _layout(
        "Login | DSS Control Plane",
        f"""
        <div class="page-header">
            <h1>Sign In</h1>
            <p>Sign in to DSS Control Plane with your Verified Identity.</p>
        </div>
        <div class="card" style="max-width:520px; margin:0 auto;">
          <h2>Sign-in with your Verified Identity</h2>
          <p class="muted">Use Microsoft Authenticator to complete the current DSS sign-in flow.</p>
          {simple_banner}
          <div class="banner warn" style="margin:0 0 16px;">
            <strong>Next step</strong>
            <div style="margin-top:6px;">Scan with Microsoft Authenticator, or request a DSS identity first if you do not have one yet.</div>
          </div>
          <a class="btn primary" href="{wallet_login_href}">Use Microsoft Authenticator</a>
          <a class="btn" href="{wizard_href}">Request Access (Wizard)</a>
          <a class="btn" href="{profile_setup_href}">Request Access (Classic)</a>
          <a class="btn" href="{login_toggle_href}">{'Simple Mode' if not simple_mode else 'Full View'}</a>
        </div>
        """,
    )


def render_wallet_login_page(request: Request, *, banner: str = "", banner_kind: str = "ok", request_record: dict[str, Any] | None = None) -> str:
    banner_html = f'<div class="banner {banner_kind}">{html.escape(banner)}</div>' if banner else ''
    next_path = _safe_next_path(str(request.query_params.get("next") or "/"))
    simple_mode = _simple_mode_enabled(request)
    wizard_href = "/wizard"
    simple_intro_html = """
      <div class="banner ok" style="margin:16px 0;">
        <strong>Simple mode</strong>
        <div style="margin-top:6px;">Scan the QR with your wallet. If you do not have a DSS identity yet, request one below.</div>
      </div>
    """ if simple_mode else ""
    record = _as_dict(request_record)
    state = str(record.get("state") or "").strip()
    return _layout(
        "Wallet Login | DSS Control Plane",
        f"""
        <div class="entry-shell">
          <div class="entry-grid" style="grid-template-columns:minmax(340px,560px); justify-content:center;">
            <div class="flip-card" id="login_flip_card">
              <div class="flip-card-inner">
                <!-- Front: Entra -->
                <div class="flip-card-front">
                  <h1 style="margin:10px 0 12px; font-size:2.1rem; line-height:1.1;">Sign-in with Entra</h1>
                  <p class="muted">Scan QR with Microsoft Authenticator (or continue on mobile).</p>
                  {simple_intro_html}
                  {banner_html}
                  <div class="qr-panel wallet-login-qr" id="wallet_login_qr_panel">
                    <p class="muted" id="wallet_login_placeholder">Preparing your sign-in request…</p>
                  </div>
                  <a class="btn primary full mobile-only" id="wallet_login_continue_cta" href="#" hidden style="text-align:center;">Continue</a>
                  <p class="mini-note" id="wallet_login_status_copy" style="margin-top:12px;"></p>
                  <div class="flip-toggle">
                    <button type="button" class="btn" id="flip_to_openid" aria-label="Switch to OpenID sign-in">Use OpenID instead</button>
                  </div>
                </div>
                <!-- Back: OpenID -->
                <div class="flip-card-back">
                  <h1 style="margin:10px 0 12px; font-size:2.1rem; line-height:1.1;">Sign-in with OpenID</h1>
                  <p class="muted">Scan QR with Altme or any OpenID4VP wallet (or continue on mobile).</p>
                  <div class="qr-panel wallet-login-qr" id="openid_vp_qr_panel">
                    <p class="muted" id="openid_vp_placeholder">Preparing OpenID sign-in…</p>
                  </div>
                  <a class="btn primary full mobile-only" id="openid_vp_continue_cta" href="#" hidden style="text-align:center;">Continue</a>
                  <p class="mini-note" id="openid_vp_status_copy" style="margin-top:12px;"></p>
                  <div class="flip-toggle">
                    <button type="button" class="btn" id="flip_to_entra" aria-label="Switch to Entra sign-in">Use Entra instead</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
          <div style="text-align:center; margin-top:18px;">
            <p class="muted" style="margin-bottom:10px;">Don't have a DSS identity or account?</p>
            <a class="btn" href="{wizard_href}">Request DSS Identity</a>
          </div>
        </div>
        <script>
        // ── Flip card ──
        const flipCard = document.getElementById('login_flip_card');
        document.getElementById('flip_to_openid').addEventListener('click', () => {{
          flipCard.classList.add('flipped');
          stopWalletPolling();
          startOpenIdVp();
        }});
        document.getElementById('flip_to_entra').addEventListener('click', () => {{
          flipCard.classList.remove('flipped');
          stopOpenIdVpPolling();
          if (!walletLoginState) startWalletLogin();
          else startWalletPolling();
        }});

        // ── Entra / MS Authenticator side ──
        let walletLoginState = {json.dumps(state)};
        const initialWalletStatus = {json.dumps(str(record.get("status") or ""))};
        const walletLoginNext = {json.dumps(next_path)};
        const qrPanel = document.getElementById('wallet_login_qr_panel');
        const continueCta = document.getElementById('wallet_login_continue_cta');
        const statusEl = document.getElementById('wallet_login_status_copy');
        const mobileViewport = window.matchMedia('(max-width: 860px)');
        let walletLoginPoll = null;
        const spinnerHtml = '<div class="ds-spinner"><svg viewBox="0 0 44 44"><circle cx="22" cy="22" r="20"></circle></svg></div>';
        const setLoadingOverlay = (active) => {{
          if (!qrPanel) return;
          if (active) {{ qrPanel.innerHTML = spinnerHtml; }}
        }};
        const updateWalletStatus = (message, overlayActive = false) => {{
          statusEl.textContent = message;
          setLoadingOverlay(overlayActive);
        }};
        const stopWalletPolling = () => {{
          if (walletLoginPoll) {{ window.clearInterval(walletLoginPoll); walletLoginPoll = null; }}
        }};
        const startWalletPolling = () => {{
          stopWalletPolling();
          if (!walletLoginState) return;
          walletLoginPoll = window.setInterval(walletPoll, 4000);
        }};
        const syncContinueVisibility = (hasUrl) => {{
          continueCta.hidden = !(hasUrl && mobileViewport.matches);
        }};
        const renderWalletRequest = (record) => {{
          const qr = String(record.request_qr_code || '');
          const url = String(record.request_url || '');
          qrPanel.innerHTML = qr
            ? (url
                ? `<a href="${{url}}" aria-label="Continue with Verified Identity" style="display:block; width:100%; max-width:300px;"><img src="${{qr}}" alt="Verified identity sign-in QR" /></a>`
                : `<img src="${{qr}}" alt="Verified identity sign-in QR" />`)
            : '<p class="muted">Unable to render QR for this request.</p>';
          if (url) {{ continueCta.href = url; syncContinueVisibility(true); }}
          else {{ syncContinueVisibility(false); }}
        }};
        const handleViewportChange = () => {{
          syncContinueVisibility(Boolean(continueCta.getAttribute('href') && continueCta.getAttribute('href') !== '#'));
        }};
        if (typeof mobileViewport.addEventListener === 'function') {{
          mobileViewport.addEventListener('change', handleViewportChange);
        }} else if (typeof mobileViewport.addListener === 'function') {{
          mobileViewport.addListener(handleViewportChange);
        }}
        const startWalletLogin = async () => {{
          try {{
            updateWalletStatus('Preparing your sign-in request...', true);
            const res = await fetch('/api/login/wallet/start', {{
              method: 'POST',
              headers: {{'content-type': 'application/json', 'accept': 'application/json'}},
              body: JSON.stringify({{next: walletLoginNext}}),
            }});
            const data = await res.json();
            if (!res.ok) throw new Error(JSON.stringify(data));
            renderWalletRequest(data.request || {{}});
            walletLoginState = String((data.request || {{}}).state || '');
            if (walletLoginState) {{
              const nextUrl = new URL(window.location.href);
              nextUrl.searchParams.set('state', walletLoginState);
              history.replaceState(null, '', nextUrl.toString());
              updateWalletStatus('Waiting for scan...', false);
              startWalletPolling();
            }} else {{
              updateWalletStatus('Waiting for scan...', false);
            }}
          }} catch (err) {{
            qrPanel.innerHTML = '<p class="muted">Unable to start Verified Identity sign-in right now.</p>';
            syncContinueVisibility(false);
            updateWalletStatus('Verified Identity sign-in could not be started. Request a DSS Identity if you do not have one yet.', false);
          }}
        }};
        const walletPoll = async () => {{
          if (!walletLoginState) return;
          try {{
            const res = await fetch(`/api/verified-id/requests/${{encodeURIComponent(walletLoginState)}}`, {{headers: {{accept: 'application/json'}}}});
            const data = await res.json();
            if (!res.ok) throw new Error(JSON.stringify(data));
            const record = data.request || {{}};
            const recordStatus = String(record.status || 'unknown');
            const normalized = recordStatus.toLowerCase();
            const statusMessage = normalized === 'presentation_verified'
              ? 'Signing you in...'
              : (['request_retrieved', 'scan_detected', 'request_viewed'].includes(normalized) ? 'Scan detected...' : (normalized === 'request_created' ? 'Waiting for scan...' : `Current sign-in state: ${{recordStatus}}.`));
            const spinnerShouldShow = ['request_retrieved', 'scan_detected', 'request_viewed', 'presentation_verified'].includes(normalized);
            updateWalletStatus(statusMessage, spinnerShouldShow);
            if (!spinnerShouldShow) {{ renderWalletRequest(record); }}
            const finalization = record.finalization || data.finalization || {{}};
            if ((finalization.status || '').toLowerCase() === 'verified' || (finalization.wallet_proof_state || '').toLowerCase() === 'verified' || normalized === 'presentation_verified') {{
              stopWalletPolling();
              updateWalletStatus('Signing you in...', true);
              window.location.assign(`/login/wallet/complete?state=${{encodeURIComponent(walletLoginState)}}&next=${{encodeURIComponent(walletLoginNext)}}`);
              return;
            }}
          }} catch (err) {{
            stopWalletPolling();
            updateWalletStatus('That sign-in attempt did not complete. Start a fresh attempt or request a DSS Identity.', false);
          }}
        }};
        if (walletLoginState) {{
          renderWalletRequest({json.dumps(record)});
          updateWalletStatus({json.dumps(_wallet_status_copy(str(record.get("status") or "")))}, ['request_retrieved', 'presentation_verified'].includes(String(initialWalletStatus || '').toLowerCase()));
          startWalletPolling();
          walletPoll();
        }} else {{
          startWalletLogin();
        }}

        // ── OpenID4VP side ──
        let openidVpState = '';
        const openidVpQrPanel = document.getElementById('openid_vp_qr_panel');
        const openidVpContinueCta = document.getElementById('openid_vp_continue_cta');
        const openidVpStatusEl = document.getElementById('openid_vp_status_copy');
        let openidVpPoll = null;
        const setOpenIdVpLoading = (active) => {{
          if (!openidVpQrPanel) return;
          if (active) {{ openidVpQrPanel.innerHTML = spinnerHtml; }}
        }};
        const updateOpenIdVpStatus = (message, overlayActive = false) => {{
          openidVpStatusEl.textContent = message;
          setOpenIdVpLoading(overlayActive);
        }};
        const stopOpenIdVpPolling = () => {{
          if (openidVpPoll) {{ window.clearInterval(openidVpPoll); openidVpPoll = null; }}
        }};
        const startOpenIdVpPolling = () => {{
          stopOpenIdVpPolling();
          if (!openidVpState) return;
          openidVpPoll = window.setInterval(openIdVpPoll, 4000);
        }};
        const syncOpenIdVpContinue = (hasUrl) => {{
          openidVpContinueCta.hidden = !(hasUrl && mobileViewport.matches);
        }};
        const renderOpenIdVpRequest = (record) => {{
          const qr = String(record.qr_code || '');
          const url = String(record.request_url || '');
          openidVpQrPanel.innerHTML = qr
            ? (url
                ? `<a href="${{url}}" aria-label="Continue with OpenID" style="display:block; width:100%; max-width:300px;"><img src="${{qr}}" alt="OpenID sign-in QR" /></a>`
                : `<img src="${{qr}}" alt="OpenID sign-in QR" />`)
            : '<p class="muted">Unable to render QR for this request.</p>';
          if (url) {{ openidVpContinueCta.href = url; syncOpenIdVpContinue(true); }}
          else {{ syncOpenIdVpContinue(false); }}
        }};
        const startOpenIdVp = async () => {{
          try {{
            updateOpenIdVpStatus('Preparing OpenID sign-in...', true);
            const res = await fetch('/api/login/openidvp/start', {{
              method: 'POST',
              headers: {{'content-type': 'application/json', 'accept': 'application/json'}},
              body: JSON.stringify({{next: walletLoginNext}}),
            }});
            const data = await res.json();
            if (!res.ok) throw new Error(JSON.stringify(data));
            renderOpenIdVpRequest(data.request || {{}});
            openidVpState = String((data.request || {{}}).state || '');
            if (openidVpState) {{
              updateOpenIdVpStatus('Waiting for scan...', false);
              startOpenIdVpPolling();
            }} else {{
              updateOpenIdVpStatus('Waiting for scan...', false);
            }}
          }} catch (err) {{
            openidVpQrPanel.innerHTML = '<p class="muted">Unable to start OpenID sign-in right now.</p>';
            syncOpenIdVpContinue(false);
            updateOpenIdVpStatus('OpenID sign-in could not be started. Make sure you have a DSS Identity in your wallet.', false);
          }}
        }};
        const openIdVpPoll = async () => {{
          if (!openidVpState) return;
          try {{
            const res = await fetch(`/api/login/openidvp/status?state=${{encodeURIComponent(openidVpState)}}`, {{headers: {{accept: 'application/json'}}}});
            const data = await res.json();
            if (!res.ok) throw new Error(JSON.stringify(data));
            const recordStatus = String(data.status || 'unknown');
            const normalized = recordStatus.toLowerCase();
            if (normalized === 'presentation_received') {{
              updateOpenIdVpStatus('Verifying presentation...', true);
            }} else if (normalized === 'verified') {{
              stopOpenIdVpPolling();
              updateOpenIdVpStatus('Signing you in...', true);
              window.location.assign(`/login/openidvp/complete?state=${{encodeURIComponent(openidVpState)}}&next=${{encodeURIComponent(walletLoginNext)}}`);
              return;
            }} else if (normalized === 'expired') {{
              stopOpenIdVpPolling();
              updateOpenIdVpStatus('This sign-in request has expired. Flip back to Entra or start again.', false);
              return;
            }} else {{
              updateOpenIdVpStatus('Waiting for scan...', false);
            }}
          }} catch (err) {{
            stopOpenIdVpPolling();
            updateOpenIdVpStatus('That sign-in attempt did not complete. Try again or use Entra.', false);
          }}
        }};
        </script>
        """,
    )

def render_github_page(request: Request) -> str:
    next_path = _safe_next_path(str(request.query_params.get("next") or "/"))
    configured = bool(str(os.getenv("GITHUB_OAUTH_CLIENT_ID") or "").strip() and str(os.getenv("GITHUB_OAUTH_CLIENT_SECRET") or "").strip())
    copy = (
        "Choose a GitHub account to authorize DSS."
        if configured else
        "GitHub OAuth is not configured in this deployment yet."
    )
    cta = (
        f'<a class="btn primary" href="/login/github/start?next={quote(next_path, safe="/?=&")}">Continue with GitHub</a>'
        if configured else ''
    )
    return _layout(
        "GitHub Sign-In | DSS Control Plane",
        f"""
        <div class="card" style="max-width:560px; margin:40px auto 0;">
          <h1>GitHub Sign-In</h1>
          <p class="muted">{html.escape(copy)}</p>
          {cta}
          <a class="btn" href="/login">Back</a>
        </div>
        """,
    )


def render_passkey_page(request: Request, *, identity_card: dict[str, Any] | None = None) -> str:
    next_path = _safe_next_path(str(request.query_params.get("next") or "/"))
    source = str(request.query_params.get("source") or "passkey").strip().lower()
    principal_hint = str(request.query_params.get("principal_did") or "").strip() or str(request.cookies.get(PRINCIPAL_DID_COOKIE) or "").strip()
    has_linked_identity = bool(principal_hint)
    identity_data = _as_dict(identity_card)
    identity_vc = _as_dict(identity_data.get("identity_vc"))
    identity_ui = _as_dict(identity_data.get("ui"))
    activation_state = str(identity_vc.get("activation_state") or "").strip().lower()
    provisioning_copy = str(identity_ui.get("provisioning_copy") or "").strip()
    provisioning_note = ""
    if principal_hint and provisioning_copy:
        provisioning_note = f'<p class="muted" style="margin-top:12px;">{html.escape(provisioning_copy)}</p>'
    if activation_state == "active":
        provisioning_note += '<p class="muted">This principal is already active for linked-environment ledger access.</p>'
    return _layout(
        "Passkey | DSS Control Plane",
        f"""
        <div class="card" style="max-width:560px; margin:40px auto 0;">
          <h1>{'Passkey Authorization' if source == 'github' else 'Passkey Login'}</h1>
          <p class="muted">{'Linked identity detected.' if has_linked_identity else 'No linked identity found yet. Continue with GitHub first.'}</p>
          {provisioning_note}
          <input id="principal_did" type="hidden" value="{html.escape(principal_hint)}" />
          <input id="next_path" type="hidden" value="{html.escape(next_path)}" />
          <div class="row">
            <button class="btn primary" id="btn_register" {'disabled' if not has_linked_identity else ''}>Register Passkey</button>
            <button class="btn" id="btn_login" {'disabled' if not has_linked_identity else ''}>Login With Passkey</button>
          </div>
          {'<a class="btn" href="/login/github?next=' + quote(next_path, safe='/?=&') + '">Continue with GitHub</a>' if not has_linked_identity else ''}
          <pre id="passkey_status"></pre>
          <pre id="passkey_error" style="color:#991b1b;"></pre>
        </div>
        <script>
        const b64uToBuf = (s) => {{
          const b64 = s.replace(/-/g, '+').replace(/_/g, '/');
          const padded = b64 + '='.repeat((4 - (b64.length % 4)) % 4);
          return Uint8Array.from(atob(padded), c => c.charCodeAt(0));
        }};
        const bufToB64u = (buf) => btoa(String.fromCharCode(...new Uint8Array(buf))).replaceAll('+', '-').replaceAll('/', '_').replace(/=+$/g, '');
        const statusEl = document.getElementById('passkey_status');
        const errEl = document.getElementById('passkey_error');
        const didEl = document.getElementById('principal_did');
        const nextEl = document.getElementById('next_path');
        let lastCredentialId = '';
        const postJson = async (url, body) => {{
          const res = await fetch(url, {{method:'POST', headers:{{'content-type':'application/json'}}, body:JSON.stringify(body)}});
          const data = await res.json();
          if (!res.ok) throw new Error(JSON.stringify(data));
          return data;
        }};
        document.getElementById('btn_register').onclick = async () => {{
          statusEl.textContent = ''; errEl.textContent = '';
          try {{
            const principal_did = (didEl.value || '').trim();
            if (!principal_did) throw new Error('linked_identity_required');
            const start = await postJson('/login/passkey/register/start', {{principal_did}});
            const o = start.creation_options || {{}};
            const excludeCredentials = Array.isArray(o.excludeCredentials) ? o.excludeCredentials.filter((item) => item && typeof item.id === 'string' && item.id.length > 0).map((item) => ({{ type: item.type || 'public-key', id: b64uToBuf(item.id) }})) : [];
            const cred = await navigator.credentials.create({{ publicKey: {{ challenge: b64uToBuf(o.challenge), rp: o.rp, user: {{id: b64uToBuf(o.user.id), name:o.user.name, displayName:o.user.displayName}}, pubKeyCredParams: o.pubKeyCredParams || [{{type:'public-key', alg:-7}}], excludeCredentials, timeout: o.timeout || 60000, attestation: o.attestation || 'none', authenticatorSelection: o.authenticatorSelection || {{userVerification:'preferred'}}, }} }});
            const resp = cred.response;
            const done = await postJson('/login/passkey/register/finish', {{ challenge_id: start.challenge_id, credential_id: bufToB64u(cred.rawId), client_data_json_b64u: bufToB64u(resp.clientDataJSON), authenticator_data_b64u: bufToB64u(resp.getAuthenticatorData()), public_key_spki_b64u: bufToB64u(resp.getPublicKey()), }});
            lastCredentialId = bufToB64u(cred.rawId);
            statusEl.textContent = 'REGISTER OK\\n' + JSON.stringify(done, null, 2);
          }} catch (e) {{
            errEl.textContent = 'REGISTER ERROR\\n' + String(e);
          }}
        }};
        document.getElementById('btn_login').onclick = async () => {{
          statusEl.textContent = ''; errEl.textContent = '';
          try {{
            const principal_did = (didEl.value || '').trim();
            if (!principal_did) throw new Error('linked_identity_required');
            const start = await postJson('/login/passkey/login/start', {{principal_did}});
            const allowCredentials = Array.isArray(start.allow_credentials) && start.allow_credentials.length > 0 ? start.allow_credentials.filter((item) => item && typeof item.id === 'string' && item.id.length > 0).map((item) => ({{ type: item.type || 'public-key', id: b64uToBuf(item.id) }})) : (lastCredentialId ? [{{type:'public-key', id:b64uToBuf(lastCredentialId)}}] : []);
            const assertion = await navigator.credentials.get({{ publicKey: {{ challenge: b64uToBuf(start.challenge), rpId: start.rp_id || undefined, allowCredentials, userVerification: 'preferred', timeout: 60000, }} }});
            const resp = assertion.response;
            const done = await postJson('/login/passkey/login/finish', {{ challenge_id: start.challenge_id, credential_id: bufToB64u(assertion.rawId), client_data_json_b64u: bufToB64u(resp.clientDataJSON), authenticator_data_b64u: bufToB64u(resp.authenticatorData), signature_b64u: bufToB64u(resp.signature), }});
            statusEl.textContent = 'LOGIN OK\\n' + JSON.stringify(done, null, 2);
            window.location = nextEl.value || '/';
          }} catch (e) {{
            errEl.textContent = 'LOGIN ERROR\\n' + String(e);
          }}
        }};
        </script>
        """,
    )


def render_profile_approval(
    request: Request,
    banner: str = "",
    banner_kind: str = "ok",
    payload_text: str = "",
    result_summary: dict[str, Any] | None = None,
    principal_lookup: dict[str, Any] | None = None,
    *,
    profile_name: str = "Profile",
) -> str:
    banner_html = f'<div class="banner {banner_kind}">{html.escape(banner)}</div>' if banner else ''
    approval_token = str(os.getenv(PROFILE_APPROVAL_TOKEN_ENV) or '').strip()
    prefill = str(request.query_params.get('payload') or '').strip() or payload_text
    helper_copy = 'Paste the structured approval payload from the profile-request email, enter the operator approval token, and approve the request. This writes DSS approval, tenant and ledger assignment, and passkey readiness; MS Entra / Verified ID wallet proof still has to happen afterward before the assigned ledger becomes active.'
    if not approval_token:
        helper_copy = f'{helper_copy} PROFILE_APPROVAL_TOKEN is not configured yet, so approvals are currently disabled.'
    preview_html = ''
    try:
        preview_payload = json.loads(prefill) if prefill else {}
    except Exception:
        preview_payload = {}
    if isinstance(preview_payload, dict) and str(preview_payload.get('request_type') or '').strip() == 'profile_setup':
        try:
            provisioning_defaults = _profile_provisioning_defaults(preview_payload)
            redirect_url = _approval_redirect_url(preview_payload)
            preview_html = f"""
            <div class="card" style="max-width:860px; margin-bottom:16px;">
              <h2>Approval Preview</h2>
              <p class="muted">This is the derived provisioning plan that will be written if you approve the pasted payload.</p>
              <div class="grid" style="margin-bottom:0;">
                <div>
                  <p><strong>Principal DID:</strong> {html.escape(provisioning_defaults['principal_did'] or 'missing')}</p>
                  <p><strong>Owner principal id:</strong> {html.escape(provisioning_defaults['owner_principal_id'])}</p>
                </div>
                <div>
                  <p><strong>Tenant:</strong> {html.escape(provisioning_defaults['tenant_id'])}</p>
                  <p><strong>Ledger:</strong> {html.escape(provisioning_defaults['ledger_id'])}</p>
                </div>
              </div>
              <p><strong>User redirect after approval:</strong> <a href="{html.escape(redirect_url)}">{html.escape(redirect_url)}</a></p>
            </div>
            """
        except Exception:
            preview_html = ''
    lookup_prefill = str(request.query_params.get("principal_did") or "").strip()
    lookup = _as_dict(principal_lookup)
    lookup_html = ""
    if lookup:
        audit = _as_dict(lookup.get("audit"))
        audit_steps = _as_dict(audit.get("steps"))
        principal_step = _as_dict(audit_steps.get("principal"))
        tenant_step = _as_dict(audit_steps.get("tenant"))
        provisioning_step = _as_dict(audit_steps.get("provisioning"))
        error = str(lookup.get("error") or "").strip()
        if error:
            error_detail = html.escape(error)
            if error_detail == "upstream_invalid_json":
                error_detail = "Principal not found in registry. This DID has not been approved or provisioned yet."
            lookup_html = f"""
            <div class="card" style="max-width:860px; margin-bottom:16px;">
              <h2>Principal Audit Lookup</h2>
              <p class="muted">Unable to load the requested principal record.</p>
              <p><strong>Principal DID:</strong> {html.escape(str(lookup.get('principal_did') or ''))}</p>
              <p class="muted">{error_detail}</p>
            </div>
            """
        else:
            audit_outcome = str(audit.get("outcome") or "unavailable").strip() or "unavailable"
            approved_at = str(audit.get("approved_at") or "").strip() or "not recorded"
            activation_state = str(lookup.get("activation_state") or "unknown").strip() or "unknown"
            provisioning_state = str(lookup.get("provisioning_state") or "unknown").strip() or "unknown"
            ledger_ready = "yes" if bool(lookup.get("ledger_access_ready")) else "no"
            lookup_html = f"""
            <div class="card" style="max-width:860px; margin-bottom:16px;">
              <h2>Principal Audit Lookup</h2>
              <p class="muted">Current activation state plus the last recorded `/profile/approve` audit result for this principal.</p>
              <div class="grid" style="margin-bottom:0;">
                <div>
                  <p><strong>Principal DID:</strong> {html.escape(str(lookup.get('principal_did') or ''))}</p>
                  <p><strong>Display name:</strong> {html.escape(str(lookup.get('display_name') or 'unknown'))}</p>
                  <p><strong>Profile request:</strong> {html.escape(str(lookup.get('profile_request_id') or 'unknown'))}</p>
                  <p><strong>Approval state:</strong> {html.escape(str(lookup.get('profile_approval_state') or 'unknown'))}</p>
                </div>
                <div>
                  <p><strong>Tenant:</strong> {html.escape(str(lookup.get('tenant_id') or 'pending'))}</p>
                  <p><strong>Ledger:</strong> {html.escape(str(lookup.get('ledger_id') or 'pending'))}</p>
                  <p><strong>Activation state:</strong> {html.escape(activation_state)}</p>
                  <p><strong>Ledger ready:</strong> {html.escape(ledger_ready)}</p>
                </div>
              </div>
              <p><strong>Last approval outcome:</strong> {html.escape(audit_outcome)}</p>
              <p><strong>Approved at:</strong> {html.escape(approved_at)}</p>
              <p><strong>Principal step:</strong> {html.escape(str(principal_step.get('status') or 'unknown'))}</p>
              <p class="muted">{html.escape(str(principal_step.get('detail') or ''))}</p>
              <p><strong>Tenant step:</strong> {html.escape(str(tenant_step.get('status') or 'unknown'))}</p>
              <p class="muted">{html.escape(str(tenant_step.get('detail') or ''))}</p>
              <p><strong>Provisioning step:</strong> {html.escape(str(provisioning_step.get('status') or 'unknown'))}</p>
              <p class="muted">{html.escape(str(provisioning_step.get('detail') or ''))}</p>
              <p><strong>Provisioning state:</strong> {html.escape(provisioning_state)}</p>
            </div>
            """
    result_html = ''
    summary = _as_dict(result_summary)
    if summary:
        principal_step = _as_dict(summary.get("principal_step"))
        tenant_step = _as_dict(summary.get("tenant_step"))
        provisioning_step = _as_dict(summary.get("provisioning_step"))
        audit_step = _as_dict(summary.get("audit_step"))
        result_html = f"""
        <div class="card" style="max-width:860px; margin-bottom:16px;">
          <h2>Approval Result</h2>
          <p class="muted">This shows the exact outcome of each write performed during approval.</p>
          <p><strong>Principal approval:</strong> {html.escape(str(principal_step.get('status') or 'unknown'))}</p>
          <p class="muted">{html.escape(str(principal_step.get('detail') or ''))}</p>
          <p><strong>Tenant provisioning:</strong> {html.escape(str(tenant_step.get('status') or 'unknown'))}</p>
          <p class="muted">{html.escape(str(tenant_step.get('detail') or ''))}</p>
          <p><strong>Provisioning state update:</strong> {html.escape(str(provisioning_step.get('status') or 'unknown'))}</p>
          <p class="muted">{html.escape(str(provisioning_step.get('detail') or ''))}</p>
          <p><strong>Approval audit write:</strong> {html.escape(str(audit_step.get('status') or 'unknown'))}</p>
          <p class="muted">{html.escape(str(audit_step.get('detail') or ''))}</p>
        </div>
        """
    return _layout(
        "Profile Approval | DSS Control Plane",
        f"""
        <div class="page-header">
            <h1>Profile Approval</h1>
            <p>{html.escape(helper_copy)}</p>
        </div>
        {banner_html}
        {preview_html}
        <div class="card" style="max-width:860px; margin-bottom:16px;">
          <form action="/profile/approve" method="get">
            <label for="lookup_principal_did">Lookup principal audit</label>
            <input id="lookup_principal_did" name="principal_did" value="{html.escape(lookup_prefill or str(lookup.get('principal_did') or ''))}" placeholder="did:key:... or did:web:..." />
            <div class="row" style="margin-top:14px;">
              <button class="btn" type="submit">Load Principal Audit</button>
            </div>
          </form>
        </div>
        {lookup_html}
        {result_html}
        <div class="card" style="max-width:860px;">
          <form action="/profile/approve" method="post">
            <label for="approval_token">Operator approval token</label>
            <input id="approval_token" name="approval_token" type="password" autocomplete="off" placeholder="Configured via PROFILE_APPROVAL_TOKEN" />
            <label for="approval_payload">Structured approval payload</label>
            <textarea id="approval_payload" name="approval_payload" placeholder='{{"request_id": "..."}}'>{html.escape(prefill)}</textarea>
            <div class="row" style="margin-top:14px;">
              <button class="btn primary" type="submit">Approve Profile Request</button>
              <a class="btn" href="/profile/setup">Back To Setup</a>
            </div>
          </form>
        </div>
        """,
        shell=True,
        current_path="/profile/approve",
        profile_name=profile_name,
        approval_count=len(_pending_profile_requests),
    )


def render_profile_setup(
    request: Request,
    banner: str = "",
    banner_kind: str = "ok",
    *,
    profile_data: dict[str, Any] | None = None,
    show_next_steps: bool = False,
) -> str:
    banner_html = f'<div class="banner {banner_kind}">{html.escape(banner)}</div>' if banner else ''
    next_steps_html = (
        '''<div class="card" style="margin-top:16px;">
            <h2>What happens next</h2>
            <p>Profile setup follows a simple governed sequence:</p>
            <ul class="muted" style="margin:0 0 0 18px; padding:0;">
              <li>Submit the identity request for operator approval.</li>
              <li>Seed the model principal and model bindings for the selected library.</li>
              <li>Receive or bind the DSS DID.</li>
              <li>Complete wallet proof or passkey registration as required.</li>
              <li>Enter the Control Plane once activation is ready.</li>
            </ul>
            <p style="margin-top:16px;"><strong>Ledger</strong> is your governed memory layer.</p>
            <p><strong>Principal</strong> is the identity being approved.</p>
            <p><strong>Surface</strong> is the app, device, or runtime context that will later connect to that identity.</p>
          </div>'''
        if show_next_steps
        else ""
    )
    profile = _as_dict(profile_data)
    principal_hint = str(profile.get("principal_did") or request.cookies.get(PRINCIPAL_DID_COOKIE) or "").strip()
    existing_did = str(profile.get("existing_did") or request.query_params.get("existing_did") or "").strip()
    display_name = str(profile.get("display_name") or request.query_params.get("display_name") or "").strip()
    contact_email = str(profile.get("contact_email") or request.query_params.get("contact_email") or "").strip()
    notes = str(profile.get("notes") or request.query_params.get("notes") or "").strip()
    did_mode = str(profile.get("did_mode") or request.query_params.get("did_mode") or ("use_existing" if existing_did else "provision_new")).strip() or "provision_new"
    authenticated = bool(profile.get("authenticated"))
    submit_label = "Update profile" if authenticated and principal_hint else "Send request"
    intro_copy = (
        "Update the canonical profile details for your current DSS principal."
        if authenticated and principal_hint
        else "Request a new governed DID or bind an existing DID, then move through approval and wallet sign-in (or passkey registration) in a controlled sequence."
    )
    helper_copy = (
        "You are signed in. Changes here update the canonical principal record used across the Control Plane."
        if authenticated and principal_hint
        else "Provide the details needed to provision or bind your identity. Initial requests are sent for operator approval."
    )
    profile_panels_html = _render_profile_setup_panels(
        principal_hint=principal_hint,
        display_name=display_name,
        contact_email=contact_email,
        did_mode=did_mode,
        existing_did=existing_did,
        notes=notes,
        model_library_options=_as_dict_list(profile.get("model_library_options")),
        model_library_model_id=str(profile.get("model_library_model_id") or "").strip(),
        model_library_principal_did=str(profile.get("model_library_principal_did") or "").strip(),
        model_library_account_binding_id=str(profile.get("model_library_account_binding_id") or "").strip(),
        model_library_ledger_binding_id=str(profile.get("model_library_ledger_binding_id") or "").strip(),
        submit_label=submit_label,
        helper_copy=helper_copy,
        authenticated=authenticated,
        include_auth_button=True,
    )
    page_body = f"""
        <div class="page-header">
          <h1>Profile Setup</h1>
          <p>{html.escape(intro_copy)}</p>
        </div>
        {banner_html}
        {next_steps_html if show_next_steps else profile_panels_html}
        """
    return _layout(
        "Profile Setup | DSS Control Plane",
        page_body,
    )


def render_verified_id_page(
    request: Request,
    *,
    banner: str = "",
    banner_kind: str = "ok",
    principal_did: str = "",
    request_record: dict[str, Any] | None = None,
    identity_card: dict[str, Any] | None = None,
) -> str:
    banner_html = f'<div class="banner {banner_kind}">{html.escape(banner)}</div>' if banner else ''
    principal_hint = principal_did.strip() or str(request.query_params.get('principal_did') or '').strip() or str(request.cookies.get(PRINCIPAL_DID_COOKIE) or '').strip()
    record = _as_dict(request_record)
    identity_data = _as_dict(identity_card)
    identity_vc = _as_dict(identity_data.get("identity_vc"))
    identity_ui = _as_dict(identity_data.get("ui"))
    state = str(record.get('state') or '').strip()
    request_url = str(record.get('request_url') or '').strip()
    qr_code = str(record.get('request_qr_code') or '').strip()
    status = str(record.get('status') or '').strip() or 'not_started'
    request_json = html.escape(json.dumps(record, indent=2)) if record else ''
    qr_html = f'<img src="{html.escape(qr_code)}" alt="Credential QR" style="max-width:320px; width:100%; border:1px solid var(--border); border-radius:12px; background:var(--surface); padding:12px;" />' if qr_code.startswith('data:image/') else '<p class="muted">Start the flow to generate a credential QR code.</p>'
    # Detect wallet provider from request record or default to generic
    wallet_provider = str(record.get('mode') or '').strip()
    if wallet_provider == 'walt_id_issuance':
        wallet_name = 'MATTR Wallet (OpenID4VCI)'
        deep_link_label = 'Open in MATTR Wallet'
        wallet_instructions = 'Scan the QR code with your MATTR wallet, or copy the link below and paste it into the wallet\'s "Receive Credential" screen.'
    else:
        wallet_name = 'Microsoft Authenticator'
        deep_link_label = 'Open in Microsoft Authenticator'
        wallet_instructions = 'Scan the QR code with Microsoft Authenticator, or tap the button to open the deep link.'
    openid_link = f'<a class="btn" href="{html.escape(request_url)}">{html.escape(deep_link_label)}</a>' if request_url else ''
    # Copy-to-clipboard UI for the offer URL
    copy_url_html = ''
    if request_url:
        copy_url_html = f"""
        <div style="margin-top:12px;">
            <label class="muted" style="font-size:0.75rem;">Credential Offer URL</label>
            <div class="row" style="gap:8px; margin-top:4px;">
                <input id="credential_offer_url" readonly value="{html.escape(request_url)}" style="flex:1; font-size:0.8rem; padding:8px 10px; border:1px solid var(--border); border-radius:8px; background:var(--surface);" />
                <button class="btn" type="button" onclick="navigator.clipboard.writeText(document.getElementById('credential_offer_url').value).then(()=>{{this.textContent='Copied!'; setTimeout(()=>this.textContent='Copy', 1500);}})">Copy</button>
            </div>
        </div>
        """
    poll_copy = 'Waiting for issuer callback.' if state else 'No active request yet.'
    activation_state = html.escape(str(identity_vc.get("activation_state") or "unknown"))
    tenant_id = html.escape(str(identity_vc.get("tenant_id") or "").strip() or "pending")
    ledger_id = html.escape(str(identity_vc.get("ledger_id") or "").strip() or "pending")
    provisioning_copy = html.escape(str(identity_ui.get("provisioning_copy") or "Ledger provisioning status is not available yet."))
    return _layout(
        "Wallet Credential | DSS Control Plane",
        f"""
        <div class="verified-id-page container">
          <div class="page-header">
            <h1>Wallet Credential</h1>
            <p>Issue or verify a wallet credential for the approved DSS principal. The issuance path depends on the principal's configured wallet provider.</p>
          </div>
        {banner_html}
        <div class="grid">
          <div class="card">
            <h2>Start Request</h2>
            <form id="verified_id_form" action="/verified-id/start" method="post">
              <input type="hidden" name="_entra_auth" value="{html.escape(str(request.query_params.get('_entra_auth') or ''))}" />
              <label for="principal_did">Principal DID</label>
              <input id="principal_did" name="principal_did" value="{html.escape(principal_hint)}" placeholder="did:key:..." required />
              <div class="row" style="margin-top:14px;">
                <button class="btn primary" formaction="/verified-id/issue/start" type="submit">Issue Wallet Card</button>
                <button class="btn" formaction="/verified-id/start" type="submit">Start Wallet Proof Check</button>
                <a class="btn" href="/login/wallet">Go To Wallet Login</a>
                <a class="btn" href="/login/passkey{('?principal_did=' + quote(principal_hint, safe='')) if principal_hint else ''}">Go To Passkey</a>
              </div>
            </form>
            <p class="muted" style="margin-top:12px;">Current status: <strong id="verified_id_status">{html.escape(status)}</strong>. {html.escape(poll_copy)}</p>
            <p class="muted">Use <strong>Issue Wallet Card</strong> first if the wallet says the credential card is missing. Use <strong>Start Wallet Proof Check</strong> after the card has been issued.</p>
          </div>
          <div class="card">
            <h2>Activation Status</h2>
            <p class="muted">{provisioning_copy}</p>
            <p><strong>Activation state:</strong> {activation_state}</p>
            <p><strong>Assigned tenant:</strong> {tenant_id}</p>
            <p><strong>Assigned ledger:</strong> {ledger_id}</p>
            <p class="muted">This page is the wallet-proof step. The assigned ledger becomes the active session scope only after wallet proof and provisioning state both clear.</p>
          </div>
          <div class="card">
            <h2>Wallet — {html.escape(wallet_name)}</h2>
            {qr_html}
            <p class="muted" style="margin-top:10px; font-size:0.875rem;">{html.escape(wallet_instructions)}</p>
            <div class="row" style="margin-top:14px;">
              {openid_link}
            </div>
            {copy_url_html}
          </div>
        </div>
        <div class="card verified-id-request-state">
          <h2>Request State</h2>
          <pre id="verified_id_request_json">{request_json or html.escape(json.dumps({"status": "not_started"}, indent=2))}</pre>
        </div>
        <script>
        const verifiedIdState = {json.dumps(state)};
        const statusEl = document.getElementById('verified_id_status');
        const jsonEl = document.getElementById('verified_id_request_json');
        const poll = async () => {{
          if (!verifiedIdState) return;
          try {{
            const res = await fetch(`/api/verified-id/requests/${{encodeURIComponent(verifiedIdState)}}`, {{headers: {{accept: 'application/json'}}}});
            const data = await res.json();
            if (!res.ok) throw new Error(JSON.stringify(data));
            const record = data.request || {{}};
            statusEl.textContent = record.status || 'unknown';
            jsonEl.textContent = JSON.stringify(data, null, 2);
            const finalization = record.finalization || data.finalization || {{}};
            const finalStatus = (finalization.status || '').toLowerCase();
            const recordStatus = (record.status || '').toLowerCase();
            if (recordStatus === 'presentation_verified' || finalStatus === 'ok' || finalStatus === 'issued') {{
              window.clearInterval(window.__verifiedIdPoll);
            }}
          }} catch (err) {{
            statusEl.textContent = 'poll_error';
          }}
        }};
        if (verifiedIdState) {{
          window.__verifiedIdPoll = window.setInterval(poll, 4000);
          poll();
        }}
        </script>
        </div>
        """,
    )


def _build_profile_request_operator_payload(payload: dict[str, str], request: Request) -> dict[str, Any]:
    request_id = f"pr_{secrets.token_urlsafe(8)}"
    requested_at = datetime.now(timezone.utc).isoformat()
    display_name = str(payload.get("display_name") or "").strip()
    contact_email = str(payload.get("contact_email") or "").strip()
    did_mode = str(payload.get("did_mode") or "provision_new").strip() or "provision_new"
    existing_did = str(payload.get("existing_did") or "").strip()
    principal_hint = str(request.cookies.get(PRINCIPAL_DID_COOKIE) or "").strip()
    requested_host = _request_host(request)
    suggested_principal_did = existing_did if did_mode == "use_existing" and existing_did.startswith("did:") else ""
    model_library_model_id = str(payload.get("model_library_model_id") or "").strip()
    model_library_principal_did = str(payload.get("model_library_principal_did") or "").strip()
    model_library_account_binding_id = str(payload.get("model_library_account_binding_id") or "").strip()
    model_library_ledger_binding_id = str(payload.get("model_library_ledger_binding_id") or "").strip()
    if contact_email:
        email_hash = hashlib.sha256(contact_email.lower().strip().encode()).hexdigest()[:16]
        wallet_slug = email_hash
    else:
        wallet_slug = "pending-user"
    wallet_did = f"did:web:{os.getenv('DEFAULT_DID_HOST', '')}:wallet:{wallet_slug}" if wallet_slug else ""
    wallet_binding_ref = f"vc:msauth:profile:{wallet_slug}:v1" if wallet_slug else ""
    credential_ref = f"cred:msauth:profile:{wallet_slug}:v1" if wallet_slug else ""
    return {
        "request_id": request_id,
        "requested_at": requested_at,
        "requested_host": requested_host,
        "requested_via": f"{PUBLIC_BASE_URL}/profile/setup",
        "request_type": "profile_setup",
        "tenant_id": FRONTEND_TENANT_ID,
        "approval_mode": "operator_manual",
        "requested_identity": {
            "display_name": display_name,
            "contact_email": contact_email,
            "did_mode": did_mode,
            "existing_did": existing_did,
            "principal_hint": principal_hint,
            "suggested_principal_did": suggested_principal_did,
        },
        "requested_model_library": {
            "model_id": model_library_model_id,
            "principal_did": model_library_principal_did,
            "account_binding_id": model_library_account_binding_id,
            "ledger_binding_id": model_library_ledger_binding_id,
            "provider_type": "OpenRouter" if model_library_model_id else "",
            "selected_via": "profile_setup",
        },
        "requested_binding": {
            "passkey_auth_required": True,
            "wallet_provider": "microsoft_authenticator",
            "wallet_did": wallet_did,
            "wallet_binding_ref": wallet_binding_ref,
            "credential_ref": credential_ref,
            "wallet_proof_state": "pending_verified_id",
            "issuer_did": ISSUER_DID,
            "trust_anchor_role": "pending_profile_approval",
        },
        "linked_environments": [
            {"label": "Identity Hub", "url": PUBLIC_BASE_URL},
            {"label": "Chat", "url": CHAT_BASE_URL},
        ],
        "approval_steps": [
            "Review the requested DID mode and contact details.",
            "If approved, provision or bind the principal in middleware.",
            "Provision the tenant and default ledger assignment for the approved principal.",
            "Attach wallet metadata and authority evidence after MS Entra / DID verification.",
            f"Direct the user back to {os.getenv('PUBLIC_BASE_URL', '')}/verified-id to issue their wallet card, then /login/wallet to complete wallet sign-in (or /login/passkey for passkey binding if preferred)."
        ],
        "notes": str(payload.get("notes") or "").strip(),
    }


async def _send_profile_request_email(payload: dict[str, str], operator_payload: dict[str, Any]) -> tuple[bool, str]:
    api_key = str(os.getenv("RESEND_API_KEY") or "").strip()
    sender = str(os.getenv("PROFILE_REQUEST_EMAIL_FROM") or os.getenv("RESEND_FROM_EMAIL") or "").strip()
    recipient = str(os.getenv("PROFILE_REQUEST_EMAIL_TO") or "").strip()
    if not api_key or not sender or not recipient:
        return False, "Resend profile-request delivery is not configured yet. Set RESEND_API_KEY, PROFILE_REQUEST_EMAIL_FROM, and PROFILE_REQUEST_EMAIL_TO."
    approval_token = str(os.getenv(PROFILE_APPROVAL_TOKEN_ENV) or "").strip()
    subject = f"DSS profile request {operator_payload.get('request_id')}: {payload.get('display_name') or payload.get('contact_email') or 'unknown user'}"
    operator_json = html.escape(json.dumps(operator_payload, indent=2, sort_keys=True))
    approval_steps = ''.join(f"<li>{html.escape(step)}</li>" for step in _as_list(operator_payload.get("approval_steps")))
    requested_identity = operator_payload.get("requested_identity") or {}
    suggested_principal_did = str(requested_identity.get("suggested_principal_did") or "pending-new-did")
    token_block = f"""
    <p><strong>Operator approval token:</strong> <code>{html.escape(approval_token)}</code></p>
    <p class="muted">Use this token on the operator approval page to authorize the request.</p>
    """ if approval_token else """
    <p class="muted"><strong>Operator approval token is not configured.</strong> Set PROFILE_APPROVAL_TOKEN to enable approvals.</p>
    """
    html_body = f"""
    <h2>DSS profile request</h2>
    <p><strong>Request ID:</strong> {html.escape(str(operator_payload.get('request_id') or ''))}</p>
    <p><strong>Requested at:</strong> {html.escape(str(operator_payload.get('requested_at') or ''))}</p>
    <p><strong>Name:</strong> {html.escape(payload.get('display_name') or '')}</p>
    <p><strong>Email:</strong> {html.escape(payload.get('contact_email') or '')}</p>
    <p><strong>DID mode:</strong> {html.escape(payload.get('did_mode') or '')}</p>
    <p><strong>Existing DID:</strong> {html.escape(payload.get('existing_did') or '')}</p>
    <p><strong>Suggested principal DID:</strong> {html.escape(suggested_principal_did)}</p>
    <p><strong>Wallet card issuance URL:</strong> <a href="{html.escape(PUBLIC_BASE_URL + '/verified-id')}">{html.escape(PUBLIC_BASE_URL + '/verified-id')}</a></p>
    <p><strong>Wallet sign-in URL:</strong> <a href="{html.escape(PUBLIC_BASE_URL + '/login/wallet')}">{html.escape(PUBLIC_BASE_URL + '/login/wallet')}</a></p>
    <p><strong>Passkey completion URL:</strong> <a href="{html.escape(PUBLIC_BASE_URL + '/login/passkey')}">{html.escape(PUBLIC_BASE_URL + '/login/passkey')}</a></p>
    <p><strong>Operator approval URL:</strong> <a href="{html.escape(PUBLIC_BASE_URL + '/profile/approve')}">{html.escape(PUBLIC_BASE_URL + '/profile/approve')}</a></p>
    <p><strong>Linked environment:</strong> <a href="{html.escape(CHAT_BASE_URL)}">{html.escape(CHAT_BASE_URL)}</a></p>
    {token_block}
    <p><strong>Notes:</strong></p>
    <pre>{html.escape(payload.get('notes') or '')}</pre>
    <h3>Operator next steps</h3>
    <ol>{approval_steps}</ol>
    <h3>Structured approval payload</h3>
    <pre>{operator_json}</pre>
    """
    _pending_profile_requests.append(operator_payload)
    try:
        async with httpx.AsyncClient(timeout=20.0) as client:
            resp = await client.post(
                "https://api.resend.com/emails",
                headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
                json={"from": sender, "to": [recipient], "subject": subject, "html": html_body},
            )
            if resp.status_code >= 400:
                return False, f"Resend rejected the request ({resp.status_code})."
    except Exception as exc:
        return False, f"Profile request delivery failed: {exc}"
    return True, f"Profile request {operator_payload.get('request_id') or ''} sent for operator approval. After approval, return here to bind the passkey." 


async def _send_human_principal_invite_email(payload: dict[str, str], request: Request) -> tuple[bool, str]:
    api_key = str(os.getenv("RESEND_API_KEY") or "").strip()
    sender = str(os.getenv("PRINCIPAL_INVITE_EMAIL_FROM") or os.getenv("PROFILE_REQUEST_EMAIL_FROM") or os.getenv("RESEND_FROM_EMAIL") or "").strip()
    recipient = str(payload.get("contact_email") or "").strip()
    if not api_key or not sender or not recipient:
        return False, "Human-principal invite delivery is not configured yet. Set RESEND_API_KEY and PRINCIPAL_INVITE_EMAIL_FROM or PROFILE_REQUEST_EMAIL_FROM."
    invite_query = urlencode(
        {
            "display_name": str(payload.get("display_name") or "").strip(),
            "contact_email": recipient,
            "did_mode": str(payload.get("did_mode") or "provision_new").strip() or "provision_new",
            "existing_did": str(payload.get("existing_did") or "").strip(),
            "notes": str(payload.get("notes") or "").strip(),
        }
    )
    invite_url = f"{PUBLIC_BASE_URL}/profile/setup?{invite_query}"
    subject = f"DSS invite: {payload.get('display_name') or recipient}"
    html_body = f"""
    <h2>DSS principal invite</h2>
    <p>You have been invited to set up a governed DSS identity.</p>
    <p><strong>Name:</strong> {html.escape(str(payload.get('display_name') or '').strip() or recipient)}</p>
    <p><strong>Email:</strong> {html.escape(recipient)}</p>
    <p><strong>Next step:</strong> open the profile-setup link below and continue in Microsoft Authenticator / Verified ID when prompted.</p>
    <p><a href="{html.escape(invite_url)}">{html.escape(invite_url)}</a></p>
    <p>If you already have an existing DID, open the same link and choose <strong>Use an existing DID</strong> during setup. Your email will remain as a secondary contact address.</p>
    """
    try:
        async with httpx.AsyncClient(timeout=20.0) as client:
            resp = await client.post(
                "https://api.resend.com/emails",
                headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
                json={"from": sender, "to": [recipient], "subject": subject, "html": html_body},
            )
            if resp.status_code >= 400:
                return False, f"Resend rejected the invite ({resp.status_code})."
    except Exception as exc:
        return False, f"Invite delivery failed: {exc}"
    return True, f"Invite sent to {recipient}. They can now start DSS DID setup and Microsoft Authenticator onboarding."


def _approval_redirect_url(operator_payload: dict[str, Any]) -> str:
    requested_identity = operator_payload.get('requested_identity') or {}
    requested_binding = operator_payload.get('requested_binding') or {}
    principal_did = str(requested_identity.get('suggested_principal_did') or requested_identity.get('existing_did') or requested_binding.get('wallet_did') or '').strip()
    has_wallet_did = bool(str(requested_binding.get('wallet_did') or '').strip())
    if not principal_did:
        return f"{PUBLIC_BASE_URL}/login/wallet"
    if has_wallet_did:
        return f"{PUBLIC_BASE_URL}/verified-id?principal_did={quote(principal_did, safe='')}"
    return f"{PUBLIC_BASE_URL}/login/passkey?principal_did={quote(principal_did, safe='')}"


def _principal_owner_id(principal_did: str) -> str:
    text = str(principal_did or '').strip()
    if text.startswith('did:'):
        return text[len('did:'):].strip() or text
    return text or 'anonymous'


def _profile_provisioning_defaults(operator_payload: dict[str, Any]) -> dict[str, str]:
    requested_identity = operator_payload.get('requested_identity') or {}
    requested_binding = operator_payload.get('requested_binding') or {}
    principal_did = str(requested_identity.get('suggested_principal_did') or requested_identity.get('existing_did') or requested_binding.get('wallet_did') or '').strip()
    display_name = str(requested_identity.get('display_name') or '').strip()
    contact_email = str(requested_identity.get('contact_email') or '').strip().lower()
    if contact_email:
        slug = hashlib.sha256(contact_email.encode()).hexdigest()[:16]
    elif display_name:
        slug = hashlib.sha256(display_name.lower().encode()).hexdigest()[:16]
    elif principal_did:
        slug = hashlib.sha256(principal_did.encode()).hexdigest()[:16]
    else:
        slug = 'member'
    tenant_id = str(operator_payload.get('tenant_id') or '').strip() or f"tenant:{slug}"
    if not tenant_id.startswith('tenant:'):
        tenant_id = f"tenant:{tenant_id}"
    ledger_id = f"chat-{tenant_id.split(':', 1)[1]}"
    return {
        'principal_did': principal_did,
        'owner_principal_id': _principal_owner_id(principal_did),
        'owner_principal_type': 'user',
        'tenant_id': tenant_id,
        'ledger_id': ledger_id,
        'display_name': display_name or principal_did or tenant_id,
        'slug': slug,
    }


def _profile_approval_audit_record(
    operator_payload: dict[str, Any],
    provisioning_defaults: dict[str, str],
    result_summary: dict[str, Any],
) -> dict[str, Any]:
    redirect_url = _approval_redirect_url(operator_payload)
    principal_step = _as_dict(result_summary.get("principal_step"))
    tenant_step = _as_dict(result_summary.get("tenant_step"))
    provisioning_step = _as_dict(result_summary.get("provisioning_step"))
    statuses = {
        str(principal_step.get("status") or "").strip().lower(),
        str(tenant_step.get("status") or "").strip().lower(),
        str(provisioning_step.get("status") or "").strip().lower(),
    }
    outcome = "ok"
    if "failed" in statuses:
        outcome = "failed"
    elif "partial" in statuses:
        outcome = "partial"
    return {
        "request_id": str(operator_payload.get("request_id") or "").strip(),
        "approved_at": datetime.now(timezone.utc).isoformat(),
        "approval_surface": "control_plane_profile_approve",
        "outcome": outcome,
        "principal_did": provisioning_defaults["principal_did"],
        "tenant_id": provisioning_defaults["tenant_id"],
        "ledger_id": provisioning_defaults["ledger_id"],
        "redirect_url": redirect_url,
        "steps": {
            "principal": principal_step,
            "tenant": tenant_step,
            "provisioning": provisioning_step,
        },
    }


async def _persist_profile_approval_audit(
    principal_payload: dict[str, Any],
    operator_payload: dict[str, Any],
    provisioning_defaults: dict[str, str],
    result_summary: dict[str, Any],
) -> tuple[int, dict[str, Any]]:
    return await _principal_upsert(
        {
            "principal_did": str(principal_payload.get("principal_did") or "").strip(),
            "tenant_id": str(principal_payload.get("tenant_id") or "").strip(),
            "display_name": str(principal_payload.get("display_name") or "").strip(),
            "metadata": {
                "profile_request_id": str(operator_payload.get("request_id") or "").strip(),
                "profile_approval_last_result": _profile_approval_audit_record(
                    operator_payload,
                    provisioning_defaults,
                    result_summary,
                ),
            },
        }
    )


async def _execute_profile_approval_core(operator_payload: dict[str, Any]) -> tuple[bool, str, dict[str, Any]]:
    """Run the actual approval writes and return (ok, message, result_summary)."""
    principal_payload, standing_event = _build_profile_approval_records(operator_payload)
    provisioning_defaults = _profile_provisioning_defaults(operator_payload)
    result_summary: dict[str, Any] = {
        "principal_step": {"status": "pending", "detail": "Principal approval not attempted yet."},
        "tenant_step": {"status": "pending", "detail": "Tenant provisioning not attempted yet."},
        "provisioning_step": {"status": "pending", "detail": "Provisioning-state update not attempted yet."},
        "audit_step": {"status": "pending", "detail": "Approval audit write not attempted yet."},
    }
    principal_status, principal_body = await _principal_upsert(principal_payload)
    if principal_status >= 400:
        detail = principal_body.get('detail') or principal_body.get('error') or principal_body
        result_summary["principal_step"] = {"status": "failed", "detail": f"{principal_status}: {detail}"}
        result_summary["audit_step"] = {"status": "skipped", "detail": "Principal write failed, so there is no principal record available for audit persistence."}
        return False, f"Principal approval failed ({principal_status}): {detail}", result_summary
    result_summary["principal_step"] = {"status": "ok", "detail": f"Approved principal {principal_payload.get('principal_did') or ''} and recorded standing update intent."}
    standing_status, standing_body = await _principal_standing_event(str(principal_payload.get('principal_did') or ''), standing_event)
    if standing_status >= 400:
        detail = standing_body.get('detail') or standing_body.get('error') or standing_body
        result_summary["principal_step"] = {"status": "partial", "detail": f"Principal record written, but standing update failed ({standing_status}: {detail})."}
        audit_status, audit_body = await _persist_profile_approval_audit(principal_payload, operator_payload, provisioning_defaults, result_summary)
        if audit_status >= 400:
            audit_detail = audit_body.get('detail') or audit_body.get('error') or audit_body
            result_summary["audit_step"] = {"status": "failed", "detail": f"{audit_status}: {audit_detail}"}
        else:
            result_summary["audit_step"] = {"status": "ok", "detail": "Persisted the approval result on the principal record for operator audit traceability."}
        return False, f"Standing update failed ({standing_status}): {detail}", result_summary
    result_summary["principal_step"] = {"status": "ok", "detail": f"Principal and standing update both succeeded for {principal_payload.get('principal_did') or ''}."}
    tenant_status = 0
    tenant_body: dict[str, Any] = {}
    if BACKEND_ADMIN_TOKEN:
        tenant_status, tenant_body = await _backend_admin_post(
            "/admin/tenants",
            {
                "tenant_id": provisioning_defaults["tenant_id"],
                "name": provisioning_defaults["display_name"],
                "owner_principal_id": provisioning_defaults["owner_principal_id"],
                "owner_principal_type": provisioning_defaults["owner_principal_type"],
                "policy_profile": "standard",
                "ledger_ids": [],
                "metadata": {
                    "profile_request_id": str(operator_payload.get('request_id') or '').strip(),
                    "provisioning_source": "control_plane_profile_approval",
                },
            },
        )
        if tenant_status >= 400:
            detail = tenant_body.get('detail') or tenant_body.get('error') or tenant_body
            result_summary["tenant_step"] = {"status": "failed", "detail": f"{tenant_status}: {detail}"}
            audit_status, audit_body = await _persist_profile_approval_audit(principal_payload, operator_payload, provisioning_defaults, result_summary)
            if audit_status >= 400:
                audit_detail = audit_body.get('detail') or audit_body.get('error') or audit_body
                result_summary["audit_step"] = {"status": "failed", "detail": f"{audit_status}: {audit_detail}"}
            else:
                result_summary["audit_step"] = {"status": "ok", "detail": "Persisted the approval result on the principal record for operator audit traceability."}
            return False, f"Tenant provisioning failed ({tenant_status}): {detail}", result_summary
        result_summary["tenant_step"] = {
            "status": "ok",
            "detail": f"Provisioned tenant {provisioning_defaults['tenant_id']} without a default ledger; ledger creation is deferred until the user completes onboarding.",
        }
    else:
        result_summary["tenant_step"] = {
            "status": "skipped",
            "detail": "Backend admin provisioning skipped because TRUST_ANCHOR_ADMIN_TOKEN or ADMIN_TOKEN is not configured.",
        }
    provisioning_status, provisioning_body = await _principal_provisioning_update(
        str(principal_payload.get('principal_did') or ''),
        {
            "tenant_id": provisioning_defaults["tenant_id"],
            "ledger_id": None,
            "provisioning_state": "pending_onboarding",
            "notification_state": "approved",
            "authority_evidence_ref": f"profile-request:{str(operator_payload.get('request_id') or '').strip()}",
        },
    )
    if provisioning_status >= 400:
        detail = provisioning_body.get('detail') or provisioning_body.get('error') or provisioning_body
        result_summary["provisioning_step"] = {"status": "failed", "detail": f"{provisioning_status}: {detail}"}
        audit_status, audit_body = await _persist_profile_approval_audit(principal_payload, operator_payload, provisioning_defaults, result_summary)
        if audit_status >= 400:
            audit_detail = audit_body.get('detail') or audit_body.get('error') or audit_body
            result_summary["audit_step"] = {"status": "failed", "detail": f"{audit_status}: {audit_detail}"}
        else:
            result_summary["audit_step"] = {"status": "ok", "detail": "Persisted the approval result on the principal record for operator audit traceability."}
        return False, f"Provisioning state update failed ({provisioning_status}): {detail}", result_summary
    result_summary["provisioning_step"] = {
        "status": "ok",
        "detail": f"Recorded {provisioning_defaults['tenant_id']} on the principal activation boundary; ledger assignment deferred until onboarding.",
    }
    audit_status, audit_body = await _persist_profile_approval_audit(principal_payload, operator_payload, provisioning_defaults, result_summary)
    if audit_status >= 400:
        audit_detail = audit_body.get('detail') or audit_body.get('error') or audit_body
        result_summary["audit_step"] = {"status": "failed", "detail": f"{audit_status}: {audit_detail}"}
        return False, f"Approval audit write failed ({audit_status}): {audit_detail}", result_summary
    result_summary["audit_step"] = {"status": "ok", "detail": "Persisted the approval result on the principal record for operator audit traceability."}
    redirect_url = _approval_redirect_url(operator_payload)
    tenant_copy = (
        f" Provisioned tenant {provisioning_defaults['tenant_id']} without a default ledger; ledger creation is deferred until the user completes onboarding."
        if BACKEND_ADMIN_TOKEN
        else f" Recorded tenant {provisioning_defaults['tenant_id']} for later activation, but backend admin provisioning is skipped until TRUST_ANCHOR_ADMIN_TOKEN or ADMIN_TOKEN is configured."
    )
    requested_binding = operator_payload.get('requested_binding') or {}
    has_wallet_did = bool(str(requested_binding.get('wallet_did') or '').strip())
    auth_copy = "wallet sign-in" if has_wallet_did else "passkey binding"
    success = (
        f"Approved {principal_payload.get('principal_did') or ''} for DSS access and {auth_copy}."
        f"{tenant_copy} Onboarding (including wallet proof and ledger selection) is still pending; once complete, the assigned ledger can become the active session scope."
        f" User next step: {redirect_url}"
    )
    return True, success, result_summary


def _build_profile_approval_records(operator_payload: dict[str, Any]) -> tuple[dict[str, Any], dict[str, Any]]:
    requested_identity = operator_payload.get('requested_identity') or {}
    requested_binding = operator_payload.get('requested_binding') or {}
    principal_did = str(requested_identity.get('suggested_principal_did') or requested_identity.get('existing_did') or requested_binding.get('wallet_did') or '').strip()
    if not principal_did.startswith('did:'):
        raise ValueError('approval payload is missing a valid principal DID')
    contact_email = str(requested_identity.get('contact_email') or '').strip().lower()
    display_name = str(requested_identity.get('display_name') or '').strip()
    did_mode = str(requested_identity.get('did_mode') or '').strip().lower()
    provisioning_defaults = _profile_provisioning_defaults(operator_payload)
    principal_metadata = {
        'actor_type': 'human',
        'wallet_capable': True,
        'wallet_provider': str(requested_binding.get('wallet_provider') or 'microsoft_authenticator').strip(),
        'wallet_proof_state': str(requested_binding.get('wallet_proof_state') or 'pending_verified_id').strip() or 'pending_verified_id',
        'pending_wallet_did': str(requested_binding.get('wallet_did') or '').strip(),
        'pending_wallet_binding_ref': str(requested_binding.get('wallet_binding_ref') or '').strip(),
        'pending_credential_ref': str(requested_binding.get('credential_ref') or '').strip(),
        'vc_status': 'none',
        'issuer_did': str(requested_binding.get('issuer_did') or ISSUER_DID).strip(),
        'trust_anchor_role': 'approved_pending_onboarding',
        'profile_request_id': str(operator_payload.get('request_id') or '').strip(),
        'profile_request_mode': str(requested_identity.get('did_mode') or '').strip(),
        'profile_approval_state': 'approved_pending_onboarding',
        'provisioning_state': 'pending_onboarding',
        'provisioned_tenant_id': provisioning_defaults['tenant_id'],
        'provisioned_ledger_id': None,
    }
    if contact_email:
        if did_mode == 'use_existing':
            principal_metadata['secondary_email'] = contact_email
            principal_metadata['secondary_email_normalized'] = contact_email
        else:
            principal_metadata['email'] = contact_email
            principal_metadata['email_normalized'] = contact_email
    principal_payload = {
        'principal_did': principal_did,
        'tenant_id': provisioning_defaults['tenant_id'],
        'display_name': display_name,
        'metadata': principal_metadata,
    }
    standing_event = {
        'event_type': 'trust_adjustment',
        'issuer': 'operator:control-plane',
        'reason_code': 'profile_request_approved_pending_onboarding',
        'delta': {
            'trust_class': 'T3',
            'posture_class': 'P3',
            'operator_profile': 'member',
            'probation_status': 'cleared',
        },
        'standing_envelope_ref': 'env:member:user',
        'idempotency_key': str(operator_payload.get('request_id') or '').strip() or f"profile-approval-{principal_did}",
    }
    return principal_payload, standing_event


async def profile_approve_page(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    principal_did = str(request.query_params.get("principal_did") or "").strip()
    principal_lookup = await _load_profile_approval_lookup(principal_did) if principal_did else None
    profile_name = _profile_name_from_identity_card(identity_card)
    return HTMLResponse(render_profile_approval(request, principal_lookup=principal_lookup, profile_name=profile_name))


async def profile_approve_submit(request: Request) -> Response:
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    profile_name = _profile_name_from_identity_card(identity_card)
    form = await request.form()
    approval_token = str(form.get('approval_token') or '').strip()
    expected_token = str(os.getenv(PROFILE_APPROVAL_TOKEN_ENV) or '').strip()
    payload_text = str(form.get('approval_payload') or '').strip()
    if not expected_token:
        return HTMLResponse(render_profile_approval(request, banner='PROFILE_APPROVAL_TOKEN is not configured yet.', banner_kind='warn', payload_text=payload_text, profile_name=profile_name), status_code=503)
    if not approval_token or not hmac.compare_digest(approval_token, expected_token):
        return HTMLResponse(render_profile_approval(request, banner='Operator approval token is invalid.', banner_kind='warn', payload_text=payload_text, profile_name=profile_name), status_code=403)
    try:
        operator_payload = json.loads(payload_text)
    except Exception as exc:
        return HTMLResponse(render_profile_approval(request, banner=f'Approval payload is not valid JSON: {exc}', banner_kind='warn', payload_text=payload_text, profile_name=profile_name), status_code=400)
    if not isinstance(operator_payload, dict) or str(operator_payload.get('request_type') or '').strip() != 'profile_setup':
        return HTMLResponse(render_profile_approval(request, banner='Approval payload must be a profile_setup request.', banner_kind='warn', payload_text=payload_text, profile_name=profile_name), status_code=400)
    ok, message, result_summary = await _execute_profile_approval_core(operator_payload)
    principal_lookup = await _load_profile_approval_lookup(
        str(_profile_provisioning_defaults(operator_payload).get("principal_did") or "").strip()
    )
    return HTMLResponse(
        render_profile_approval(
            request,
            banner=message,
            banner_kind="ok" if ok else "warn",
            payload_text=payload_text,
            result_summary=result_summary,
            principal_lookup=principal_lookup,
            profile_name=profile_name,
        ),
        status_code=200 if ok else 502,
    )


