async def issuer_authority_document(_: Request) -> JSONResponse:
    bundle = await fetch_json('/api/trust-anchor/bundle')
    if isinstance(bundle, dict):
        authority = bundle.get('public_issuer_authority')
        if isinstance(authority, dict):
            return JSONResponse(authority)
    fallback_bundle = await trust_anchor_bundle(_)
    try:
        payload = json.loads(_response_body_text(fallback_bundle))
    except Exception:
        payload = {}
    authority = _as_dict(payload).get('public_issuer_authority')
    return JSONResponse(_as_dict(authority))


