def _parse_iso_datetime(value: Any) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    normalized = text.replace("Z", "+00:00")
    try:
        parsed = datetime.fromisoformat(normalized)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _event_timestamp(event: dict[str, Any]) -> datetime:
    return _parse_iso_datetime(event.get("timestamp")) or datetime(1970, 1, 1, tzinfo=timezone.utc)


def _timestamp_from_value(value: Any) -> datetime:
    return _parse_iso_datetime(value) or datetime(1970, 1, 1, tzinfo=timezone.utc)


def _format_activity_timestamp(value: Any) -> str:
    parsed = _parse_iso_datetime(value)
    if not parsed:
        return str(value or "").strip()
    return parsed.strftime("%d %b %Y, %H:%M")


def _ledger_entry_coord(entry: dict[str, Any]) -> str:
    key = _as_dict(entry.get("key"))
    namespace = str(key.get("namespace") or entry.get("namespace") or "").strip()
    identifier = str(key.get("identifier") or entry.get("identifier") or "").strip()
    coordinate = str(entry.get("coordinate") or "").strip()
    if coordinate:
        return coordinate
    if namespace and identifier:
        return f"{namespace}:{identifier}"
    return ""


def _ledger_entry_metadata(entry: dict[str, Any]) -> dict[str, Any]:
    state = _as_dict(entry.get("state"))
    return _as_dict(state.get("metadata") or entry.get("metadata"))


def _ledger_entry_timestamp(entry: dict[str, Any], metadata: dict[str, Any]) -> str:
    meta = _as_dict(metadata.get("meta"))
    for candidate in (
        entry.get("created_at"),
        meta.get("created_at"),
        metadata.get("created_at"),
        metadata.get("timestamp"),
        metadata.get("ts"),
    ):
        text = str(candidate or "").strip()
        if text:
            return text
    return datetime.now(timezone.utc).isoformat()


def _ledger_entry_content(metadata: dict[str, Any], entry: dict[str, Any]) -> str:
    payload = _as_dict(metadata.get("payload"))
    skim = _as_dict(metadata.get("skim"))
    blobs = _as_dict(payload.get("blobs"))
    segments = _as_list(payload.get("segments"))

    for candidate in (
        metadata.get("content"),
        metadata.get("assistant_reply"),
        metadata.get("user_message"),
        metadata.get("prompt"),
        metadata.get("text"),
        skim.get("one_line"),
        entry.get("notes"),
    ):
        text = str(candidate or "").strip()
        if text:
            return text

    for segment in segments:
        if not isinstance(segment, dict):
            continue
        blob_ref = str(segment.get("blob_ref") or "").strip()
        blob_value = str(blobs.get(blob_ref) or "").strip() if blob_ref else ""
        if blob_value:
            return blob_value

    for value in blobs.values():
        text = str(value or "").strip()
        if text:
            return text
    return ""


def _ledger_entry_kind(metadata: dict[str, Any], entry: dict[str, Any]) -> str:
    return str(metadata.get("kind") or entry.get("type") or "").strip().lower()


def _prompt_principal_label(metadata: dict[str, Any]) -> str:
    delegated = _as_dict(metadata.get("delegated_prompt_path"))
    principal_type = str(
        delegated.get("prompt_principal_type")
        or delegated.get("principal_type")
        or ""
    ).strip().lower()
    principal_id = str(
        delegated.get("prompt_principal_id")
        or delegated.get("principal_id")
        or ""
    ).strip()
    principal_did = str(
        delegated.get("prompt_principal_did")
        or delegated.get("principal_did")
        or ""
    ).strip()
    if not principal_id and not principal_did:
        contributor = _as_dict(metadata.get("contributor"))
        principal_type = str(contributor.get("principal_type") or "").strip().lower()
        principal_id = str(contributor.get("principal_id") or "").strip()
        principal_did = str(contributor.get("principal_did") or "").strip()

    if principal_type == "agent":
        if principal_id.startswith("openai:agent:"):
            agent_name = principal_id[len("openai:agent:") :].strip()
            if agent_name:
                return f"openai/{agent_name}"
        if principal_id.startswith("openai:"):
            agent_name = principal_id[len("openai:") :].strip()
            if agent_name:
                return f"openai/{agent_name}"
        marker = ":principals:agent:openai:"
        if marker in principal_did:
            agent_name = principal_did.split(marker, 1)[1].strip()
            if agent_name:
                return f"openai/{agent_name}"
    if principal_id.startswith("openai:agent:"):
        agent_name = principal_id[len("openai:agent:") :].strip()
        if agent_name:
            return f"openai/{agent_name}"
    if principal_id.startswith("openai:"):
        agent_name = principal_id[len("openai:") :].strip()
        if agent_name:
            return f"openai/{agent_name}"
    marker = ":principals:agent:openai:"
    if marker in principal_did:
        agent_name = principal_did.split(marker, 1)[1].strip()
        if agent_name:
            return f"openai/{agent_name}"

    if principal_id:
        return principal_id
    if principal_did:
        return principal_did
    return ""


def _response_model_label(metadata: dict[str, Any]) -> str:
    model_id = str(metadata.get("model_id") or "").strip()
    if model_id:
        return model_id
    provider_id = str(metadata.get("provider_id") or "").strip()
    if provider_id:
        return provider_id
    return ""


def _delegated_prompt_details(metadata: dict[str, Any]) -> dict[str, Any]:
    return _as_dict(metadata.get("delegated_prompt_path"))


def _answer_surface_integrity_details(metadata: dict[str, Any]) -> dict[str, Any]:
    return _as_dict(metadata.get("answer_surface_integrity"))


def _ledger_entry_attribution(metadata: dict[str, Any], *, role: str) -> tuple[str, str]:
    prompt_actor = _prompt_principal_label(metadata)
    response_actor = _response_model_label(metadata) if role == "assistant" else ""
    return prompt_actor, response_actor


def _ledger_entries_from_history_items(history: list[dict[str, Any]], *, fallback_ledger_id: str = "") -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for item in history:
        if not isinstance(item, dict):
            continue
        coord = str(item.get("coordinate") or "").strip()
        metadata = _as_dict(item.get("metadata"))
        coord_meta = _as_dict(item.get("coord_meta"))
        if not coord_meta:
            coord_meta = _as_dict(metadata.get("coord_meta"))
        if not coord_meta:
            runtime_identity = _as_dict(metadata.get("runtime_identity"))
            if runtime_identity:
                coord_meta = {
                    "coord": coord,
                    "coord_type": str(runtime_identity.get("coord_type") or "").strip() or None,
                    "identifier": str(runtime_identity.get("identifier") or item.get("entry_id") or "").strip() or None,
                    "runtime_namespace": str(runtime_identity.get("runtime_namespace") or fallback_ledger_id).strip() or fallback_ledger_id,
                    "canonical_subject": str(runtime_identity.get("ledger_canonical_subject") or "").strip() or None,
                    "canonical_subject_source": str(runtime_identity.get("ledger_canonical_subject_source") or "did:web:ledger").strip() or "did:web:ledger",
                }
        namespace = str(coord_meta.get("runtime_namespace") or fallback_ledger_id).strip() or fallback_ledger_id
        identifier = str(coord_meta.get("identifier") or item.get("entry_id") or "").strip()
        if coord and ":" in coord and (not namespace or not identifier):
            namespace_from_coord, identifier_from_coord = coord.rsplit(":", 1)
            namespace = namespace or namespace_from_coord
            identifier = identifier or identifier_from_coord
        if not namespace or not identifier:
            continue
        role = str(item.get("role") or metadata.get("role") or "").strip()
        content = str(item.get("content") or "").strip()
        if role and "role" not in metadata:
            metadata["role"] = role
        if content and "content" not in metadata:
            metadata["content"] = content
        if coord and "coord" not in metadata:
            metadata["coord"] = coord
        entries.append(
            {
                "key": {"namespace": namespace, "identifier": identifier},
                "created_at": str(item.get("timestamp") or ""),
                "coordinate": coord,
                "coord_meta": coord_meta or None,
                "state": {"metadata": metadata},
            }
        )
    return entries


def _normalize_ledger_entry_rows(entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    seen_keys: set[tuple[str, str, str]] = set()
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        metadata = _ledger_entry_metadata(entry)
        coord = _ledger_entry_coord(entry)
        key = _as_dict(entry.get("key"))
        ledger_id = str(key.get("namespace") or entry.get("namespace") or "").strip()
        entry_id = str(key.get("identifier") or entry.get("identifier") or "").strip()
        if not ledger_id or not entry_id:
            continue
        dedupe_key = (coord, ledger_id, entry_id)
        if dedupe_key in seen_keys:
            continue
        seen_keys.add(dedupe_key)
        kind = _ledger_entry_kind(metadata, entry)
        role = str(metadata.get("role") or "").strip().lower()
        coord_meta = _as_dict(entry.get("coord_meta"))
        runtime_namespace = str(coord_meta.get("runtime_namespace") or ledger_id).strip() or ledger_id
        canonical_subject = str(coord_meta.get("canonical_subject") or _canonical_entity_subject("ledger", ledger_id)).strip() or _canonical_entity_subject("ledger", ledger_id)
        canonical_subject_source = str(coord_meta.get("canonical_subject_source") or "did:web:ledger").strip() or "did:web:ledger"
        display_label = str(metadata.get("ledger_name") or metadata.get("display_label") or runtime_namespace).strip() or runtime_namespace
        raw_actor = str(
            metadata.get("actor_did")
            or metadata.get("principal_did")
            or metadata.get("guardian_did")
            or metadata.get("issuer")
            or "ledger-service"
        ).strip()
        prompt_actor_label, response_actor_label = _ledger_entry_attribution(metadata, role=role)
        actor = prompt_actor_label or raw_actor
        content = _ledger_entry_content(metadata, entry)
        if len(content) > 160:
            content = f"{content[:157]}..."
        if kind in {"chat", "wx"}:
            if role == "assistant":
                summary = f"Chat response committed to {canonical_subject}"
            elif role == "user":
                summary = f"Chat prompt committed to {canonical_subject}"
            else:
                summary = f"Chat turn committed to {canonical_subject}"
        else:
            summary = f"Ledger entry committed to {canonical_subject}"
        if content:
            summary = f"{summary}: {content}"
        rows.append(
            _finalize_activity_row(
                {
                    "timestamp": _ledger_entry_timestamp(entry, metadata),
                    "row_kind": "event",
                    "event_type": "ledger.entry",
                    "event_group": "ledger",
                    "type_label": "Ledger Entry",
                    "entity_type": "ledger",
                    "entity_id": ledger_id,
                    "entity_label": "Ledger",
                    "canonical_subject": canonical_subject,
                    "canonical_subject_source": canonical_subject_source,
                    "display_label": display_label,
                    "ledger_id": ledger_id,
                    "coord": coord,
                    "reference": _activity_reference(coord=coord, ledger_id=ledger_id, entity_id=ledger_id),
                    "status": role or kind or "committed",
                    "summary": summary,
                    "actor": actor,
                    "details": {
                        **metadata,
                        "entry_id": entry_id,
                        "ledger_id": ledger_id,
                        "runtime_namespace": runtime_namespace,
                        "canonical_subject": canonical_subject,
                        "canonical_subject_source": canonical_subject_source,
                        "coord_meta": coord_meta or None,
                        "display_label": display_label,
                        "coord": coord,
                        "content_preview": content,
                        "prompt_principal_label": prompt_actor_label,
                        "response_model_label": response_actor_label,
                        "delegated_prompt_path": _delegated_prompt_details(metadata),
                        "raw_actor": raw_actor,
                    },
                    "open_href": f"/activity?q={quote(coord or entry_id, safe='')}",
                }
            )
        )
    return rows


def _chip_tone(value: str) -> str:
    normalized = value.strip().lower()
    if normalized in {"active", "ok", "approved", "accepted", "success", "ready"}:
        return "ok"
    if normalized in {"removed", "failed", "error", "degraded", "revoked", "blocked"}:
        return "warn"
    return ""


def _activity_reference(
    *,
    coord: str = "",
    submission_ref: str = "",
    entity_id: str = "",
    principal_did: str = "",
    ledger_id: str = "",
) -> str:
    for candidate in (coord, submission_ref, entity_id, principal_did, ledger_id):
        text = str(candidate or "").strip()
        if text:
            return text
    return ""


def _activity_entity_href(entity_type: str, entity_id: str) -> str:
    normalized_type = str(entity_type or "").strip().lower()
    normalized_id = str(entity_id or "").strip()
    if normalized_type == "ledger" and normalized_id:
        return f"/ledgers/{quote(normalized_id, safe='')}"
    if normalized_type == "principal" and normalized_id:
        return f"/principals/{quote(normalized_id, safe='')}"
    if normalized_type == "surface" and normalized_id:
        return f"/surfaces/{quote(normalized_id, safe='')}"
    if normalized_type in {"provider", "binding", "relationship"} and normalized_id:
        return f"/connections?q={quote(normalized_id, safe='')}"
    if normalized_type == "submission" and normalized_id:
        return f"/submissions?submission_ref={quote(normalized_id, safe='')}"
    return ""


def _activity_open_href(entity_type: str, entity_id: str, reference: str) -> str:
    entity_href = _activity_entity_href(entity_type, entity_id)
    if entity_href:
        return entity_href
    if reference:
        return f"/activity?q={quote(reference, safe='')}"
    return "/activity"


def _activity_segment(row: dict[str, Any]) -> str:
    row_kind = str(row.get("row_kind") or "").strip().lower()
    if row_kind in {"event", "record", "governance"}:
        return row_kind
    return "event"


def _activity_feed_class(row: dict[str, Any]) -> str:
    segment = _activity_segment(row)
    if segment == "record":
        return "identity"
    return "interaction"


def _activity_scope_matches(row: dict[str, Any], scope: str) -> bool:
    normalized_scope = str(scope or "").strip().lower()
    if normalized_scope in {"interaction", "interactions"}:
        normalized_scope = "event"
    if normalized_scope in {"identity", "identities"}:
        normalized_scope = "record"
    if not normalized_scope or normalized_scope == "all":
        return True
    if normalized_scope == "shared":
        return bool(row.get("share_ready"))
    return _activity_segment(row) == normalized_scope


def _activity_row_timestamp(row: dict[str, Any]) -> datetime:
    return _timestamp_from_value(row.get("timestamp"))


def _activity_when_sort_key(
    row: dict[str, Any],
    *,
    prioritize_interactions: bool,
    reverse_sort: bool,
) -> tuple[int, datetime]:
    feed_rank = 0
    if prioritize_interactions:
        is_interaction = _activity_feed_class(row) != "identity"
        feed_rank = 1 if (is_interaction and reverse_sort) or (not is_interaction and not reverse_sort) else 0
    return (feed_rank, _activity_row_timestamp(row))


def _activity_sort_value(row: dict[str, Any], field: str) -> str:
    normalized = str(field or "").strip().lower()
    if normalized == "when":
        return str(row.get("timestamp") or "")
    if normalized in {"name", "display_label"}:
        return str(row.get("display_label") or row.get("canonical_subject") or "")
    if normalized == "type":
        return str(row.get("type_label") or row.get("row_kind") or "")
    if normalized in {"event", "summary"}:
        return str(row.get("summary") or "")
    if normalized == "entity":
        return str(row.get("entity_label") or row.get("entity_type") or "")
    if normalized == "status":
        return str(row.get("status") or "")
    return str(row.get("summary") or "")


def _activity_governance_summary(submission: dict[str, Any]) -> str:
    mutation_kind = str(submission.get("mutation_kind") or "mutation").strip() or "mutation"
    status = str(submission.get("submission_status") or submission.get("status") or "submitted").strip() or "submitted"
    reviewer = str(submission.get("reviewed_by_principal_id") or "").strip()
    reason = str(
        submission.get("reviewer_note")
        or submission.get("failure_reason")
        or submission.get("failure_code")
        or submission.get("reason")
        or submission.get("reason_code")
        or ""
    ).strip()
    summary = f"{mutation_kind} · {status}"
    if reviewer:
        summary += f" · reviewer {reviewer}"
    if reason:
        summary += f" · {reason}"
    return summary


def _activity_query_href(base_params: dict[str, str], **overrides: str) -> str:
    params = dict(base_params)
    for key, value in overrides.items():
        text = str(value or "").strip()
        if text:
            params[key] = text
        else:
            params.pop(key, None)
    return f"/activity?{urlencode(params)}" if params else "/activity"


def _activity_detail_fields(row: dict[str, Any]) -> list[tuple[str, str]]:
    detail_fields: list[tuple[str, str]] = []
    details = _as_dict(row.get("details"))
    delegated = _as_dict(details.get("delegated_prompt_path"))
    integrity = _answer_surface_integrity_details(details)
    for label, value in (
        ("What happened", row.get("summary")),
        ("Event type", row.get("event_type")),
        ("Entity type", row.get("entity_type")),
        ("Entity ID", row.get("entity_id")),
        ("Status", row.get("status")),
        ("Actor", row.get("actor")),
        ("Asked by", details.get("prompt_principal_label")),
        ("Answered by", details.get("response_model_label")),
        ("Answer integrity", integrity.get("status")),
        ("Requested by", delegated.get("requested_by_principal_did")),
        ("Timestamp", row.get("timestamp")),
        ("COORD", row.get("coord")),
        ("Ledger", row.get("ledger_id")),
        ("Target surface", delegated.get("target_surface_id")),
        ("Canonical subject", row.get("canonical_subject")),
        ("Subject source", row.get("canonical_subject_source")),
        ("Display label", row.get("display_label")),
        ("Reference", row.get("reference")),
        ("Runtime namespace", details.get("runtime_namespace")),
        ("Event group", row.get("event_group")),
        ("Submission ref", row.get("submission_ref")),
        ("Mutation kind", row.get("mutation_kind")),
        ("Permission scope", row.get("permission_scope")),
        ("Enabled state", row.get("enabled_state")),
        ("Evidence ref", row.get("evidence_ref")),
        ("Provenance ref", row.get("provenance_ref")),
        ("Standing envelope", row.get("standing_envelope_ref")),
        ("Credential ref", row.get("credential_ref")),
        ("Wallet provider", row.get("wallet_provider")),
    ):
        text = str(value or "").strip()
        if text:
            detail_fields.append((label, text))
    return detail_fields


def _activity_detail_sections(row: dict[str, Any]) -> list[tuple[str, list[tuple[str, str]]]]:
    details = _as_dict(row.get("details"))
    delegated = _as_dict(details.get("delegated_prompt_path"))
    integrity = _answer_surface_integrity_details(details)
    sections: list[tuple[str, list[tuple[str, str]]]] = []

    overview_fields = _activity_detail_fields(row)
    if overview_fields:
        sections.append(("Overview", overview_fields))

    attribution_fields: list[tuple[str, str]] = []
    contributor = _as_dict(details.get("contributor"))
    for label, value in (
        ("Asked by", details.get("prompt_principal_label")),
        ("Answered by", details.get("response_model_label")),
        ("Prompt principal DID", contributor.get("principal_did")),
        ("Prompt principal type", contributor.get("principal_type")),
        ("Prompt principal ID", contributor.get("principal_id")),
        ("Response model", details.get("model_id")),
        ("Response provider", details.get("provider_id")),
    ):
        text = str(value or "").strip()
        if text:
            attribution_fields.append((label, text))
    if attribution_fields:
        sections.append(("Attribution", attribution_fields))

    delegation_fields: list[tuple[str, str]] = []
    for label, value in (
        ("Delegation mode", delegated.get("delegation_mode")),
        ("Audit posture", delegated.get("audit_posture")),
        ("Requested by", delegated.get("requested_by_principal_did")),
        ("Prompt principal DID", delegated.get("prompt_principal_did")),
        ("Prompt principal ID", delegated.get("prompt_principal_id")),
        ("Target ledger", delegated.get("target_ledger_id")),
        ("Target surface", delegated.get("target_surface_id")),
        ("Ledger scope", ", ".join(str(item).strip() for item in _as_list(delegated.get("ledger_scope")) if str(item).strip())),
        ("Surface scope", ", ".join(str(item).strip() for item in _as_list(delegated.get("surface_scope")) if str(item).strip())),
        ("Delegation expires", delegated.get("expires_at")),
    ):
        text = str(value or "").strip()
        if text:
            delegation_fields.append((label, text))
    if delegated:
        delegation_fields.append(("CLI-requested", "true" if bool(delegated.get("cli_request_required")) else "false"))
    if delegation_fields:
        sections.append(("Delegation", delegation_fields))

    answer_integrity_fields: list[tuple[str, str]] = []
    for label, value in (
        ("Status", integrity.get("status")),
        ("Reason", integrity.get("reason")),
        ("Visible answer preview", integrity.get("visible_answer_preview")),
        ("Committed summary preview", integrity.get("committed_summary_preview")),
        ("Summary source", integrity.get("summary_source")),
    ):
        text = str(value or "").strip()
        if text:
            answer_integrity_fields.append((label, text))
    if answer_integrity_fields:
        sections.append(("Answer Integrity", answer_integrity_fields))

    governance_fields: list[tuple[str, str]] = []
    applied_result = _as_dict(details.get("applied_result"))
    applied_result_text = json.dumps(applied_result, sort_keys=True) if applied_result else ""
    for label, value in (
        ("Submission ref", row.get("submission_ref") or details.get("submission_ref")),
        ("Mutation kind", row.get("mutation_kind") or details.get("mutation_kind")),
        ("Execution mode", details.get("execution_mode")),
        ("Submission status", details.get("submission_status") or row.get("status")),
        ("Reason", details.get("reviewer_note") or details.get("failure_reason") or details.get("failure_code") or details.get("reason") or details.get("reason_code")),
        ("Reviewer", details.get("reviewed_by_principal_id")),
        ("Reviewed at", details.get("reviewed_at")),
        ("Mutation ref", details.get("mutation_ref")),
        ("Applied result", applied_result_text),
    ):
        text = str(value or "").strip()
        if text:
            governance_fields.append((label, text))
    if governance_fields:
        sections.append(("Governance", governance_fields))

    permission_payload = details.get("permission_payload")
    permission_payload_text = ""
    if isinstance(permission_payload, dict) and permission_payload:
        permission_payload_text = json.dumps(permission_payload, sort_keys=True)
    elif permission_payload:
        permission_payload_text = str(permission_payload).strip()
    access_fields: list[tuple[str, str]] = []
    for label, value in (
        ("Permission scope", row.get("permission_scope") or details.get("permission_scope")),
        ("Enabled state", row.get("enabled_state") or details.get("enabled_state")),
        ("Permission payload", permission_payload_text),
        ("Start at", details.get("start_at") or details.get("start_date")),
        ("End at", details.get("end_at") or details.get("end_date")),
        ("Target path", details.get("target_path")),
    ):
        text = str(value or "").strip()
        if text:
            access_fields.append((label, text))
    if access_fields:
        sections.append(("Access", access_fields))

    provenance_fields: list[tuple[str, str]] = []
    standing = _as_dict(details.get("standing_view"))
    for label, value in (
        ("COORD", row.get("coord") or details.get("coord")),
        ("Reference", row.get("reference")),
        ("Evidence ref", row.get("evidence_ref") or details.get("evidence_ref")),
        ("Provenance ref", row.get("provenance_ref") or details.get("provenance_ref")),
        ("Evidence manifest", details.get("evidence_manifest_ref") or standing.get("evidence_manifest_ref")),
        ("Standing envelope", row.get("standing_envelope_ref") or details.get("standing_envelope_ref") or standing.get("standing_envelope_ref")),
        ("Credential ref", row.get("credential_ref") or details.get("credential_ref") or standing.get("credential_ref")),
    ):
        text = str(value or "").strip()
        if text:
            provenance_fields.append((label, text))
    if provenance_fields:
        sections.append(("Provenance", provenance_fields))

    standing_fields: list[tuple[str, str]] = []
    sanctions = details.get("active_sanctions") or standing.get("active_sanctions")
    sanctions_text = ""
    if isinstance(sanctions, list) and sanctions:
        sanctions_text = ", ".join(str(item) for item in sanctions if str(item).strip())
    elif sanctions:
        sanctions_text = str(sanctions).strip()
    for label, value in (
        ("Trust class", details.get("trust_class") or standing.get("trust_class")),
        ("Posture class", details.get("posture_class") or standing.get("posture_class")),
        ("Probation status", details.get("probation_status") or standing.get("probation_status")),
        ("Validation status", details.get("current_validation_status") or standing.get("current_validation_status")),
        ("Authority subject", details.get("authority_subject_id") or standing.get("authority_subject_id")),
        ("Active sanctions", sanctions_text),
    ):
        text = str(value or "").strip()
        if text:
            standing_fields.append((label, text))
    if standing_fields:
        sections.append(("Standing", standing_fields))

    return sections


def _activity_share_bundle(row: dict[str, Any]) -> tuple[str, bool, str]:
    details = _as_dict(row.get("details"))
    standing = _as_dict(details.get("standing_view"))
    candidates: list[tuple[str, str]] = [
        ("coord", str(row.get("coord") or details.get("coord") or "").strip()),
        ("submission_ref", str(row.get("submission_ref") or details.get("submission_ref") or "").strip()),
        ("evidence_ref", str(row.get("evidence_ref") or details.get("evidence_ref") or "").strip()),
        ("provenance_ref", str(row.get("provenance_ref") or details.get("provenance_ref") or "").strip()),
        (
            "standing_envelope_ref",
            str(row.get("standing_envelope_ref") or details.get("standing_envelope_ref") or standing.get("standing_envelope_ref") or "").strip(),
        ),
        ("credential_ref", str(row.get("credential_ref") or details.get("credential_ref") or standing.get("credential_ref") or "").strip()),
        ("principal_did", str(details.get("principal_did") or row.get("entity_id") if str(row.get("entity_type") or "").strip().lower() == "principal" else "").strip()),
    ]
    for reason, value in candidates:
        if value:
            return value, True, reason
    fallback = str(row.get("reference") or "").strip()
    return fallback, False, ""


def _activity_badges(row: dict[str, Any]) -> list[str]:
    details = _as_dict(row.get("details"))
    standing = _as_dict(details.get("standing_view"))
    badges: list[str] = []
    feed_class = _activity_feed_class(row)
    if feed_class == "identity":
        badges.append("identity")
    else:
        badges.append("interaction")
    if bool(row.get("share_ready")):
        badges.append("share-ready")
    if str(row.get("row_kind") or "").strip().lower() == "governance":
        badges.append("governance")
    if (
        str(row.get("permission_scope") or details.get("permission_scope") or "").strip()
        or bool(details.get("permission_payload"))
        or str(row.get("enabled_state") or details.get("enabled_state") or "").strip()
    ):
        badges.append("permissioned")
    if any(
        str(value or "").strip()
        for value in (
            row.get("evidence_ref"),
            row.get("provenance_ref"),
            row.get("standing_envelope_ref"),
            row.get("credential_ref"),
            details.get("trust_class"),
            details.get("posture_class"),
            details.get("current_validation_status"),
            standing.get("trust_class"),
            standing.get("posture_class"),
            standing.get("current_validation_status"),
        )
    ):
        badges.append("trust-bearing")
    return badges


def _activity_raw_source(row: dict[str, Any]) -> str:
    row_kind = str(row.get("row_kind") or "").strip().lower()
    details = _as_dict(row.get("details"))
    if row_kind == "governance":
        return "control_plane_submission"
    if row_kind == "event":
        return "dashboard_event_stream"
    if row_kind == "record":
        if details.get("coord_meta") or str(row.get("type_label") or "").strip().lower() == "ledger entry":
            return "ledger_history"
        return "dashboard_record_projection"
    return "dashboard_activity_projection"


def _activity_kind(row: dict[str, Any]) -> str:
    row_kind = str(row.get("row_kind") or "").strip().lower()
    if row_kind in {"event", "record", "governance"}:
        return row_kind
    return "event"


def _activity_type_value(row: dict[str, Any]) -> str:
    return str(
        row.get("event_type")
        or row.get("type_label")
        or row.get("entity_type")
        or _activity_kind(row)
    ).strip()


def _activity_open_target(row: dict[str, Any]) -> str:
    target = str(row.get("open_href") or "").strip()
    if target:
        return target
    entity_type = str(row.get("entity_type") or "").strip()
    entity_id = str(row.get("entity_id") or "").strip()
    reference = str(row.get("reference") or "").strip()
    return _activity_open_href(entity_type, entity_id, reference)


def _activity_contract_row(row: dict[str, Any]) -> dict[str, Any]:
    normalized = dict(row)
    details = _as_dict(normalized.get("details"))
    kind = _activity_kind(normalized)
    normalized["kind"] = kind
    normalized["type"] = _activity_type_value(normalized)
    normalized["shareable"] = bool(normalized.get("share_ready"))
    normalized["open_target"] = _activity_open_target(normalized)
    normalized["raw_source"] = _activity_raw_source(normalized)
    normalized["details"] = details
    normalized.setdefault("reference", str(normalized.get("preferred_reference") or "").strip())
    normalized.setdefault("coord", str(details.get("coord") or "").strip())
    normalized.setdefault("ledger_id", str(details.get("ledger_id") or "").strip())
    return normalized


def _finalize_activity_row(row: dict[str, Any]) -> dict[str, Any]:
    row["canonical_subject"] = _rewrite_legacy_did_web_host(row.get("canonical_subject"))
    row["details"] = _as_dict(_rewrite_legacy_did_web_host(row.get("details")))
    preferred_reference, share_ready, share_reason = _activity_share_bundle(row)
    if not str(row.get("reference") or "").strip():
        row["reference"] = preferred_reference
    row["preferred_reference"] = preferred_reference
    row["share_ready"] = share_ready
    row["share_reason"] = share_reason
    row["badges"] = _activity_badges(row)
    return _activity_contract_row(row)


def _activity_collapsed_hint(row: dict[str, Any]) -> str:
    details = _as_dict(row.get("details"))
    delegated = _as_dict(details.get("delegated_prompt_path"))
    integrity = _answer_surface_integrity_details(details)
    parts: list[str] = []
    prompt_principal_label = str(details.get("prompt_principal_label") or "").strip()
    response_model_label = str(details.get("response_model_label") or "").strip()
    if prompt_principal_label:
        parts.append(f"asked by: {prompt_principal_label}")
    if response_model_label:
        parts.append(f"answered by: {response_model_label}")
    integrity_status = str(integrity.get("status") or "").strip().lower()
    integrity_reason = str(integrity.get("reason") or "").strip().lower()
    if integrity_status == "diverged" and integrity_reason == "assembly_summary_richer_than_visible_answer":
        parts.append("summary richer than visible answer")
    elif integrity_status == "collapsed" and integrity_reason == "visible_answer_preamble_collapse_under_blocked_context":
        parts.append("visible answer collapsed under blocked context")
    requested_by = str(delegated.get("requested_by_principal_did") or "").strip()
    if requested_by:
        parts.append(f"requested by: {requested_by}")
    target_surface = str(delegated.get("target_surface_id") or "").strip()
    if target_surface:
        parts.append(f"surface: {target_surface}")
    runtime_namespace = str(details.get("runtime_namespace") or "").strip()
    canonical_subject = str(row.get("canonical_subject") or details.get("canonical_subject") or "").strip()
    if runtime_namespace and canonical_subject:
        parts.append(f"runtime: {runtime_namespace}")
    relationship_type = str(details.get("relationship_type") or "").strip()
    if relationship_type:
        parts.append(f"relationship: {relationship_type}")
    permission_scope = str(row.get("permission_scope") or details.get("permission_scope") or "").strip()
    if permission_scope:
        parts.append(f"scope: {permission_scope}")
    permission_payload = details.get("permission_payload")
    if isinstance(permission_payload, dict) and permission_payload:
        parts.append(f"permissions: {', '.join(sorted(str(key) for key in permission_payload.keys())[:3])}")
    execution_mode = str(details.get("execution_mode") or "").strip()
    if execution_mode:
        parts.append(f"mode: {execution_mode}")
    submission_status = str(details.get("submission_status") or "").strip()
    if submission_status:
        parts.append(f"submission: {submission_status}")
    reviewer = str(details.get("reviewed_by_principal_id") or "").strip()
    if reviewer:
        parts.append(f"reviewer: {reviewer}")
    reviewer_note = str(
        details.get("reviewer_note")
        or details.get("failure_reason")
        or details.get("failure_code")
        or details.get("reason")
        or details.get("reason_code")
        or ""
    ).strip()
    if reviewer_note:
        parts.append(f"reason: {reviewer_note}")
    trust_class = str(details.get("trust_class") or _as_dict(details.get("standing_view")).get("trust_class") or "").strip()
    posture_class = str(details.get("posture_class") or _as_dict(details.get("standing_view")).get("posture_class") or "").strip()
    if trust_class or posture_class:
        parts.append(" / ".join(value for value in (trust_class, posture_class) if value))
    return " · ".join(parts[:3])


def _activity_target_href(row: dict[str, Any]) -> str:
    details = _as_dict(row.get("details"))
    target_entity_type = str(details.get("target_entity_type") or "").strip().lower()
    target_entity_id = str(details.get("target_entity_id") or "").strip()
    if target_entity_type and target_entity_id:
        return _activity_entity_href(target_entity_type, target_entity_id)
    return ""


def _activity_reference_label(row: dict[str, Any]) -> str:
    reason = str(row.get("share_reason") or "").strip().lower()
    labels = {
        "coord": "COORD",
        "submission_ref": "Submission Ref",
        "evidence_ref": "Evidence Ref",
        "provenance_ref": "Provenance Ref",
        "standing_envelope_ref": "Standing Envelope",
        "credential_ref": "Credential Ref",
        "principal_did": "Principal DID",
    }
    if reason:
        return labels.get(reason, reason.replace("_", " ").title())
    if str(row.get("reference") or "").strip():
        return "Reference"
    return ""


def _activity_empty_state_message(
    *,
    activity_scope: str,
    tag_filter: str,
    reference_filter: str,
    recent_period: str,
    date_from_filter: str,
    date_to_filter: str,
    entity_type_filter: str,
    status_filter: str,
    ledger_filter: str,
    actor_filter: str,
    text_filter: str,
) -> str:
    filters: list[str] = []
    if activity_scope and activity_scope != "all":
        filters.append(f"scope '{activity_scope}'")
    if tag_filter:
        filters.append(f"tag '{tag_filter}'")
    if reference_filter:
        filters.append(f"reference '{reference_filter}'")
    if recent_period:
        filters.append(f"window '{recent_period}'")
    if date_from_filter or date_to_filter:
        filters.append("date range")
    if entity_type_filter:
        filters.append(f"entity type '{entity_type_filter}'")
    if status_filter:
        filters.append(f"status '{status_filter}'")
    if ledger_filter:
        filters.append(f"ledger '{ledger_filter}'")
    if actor_filter:
        filters.append(f"actor '{actor_filter}'")
    if text_filter:
        filters.append(f"search '{text_filter}'")
    if not filters:
        return "No activity is available yet."
    return f"No activity rows match {', '.join(filters)}."


def _activity_row_matches_filters(
    row: dict[str, Any],
    *,
    activity_scope: str,
    entity_type_filter: str,
    actor_filter: str,
    status_filter: str,
    ledger_filter: str,
    tag_filter: str,
    reference_filter: str,
    date_from_dt: datetime | None,
    date_to_dt: datetime | None,
    recent_days: int | None,
    now: datetime,
    text_filter: str,
) -> bool:
    ts = _activity_row_timestamp(row)
    segment = _activity_segment(row)
    if not _activity_scope_matches(row, activity_scope):
        return False
    if entity_type_filter and str(row.get("entity_type") or "").strip().lower() != entity_type_filter:
        return False
    if actor_filter and actor_filter not in str(row.get("actor") or "").strip().lower():
        return False
    if status_filter and status_filter != str(row.get("status") or "").strip().lower():
        return False
    if ledger_filter and ledger_filter != str(row.get("ledger_id") or "").strip().lower():
        return False
    if tag_filter and tag_filter not in {str(badge or "").strip().lower() for badge in _as_list(row.get("badges"))}:
        return False
    if reference_filter and reference_filter != str(row.get("share_reason") or "").strip().lower():
        return False
    if date_from_dt and ts < date_from_dt:
        return False
    if date_to_dt and ts > date_to_dt:
        return False
    if recent_days is not None and ts < (now - timedelta(days=recent_days)):
        return False
    if text_filter:
        haystack = " ".join(
            [
                str(row.get("summary") or ""),
                str(row.get("details") or ""),
                str(row.get("entity_id") or ""),
                str(row.get("entity_type") or ""),
                str(row.get("reference") or ""),
                str(row.get("actor") or ""),
                str(row.get("coord") or ""),
                str(row.get("submission_ref") or ""),
            ]
        ).lower()
        if text_filter not in haystack:
            return False
    return True


def _normalize_event_rows(events: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for event in events:
        entity_type = str(event.get("entity_type") or "event").strip().lower()
        entity_id = str(event.get("entity_id") or "").strip()
        ledger_id = str(event.get("ledger_id") or "").strip()
        coord = str(event.get("coord") or "").strip()
        details = _as_dict(event.get("details"))
        canonical_subject = str(
            event.get("canonical_subject")
            or details.get("canonical_subject")
            or _canonical_entity_subject(entity_type, entity_id)
        ).strip()
        canonical_subject_source = str(
            event.get("canonical_subject_source")
            or details.get("canonical_subject_source")
            or ("principal_did" if entity_type == "principal" else f"did:web:{entity_type}")
        ).strip()
        display_label = str(
            event.get("display_label")
            or details.get("display_label")
            or details.get("display_name")
            or details.get("ledger_name")
            or details.get("label")
            or details.get("name")
            or entity_id
        ).strip() or entity_id
        principal_did = str(details.get("principal_did") or entity_id if entity_type == "principal" else "").strip()
        reference = _activity_reference(
            coord=coord,
            entity_id=entity_id,
            principal_did=principal_did,
            ledger_id=ledger_id,
        )
        rows.append(
            _finalize_activity_row(
                {
                "row_kind": "event",
                "timestamp": str(event.get("timestamp") or ""),
                "type_label": str(event.get("event_type") or "event").strip() or "event",
                "summary": str(event.get("summary") or "").strip() or "Activity event",
                "entity_type": entity_type or "event",
                "entity_id": entity_id,
                "entity_label": str(event.get("entity_type") or "event").strip() or "event",
                "canonical_subject": canonical_subject,
                "canonical_subject_source": canonical_subject_source,
                "display_label": display_label,
                "reference": reference,
                "preferred_reference": reference,
                "actor": str(event.get("actor") or "").strip() or "system",
                "status": str(event.get("status") or "unknown").strip() or "unknown",
                "coord": coord,
                "ledger_id": ledger_id,
                "event_type": str(event.get("event_type") or "").strip(),
                "event_group": str(event.get("event_group") or "").strip(),
                "details": details,
                "open_href": _activity_open_href(entity_type, entity_id, reference),
                }
            )
        )
    return rows


def _normalize_record_rows(
    principals: list[dict[str, Any]],
    connection_context: _ConnectionLookupContext,
    control_plane_state: dict[str, Any],
) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for ledger in connection_context.get("ledgers", []):
        ledger_id = str(ledger.get("ledger_id") or "").strip()
        if not ledger_id:
            continue
        canonical_subject = _entity_trust_identifier("ledger", ledger_id, ledger)
        display_label = str(ledger.get("ledger_name") or ledger.get("display_name") or ledger_id).strip() or ledger_id
        coord = str(ledger.get("coord") or "").strip()
        reference = _activity_reference(coord=coord, entity_id=ledger_id, ledger_id=ledger_id)
