async def account_setup_page(request: Request) -> Response:
    # DSS-014: wizard entry integration
    query_params = request.query_params
    if str(query_params.get("start") or "").strip().lower() == "wizard":
        return RedirectResponse(url="/wizard", status_code=307)

    # Try to determine if user has an account/signup
    identity_card = await _build_identity_card(request)
    identity_vc = _as_dict(identity_card.get("identity_vc"))
    principal_did = str(identity_vc.get("principal_did") or "").strip()
    is_authenticated = bool(principal_did and identity_vc.get("verified"))

    if not is_authenticated:
        # Unauthenticated users see wizard entry CTA
        return HTMLResponse(
            _layout(
                "Account Setup | DSS Control Plane",
                f"""
                <div class="page-header" style="text-align:center; max-width:560px; margin:0 auto;">
                    <h1>Account Setup</h1>
                    <p class="muted">Get started with DSS Control Plane.</p>
                </div>
                <div class="card" style="max-width:520px; margin:0 auto; text-align:center;">
                    <h2>Request Access</h2>
                    <p>New to DSS? Complete the Account Setup Wizard to request access.</p>
                    <a class="btn primary" href="/wizard" style="margin:8px;">Start Account Setup Wizard</a>
                    <p class="muted" style="margin-top:16px;">Already have access?</p>
                    <a class="btn" href="/login?next=/account/setup" style="margin:8px;">Sign In</a>
                </div>
                """,
            ),
            status_code=200,
        )

    # Authenticated user — check if they have an account via backend
    status_code, body = await _auth_proxy_get("/account/current", headers={"x-principal-id": principal_did})
    has_account = status_code < 400 and isinstance(body, dict) and body.get("status") == "ok"

    if not has_account:
        # Authenticated but no account yet — show wizard CTA
        return HTMLResponse(
            _layout(
                "Account Setup | DSS Control Plane",
                f"""
                <div class="page-header" style="text-align:center; max-width:560px; margin:0 auto;">
                    <h1>Account Setup</h1>
                    <p class="muted">Complete your account setup to access DSS features.</p>
                </div>
                <div class="card" style="max-width:520px; margin:0 auto; text-align:center;">
                    <h2>Finish Account Setup</h2>
                    <p>Your identity is verified but your account setup is not complete.</p>
                    <a class="btn primary" href="/wizard" style="margin:8px;">Start Account Setup Wizard</a>
                    <p class="muted" style="margin-top:12px; font-size:0.85rem;">If you have already submitted a request, please wait for operator approval.</p>
                </div>
                """,
                profile_name=_profile_name_from_identity_card(identity_vc),
            ),
            status_code=200,
        )

    # Authenticated with account — redirect to canonical settings checklist
    return RedirectResponse(url="/settings#account-setup-checklist", status_code=303)


async def account_setup_documents_page(request: Request) -> Response:
    """Authenticated document upload step for onboarding."""
    identity_card, redirect = await _require_control_plane_auth(request)
    if redirect is not None:
        return redirect
    profile_name = _profile_name_from_identity_card(identity_card)
    current_principal_did = str(_as_dict(identity_card).get("principal_did") or "").strip()
    context = await _load_connection_lookup_context(request, identity_card=identity_card)
    ledgers = context.get("ledgers") or []
    user_ledgers = [
        item for item in ledgers
        if isinstance(item, dict) and _is_valid_material_ledger_id(item.get("ledger_id"))
    ]
    if not user_ledgers:
        return HTMLResponse(
            _layout_with_nav(
                "Document Upload | DSS Control Plane",
                f"""
                <div class="page-header" style="text-align:center; max-width:560px; margin:0 auto;">
                    <h1>Seed Ledger Documents</h1>
                    <p class="muted">Upload foundational documents to your ledger.</p>
                </div>
                <div class="card" style="max-width:520px; margin:0 auto; text-align:center;">
                    <p class="muted">No ledgers are available yet. Complete provisioning first.</p>
                    <a class="btn" href="/settings">Back to Setup</a>
                </div>
                """,
                "/account/setup/documents",
                profile_name=profile_name,
            ),
            status_code=200,
        )

    control_plane_state = _load_control_plane_state()
    sources_data = _source_records_from_state(control_plane_state)
    source_jobs_data = _source_jobs_from_state(control_plane_state)

    ledger_cards = []
    for ledger in user_ledgers[:3]:
        ledger_id = str(ledger.get("ledger_id") or "").strip()
        ledger_name = str(ledger.get("ledger_name") or ledger_id).strip()
        ledger_sources = [s for s in sources_data if str(s.get("ledger_id") or "").strip() == ledger_id]
        recent_jobs = [j for j in source_jobs_data if str(j.get("ledger_id") or "").strip() == ledger_id][:2]
        latest_job = recent_jobs[0] if recent_jobs else None
        latest_status = str(latest_job.get("status") or "idle").title() if isinstance(latest_job, dict) else "Idle"

        source_rows = ""
        for src in ledger_sources[:5]:
            fname = str(src.get("file_name") or src.get("original_file_name") or "Unnamed").strip()
            src_status = str(src.get("status") or "queued").strip().title()
            source_rows += f'<li>{html.escape(fname)} — <span class="muted">{html.escape(src_status)}</span></li>'

        source_list = f'<ul style="margin:8px 0; padding-left:18px;">{source_rows}</ul>' if source_rows else '<p class="muted">No documents uploaded yet.</p>'

        card_html = f"""
        <div class="card" style="margin-bottom:18px;">
            <h3>{html.escape(ledger_name)}</h3>
            <p class="muted" style="font-size:0.85rem;"><code>{html.escape(ledger_id)}</code></p>
            {source_list}
            <form class="ledger-doc-upload-form" method="post" action="/api/control-plane/sources/upload" enctype="multipart/form-data" data-ledger-id="{html.escape(ledger_id)}">
                <input type="hidden" name="ledger_id" value="{html.escape(ledger_id)}">
                <input type="hidden" name="principal_did" value="{html.escape(current_principal_did)}">
                <input type="hidden" name="batch_label" value="Onboarding document seed">
                <div style="display:flex; gap:12px; align-items:flex-end; flex-wrap:wrap;">
                    <div style="flex:1; min-width:200px;">
                        <label class="field-label" for="doc-files-{html.escape(ledger_id)}">Select files</label>
                        <input id="doc-files-{html.escape(ledger_id)}" type="file" name="source_files" accept=".txt,.md,.json,.csv,.html,.xml,.pdf,.doc,.docx" multiple required style="width:100%;">
                    </div>
                    <button class="btn primary" type="submit">Upload</button>
                </div>
            </form>
            <div class="ledger-doc-progress" data-ledger-doc-progress="{html.escape(ledger_id)}" style="margin-top:10px; display:none;">
                <div style="background:var(--surface-muted); border-radius:6px; overflow:hidden; height:18px;">
                    <div data-ledger-doc-bar="{html.escape(ledger_id)}" style="width:0%; height:100%; background:var(--ok); transition:width 0.3s;"></div>
                </div>
                <p class="muted" data-ledger-doc-status="{html.escape(ledger_id)}" style="margin-top:6px; font-size:0.85rem;">Preparing upload...</p>
            </div>
            {f'<p class="muted" style="margin-top:8px; font-size:0.85rem;">Latest job status: {html.escape(latest_status)}.</p>' if latest_job else ''}
        </div>
        """
        ledger_cards.append(card_html)

    page_html = _layout_with_nav(
        "Document Upload | DSS Control Plane",
        f"""
        <div class="page-header" style="text-align:center; max-width:640px; margin:0 auto;">
            <h1>Seed Ledger Documents</h1>
            <p class="muted">Upload foundational documents to your ledger. These become retrievable context for principals and agents.</p>
        </div>
        <div style="max-width:640px; margin:0 auto;">
            {''.join(ledger_cards)}
            <div class="inline-actions" style="justify-content:center; margin-top:8px;">
                <a class="btn" href="/settings">Back to Setup</a>
                <a class="btn primary" href="/connections?type=ledgers">Manage Ledgers</a>
            </div>
        </div>
        <script>
            document.querySelectorAll('.ledger-doc-upload-form').forEach((form) => {{
                form.addEventListener('submit', async (event) => {{
                    event.preventDefault();
                    const ledgerId = form.getAttribute('data-ledger-id') || '';
                    const progressWrap = document.querySelector('[data-ledger-doc-progress="' + ledgerId + '"]');
                    const progressBar = document.querySelector('[data-ledger-doc-bar="' + ledgerId + '"]');
                    const statusNode = document.querySelector('[data-ledger-doc-status="' + ledgerId + '"]');
                    const button = form.querySelector('button[type="submit"]');
                    if (button) button.disabled = true;
                    if (progressWrap) progressWrap.style.display = 'block';
                    if (progressBar) progressBar.style.width = '10%';
                    if (statusNode) statusNode.textContent = 'Uploading documents...';
                    try {{
                        const response = await fetch(form.action, {{
                            method: 'POST',
                            headers: {{ 'accept': 'application/json' }},
                            credentials: 'same-origin',
                            body: new FormData(form),
                        }});
                        const payload = await response.json().catch(() => ({{}}));
                        const job = payload && typeof payload === 'object' ? payload.job : null;
                        if (!response.ok) {{
                            const detail = payload && (payload.detail || payload.error) ? (typeof payload.detail === 'string' ? payload.detail : (payload.detail.reason || payload.detail.error || payload.error)) : 'Upload failed';
                            if (statusNode) statusNode.textContent = 'Unable to queue upload: ' + detail;
                            if (progressBar) progressBar.style.width = '0%';
                            return;
                        }}
                        const jobId = job && job.job_id ? String(job.job_id) : 'unknown';
                        const jobState = job && job.status ? String(job.status) : 'queued';
                        if (jobState === 'completed') {{
                            if (progressBar) progressBar.style.width = '100%';
                            if (statusNode) statusNode.textContent = 'Upload complete. Job ref: ' + jobId + '.';
                            window.setTimeout(() => window.location.reload(), 800);
                            return;
                        }}
                        if (progressBar) progressBar.style.width = '30%';
                        if (statusNode) statusNode.textContent = 'Queued as ' + jobState + '. Job ref: ' + jobId + '.';
                        if (!jobId || jobId === 'unknown') return;
                        const poll = async () => {{
                            try {{
                                const statusResponse = await fetch('/api/control-plane/source-jobs/' + encodeURIComponent(jobId), {{
                                    headers: {{ 'accept': 'application/json' }},
                                    credentials: 'same-origin',
                                }});
                                const statusPayload = await statusResponse.json().catch(() => ({{}}));
                                if (!statusResponse.ok) {{
                                    if (statusNode) statusNode.textContent = 'Status refresh unavailable for job ' + jobId;
                                    return;
                                }}
                                const statusJob = statusPayload && typeof statusPayload === 'object' ? statusPayload.job : null;
                                const nextState = statusJob && statusJob.status ? String(statusJob.status) : 'unknown';
                                const progressDone = parseInt(statusJob && statusJob.progress_done ? String(statusJob.progress_done) : '0', 10);
                                const progressTotal = parseInt(statusJob && statusJob.progress_total ? String(statusJob.progress_total) : '0', 10);
                                const pct = progressTotal > 0 ? Math.max(10, Math.min(95, Math.round((progressDone / progressTotal) * 100))) : 50;
                                if (progressBar) progressBar.style.width = pct + '%';
                                if (nextState === 'queued' || nextState === 'running') {{
                                    if (statusNode) statusNode.textContent = 'Job ' + jobId + ' is ' + nextState + '. Progress ' + progressDone + ' / ' + progressTotal + '.';
                                    window.setTimeout(poll, 1200);
                                    return;
                                }}
                                if (nextState === 'completed') {{
                                    if (progressBar) progressBar.style.width = '100%';
                                    if (statusNode) statusNode.textContent = 'Upload complete. Job ref: ' + jobId + '.';
                                    window.setTimeout(() => window.location.reload(), 800);
                                    return;
                                }}
                                if (nextState === 'failed') {{
                                    const failureMessage = statusJob && statusJob.failure_message ? String(statusJob.failure_message) : '';
                                    if (statusNode) statusNode.textContent = 'Upload failed. Job ref: ' + jobId + '. ' + (failureMessage || 'Review backend job detail.');
                                    if (progressBar) progressBar.style.width = '0%';
                                    return;
                                }}
                                if (statusNode) statusNode.textContent = 'Job state: ' + nextState + '.';
                            }} catch (_pollError) {{
                                if (statusNode) statusNode.textContent = 'Queued. Job ref: ' + jobId + '. Status refresh unavailable right now.';
                            }}
                        }};
                        window.setTimeout(poll, 600);
                    }} catch (_error) {{
                        if (statusNode) statusNode.textContent = 'Unable to queue upload right now.';
                        if (progressBar) progressBar.style.width = '0%';
                    }} finally {{
                        if (button) button.disabled = false;
                    }}
                }});
            }});
        </script>
        """,
        "/account/setup/documents",
        profile_name=profile_name,
    )
    return HTMLResponse(page_html, status_code=200)


# ── Wizard (DSS-017) ──


def render_wizard_page(*, banner: str = "", banner_kind: str = "ok") -> str:
    banner_html = f'<div class="banner {banner_kind}">{html.escape(banner)}</div>' if banner else ''
    return _layout(
        "Account Setup Wizard | DSS Control Plane",
        f"""
        <div class="page-header" style="text-align:center; max-width:640px; margin:0 auto;">
            <h1>Account Setup Wizard</h1>
            <p class="muted">Request access to DSS Control Plane. No sign-in required.</p>
        </div>
        {banner_html}
        <div class="wizard-container" style="max-width:640px; margin:0 auto;">
            <!-- Progress -->
            <div class="wizard-progress" id="wizard_progress" style="display:flex; justify-content:space-between; margin-bottom:24px; padding:0 8px;">
                <div class="wizard-step-dot active" data-step="1">1</div>
                <div class="wizard-step-line"></div>
                <div class="wizard-step-dot" data-step="2">2</div>
                <div class="wizard-step-line"></div>
                <div class="wizard-step-dot" data-step="3">3</div>
                <div class="wizard-step-line"></div>
                <div class="wizard-step-dot" data-step="4">4</div>
                <div class="wizard-step-line"></div>
                <div class="wizard-step-dot" data-step="5">5</div>
            </div>

            <!-- Step 1: Business Profile -->
            <div class="wizard-step" data-step="1">
                <div class="card">
                    <h2>Business Profile</h2>
                    <p class="muted">Tell us about your organisation.</p>
                    <label for="w_display_name">Business / Display Name</label>
                    <input id="w_display_name" name="display_name" placeholder="Acme Corp" required />
                    <label for="w_organisation_label">Organisation Label (optional)</label>
                    <input id="w_organisation_label" name="organisation_label" placeholder="acme" />
                    <label for="w_use_case">Intended Use Case</label>
                    <select id="w_use_case" name="use_case">
                        <option value="pilot">Pilot evaluation</option>
                        <option value="production">Production deployment</option>
                        <option value="research">Research & development</option>
                        <option value="other">Other</option>
                    </select>
                    <div class="row" style="margin-top:18px; justify-content:flex-end;">
                        <button class="btn primary" type="button" onclick="wizardNext(1)">Next</button>
                    </div>
                </div>
            </div>

            <!-- Step 2: Contact & Email -->
            <div class="wizard-step" data-step="2" hidden>
                <div class="card">
                    <h2>Contact Details</h2>
                    <p class="muted">We will send a verification code to this email.</p>
                    <label for="w_email">Email Address</label>
                    <input id="w_email" name="email" type="email" placeholder="you@example.com" required />
                    <div class="row" style="margin-top:18px; justify-content:space-between;">
                        <button class="btn" type="button" onclick="wizardPrev(2)">Back</button>
                        <button class="btn primary" type="button" id="w_send_otp_btn" onclick="wizardSendOtp()">Send Verification Code</button>
                    </div>
                    <div id="w_otp_section" hidden style="margin-top:18px; padding-top:18px; border-top:1px solid var(--border);">
                        <label for="w_otp">Verification Code</label>
                        <input id="w_otp" name="otp" placeholder="000000" maxlength="6" inputmode="numeric" />
                        <p class="muted" style="font-size:0.8rem;">Enter the 6-digit code sent to your email. Codes expire in 15 minutes.</p>
                        <div class="row" style="margin-top:12px; justify-content:flex-end;">
                            <button class="btn primary" type="button" id="w_confirm_otp_btn" onclick="wizardConfirmOtp()">Confirm Code</button>
                        </div>
                    </div>
                    <div id="w_email_status" class="muted" style="margin-top:10px; font-size:0.85rem;"></div>
                    <div class="row" style="margin-top:18px; justify-content:flex-end;" id="w_step2_next_row" hidden>
                        <button class="btn primary" type="button" onclick="wizardNext(2)">Next</button>
                    </div>
                </div>
            </div>

            <!-- Step 3: DID Configuration -->
            <div class="wizard-step" data-step="3" hidden>
                <div class="card">
                    <h2>DID Configuration</h2>
                    <p class="muted">Choose how your Decentralised Identifier (DID) will be created.</p>
                    <div style="margin-bottom:14px;">
                        <label style="display:flex; align-items:flex-start; gap:10px; cursor:pointer; padding:12px; border:1px solid var(--border); border-radius:10px; margin-bottom:10px;">
                            <input type="radio" name="did_choice" value="issuer_assigned" checked style="margin-top:4px;" onchange="wizardToggleDidInput()" />
                            <div>
                                <strong>Issue me a new DID</strong>
                                <p class="muted" style="margin:4px 0 0; font-size:0.85rem;">DSS will generate a DID for you on <code>{{os.getenv("DEFAULT_DID_HOST", "")}}</code>.</p>
                            </div>
                        </label>
                        <label style="display:flex; align-items:flex-start; gap:10px; cursor:pointer; padding:12px; border:1px solid var(--border); border-radius:10px;">
                            <input type="radio" name="did_choice" value="use_existing" style="margin-top:4px;" onchange="wizardToggleDidInput()" />
                            <div>
                                <strong>I already have a DID</strong>
                                <p class="muted" style="margin:4px 0 0; font-size:0.85rem;">Provide your existing DID (e.g., <code>did:web:...</code>).</p>
                            </div>
                        </label>
                    </div>
                    <div id="w_existing_did_wrap" hidden>
                        <label for="w_existing_did">Existing DID</label>
                        <input id="w_existing_did" name="existing_did" placeholder="did:web:example.com" />
                    </div>
                    <div class="row" style="margin-top:18px; justify-content:space-between;">
                        <button class="btn" type="button" onclick="wizardPrev(3)">Back</button>
                        <button class="btn primary" type="button" onclick="wizardNext(3)">Next</button>
                    </div>
                </div>
            </div>

            <!-- Step 4: Wallet Setup -->
            <div class="wizard-step" data-step="4" hidden>
                <div class="card">
                    <h2>Wallet Setup</h2>
                    <p class="muted">Select the wallet you will use for DSS authentication.</p>
                    <div style="margin-bottom:14px;">
                        <label style="display:flex; align-items:flex-start; gap:10px; cursor:pointer; padding:12px; border:1px solid var(--border); border-radius:10px; margin-bottom:10px;">
                            <input type="radio" name="wallet_provider" value="altme" checked style="margin-top:4px;" />
                            <div>
                                <strong>Altme (Recommended)</strong>
                                <p class="muted" style="margin:4px 0 0; font-size:0.85rem;">OpenID4VP / OpenID4VCI compatible. Works out of the box with DSS.</p>
                            </div>
                        </label>
                        <label style="display:flex; align-items:flex-start; gap:10px; cursor:pointer; padding:12px; border:1px solid var(--border); border-radius:10px;">
                            <input type="radio" name="wallet_provider" value="microsoft_entra" style="margin-top:4px;" />
                            <div>
                                <strong>Microsoft Entra Verified ID</strong>
                                <p class="muted" style="margin:4px 0 0; font-size:0.85rem;">Requires MS Authenticator. <span style="color:var(--error)">Known issue: middleware callback may fail.</span></p>
                            </div>
                        </label>
                    </div>
                    <div class="row" style="margin-top:18px; justify-content:space-between;">
                        <button class="btn" type="button" onclick="wizardPrev(4)">Back</button>
                        <button class="btn primary" type="button" onclick="wizardNext(4)">Next</button>
                    </div>
                </div>
            </div>

            <!-- Step 5: Review & Submit -->
            <div class="wizard-step" data-step="5" hidden>
                <div class="card">
                    <h2>Review & Submit</h2>
                    <p class="muted">Confirm your details before submitting for operator approval.</p>
                    <div id="w_review_content" style="margin:14px 0; padding:14px; background:var(--surface-muted); border-radius:10px; font-size:0.9rem;">
                        <!-- Populated by JS -->
                    </div>
                    <label style="display:flex; align-items:flex-start; gap:10px; cursor:pointer; margin:14px 0;">
                        <input type="checkbox" id="w_terms" style="margin-top:4px;" />
                        <span>I agree to the terms of service and understand that my request will be reviewed by a DSS operator.</span>
                    </label>
                    <div class="row" style="margin-top:18px; justify-content:space-between;">
                        <button class="btn" type="button" onclick="wizardPrev(5)">Back</button>
                        <button class="btn primary" type="button" id="w_submit_btn" onclick="wizardSubmit()">Submit Request</button>
                    </div>
                    <div id="w_submit_status" class="muted" style="margin-top:10px; font-size:0.85rem;"></div>
                </div>
            </div>

            <!-- Confirmation -->
            <div class="wizard-step" data-step="confirm" hidden>
                <div class="card" style="text-align:center;">
                    <h2 style="color:var(--ok);">✓ Request Submitted</h2>
                    <p>Your account setup request has been received and is awaiting operator approval.</p>
                    <p class="muted">You will receive an email at <strong id="w_confirm_email"></strong> once your request has been reviewed. The email will contain a link to complete wallet authentication and access the Control Plane.</p>
                    <div style="margin-top:24px;">
                        <a class="btn primary" href="/login">Go to Sign In</a>
                        <a class="btn" href="/">Return Home</a>
                    </div>
                </div>
            </div>
        </div>

        <style>
            .wizard-progress {{ display:flex; align-items:center; justify-content:space-between; }}
            .wizard-step-dot {{ width:32px; height:32px; border-radius:50%; background:var(--surface-muted); border:2px solid var(--border-strong); display:flex; align-items:center; justify-content:center; font-weight:600; font-size:0.85rem; color:var(--text-muted); flex-shrink:0; }}
            .wizard-step-dot.active {{ background:var(--accent); border-color:var(--accent); color:#fff; }}
            .wizard-step-dot.completed {{ background:var(--ok); border-color:var(--ok); color:#fff; }}
            .wizard-step-line {{ flex:1; height:2px; background:var(--border); margin:0 6px; }}
            .wizard-step-line.completed {{ background:var(--ok); }}
            .wizard-step[hidden] {{ display:none !important; }}
            .wizard-container label {{ display:block; margin:14px 0 6px; font-weight:500; font-size:0.9rem; }}
            .wizard-container input, .wizard-container select {{ width:100%; padding:10px 12px; border:1px solid var(--border-strong); border-radius:8px; background:var(--surface); font-size:0.95rem; }}
            .wizard-container input:focus, .wizard-container select:focus {{ outline:none; border-color:var(--accent); }}
            @media (max-width:520px) {{ .wizard-step-dot {{ width:26px; height:26px; font-size:0.75rem; }} }}
        </style>

        <script>
        (function() {{
            const STORAGE_KEY = 'dss_wizard_v1';
            let state = {{step: 1, request_id: '', token: '', data: {{}}, email_verified: false, otp_sent: false}};

            function loadState() {{
                try {{ const s = JSON.parse(localStorage.getItem(STORAGE_KEY) || '{{}}'); if (s.request_id && s.token) state = {{...state, ...s}}; }} catch(e) {{}}
            }}
            function saveState() {{ localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }}
            function clearState() {{ localStorage.removeItem(STORAGE_KEY); }}

            async function api(path, method, body) {{
                const opts = {{ method, headers: {{ 'accept': 'application/json', 'content-type': 'application/json' }} }};
                if (state.token) opts.headers['x-anonymous-token'] = state.token;
                if (body) opts.body = JSON.stringify(body);
                const res = await fetch(path, opts);
                const data = await res.json().catch(() => ({{}}));
                if (!res.ok) throw new Error(data.detail?.error || data.error || `HTTP ${{res.status}}`);
                return data;
            }}

            async function initRequest() {{
                if (state.request_id) return;
                const data = await api('/api/wizard/request', 'POST');
                state.request_id = data.request_id;
                state.token = data.anonymous_token;
                saveState();
            }}

            function showStep(n) {{
                document.querySelectorAll('.wizard-step').forEach(el => el.hidden = true);
                const target = document.querySelector(`.wizard-step[data-step="${{n}}"]`);
                if (target) target.hidden = false;
                updateDots(n);
                state.step = n;
                saveState();
                if (n === 2) {{
                    document.getElementById('w_step2_next_row').hidden = !state.email_verified;
                }}
            }}

            function updateDots(current) {{
                document.querySelectorAll('.wizard-step-dot').forEach(dot => {{
                    const s = parseInt(dot.dataset.step);
                    dot.classList.remove('active','completed');
                    if (s < current) dot.classList.add('completed');
                    else if (s === current) dot.classList.add('active');
                }});
                document.querySelectorAll('.wizard-step-line').forEach((line, i) => {{
                    line.classList.toggle('completed', i < current - 1);
                }});
            }}

            async function saveProfile() {{
                const display_name = document.getElementById('w_display_name').value.trim();
                const organisation_label = document.getElementById('w_organisation_label').value.trim();
                const use_case = document.getElementById('w_use_case').value;
                if (!display_name) {{ alert('Please enter a business name.'); return false; }}
                state.data.display_name = display_name;
                state.data.organisation_label = organisation_label;
                state.data.use_case = use_case;
                saveState();
                return true;
            }}

            async function saveContact() {{
                const email = document.getElementById('w_email').value.trim().toLowerCase();
                if (!email || !email.includes('@')) {{ alert('Please enter a valid email address.'); return false; }}
                state.data.email = email;
                // Send profile step to backend now that we have all fields
                await api(`/api/wizard/step/${{state.request_id}}/profile`, 'POST', {{
                    display_name: state.data.display_name,
                    email: state.data.email,
                    organisation_label: state.data.organisation_label || ''
                }});
                saveState();
                return true;
            }}

            async function saveDid() {{
                const choice = document.querySelector('input[name="did_choice"]:checked').value;
                const existing = document.getElementById('w_existing_did').value.trim();
                if (choice === 'use_existing' && (!existing || !existing.startsWith('did:'))) {{
                    alert('Please enter a valid DID starting with did:'); return false;
                }}
                state.data.did_choice = choice;
                state.data.did_value = choice === 'use_existing' ? existing : '';
                await api(`/api/wizard/step/${{state.request_id}}/did_choice`, 'POST', {{
                    did_choice: state.data.did_choice,
                    did_value: state.data.did_value
                }});
                saveState();
                return true;
            }}

            async function saveWallet() {{
                const provider = document.querySelector('input[name="wallet_provider"]:checked').value;
                state.data.wallet_provider = provider;
                await api(`/api/wizard/step/${{state.request_id}}/wallet_setup`, 'POST', {{ wallet_provider: provider }});
                saveState();
                return true;
            }}

            window.wizardNext = async function(currentStep) {{
                if (currentStep === 1) {{ if (!await saveProfile()) return; }}
                if (currentStep === 2) {{
                    if (!state.email_verified) {{ alert('Please verify your email before continuing.'); return; }}
                }}
                if (currentStep === 3) {{ if (!await saveDid()) return; }}
                if (currentStep === 4) {{ if (!await saveWallet()) return; populateReview(); }}
                showStep(currentStep + 1);
            }};

            window.wizardPrev = function(currentStep) {{
                showStep(currentStep - 1);
            }};

            window.wizardToggleDidInput = function() {{
                const choice = document.querySelector('input[name="did_choice"]:checked').value;
                document.getElementById('w_existing_did_wrap').hidden = (choice !== 'use_existing');
            }};

            window.wizardSendOtp = async function() {{
                const email = document.getElementById('w_email').value.trim().toLowerCase();
                if (!email || !email.includes('@')) {{ alert('Please enter a valid email first.'); return; }}
                state.data.email = email;
                // Save profile first so backend has the email
                await api(`/api/wizard/step/${{state.request_id}}/profile`, 'POST', {{
                    display_name: state.data.display_name,
                    email: state.data.email,
                    organisation_label: state.data.organisation_label || ''
                }});
                const btn = document.getElementById('w_send_otp_btn');
                btn.disabled = true; btn.textContent = 'Sending...';
                try {{
                    const data = await api('/api/wizard/verify-email', 'POST', {{ request_id: state.request_id }});
                    state.otp_sent = true;
                    saveState();
                    document.getElementById('w_otp_section').hidden = false;
                    document.getElementById('w_email_status').textContent = 'Verification code sent! Check your email (or developer console).';
                    // In dev mode the code is returned directly
                    if (data.verification_code) {{
                        document.getElementById('w_email_status').textContent += ` Code: ${{data.verification_code}}`;
                    }}
                }} catch (err) {{
                    document.getElementById('w_email_status').textContent = 'Error: ' + err.message;
                }} finally {{
                    btn.disabled = false; btn.textContent = 'Send Verification Code';
                }}
            }};

            window.wizardConfirmOtp = async function() {{
                const code = document.getElementById('w_otp').value.trim();
                if (!code) {{ alert('Please enter the verification code.'); return; }}
                const btn = document.getElementById('w_confirm_otp_btn');
                btn.disabled = true; btn.textContent = 'Confirming...';
                try {{
                    await api('/api/wizard/verify-email/confirm', 'POST', {{ request_id: state.request_id, code }});
                    state.email_verified = true;
                    saveState();
                    document.getElementById('w_email_status').textContent = 'Email verified successfully!';
                    document.getElementById('w_otp_section').hidden = true;
                    document.getElementById('w_send_otp_btn').hidden = true;
                    document.getElementById('w_step2_next_row').hidden = false;
                }} catch (err) {{
                    document.getElementById('w_email_status').textContent = 'Error: ' + err.message;
                }} finally {{
                    btn.disabled = false; btn.textContent = 'Confirm Code';
                }}
            }};

            function populateReview() {{
                const p = state.data.wallet_provider === 'altme' ? 'Altme (OpenID4VP)' : 'Microsoft Entra Verified ID';
                const d = state.data.did_choice === 'issuer_assigned' ? 'New DID issued by DSS' : state.data.did_value;
                document.getElementById('w_review_content').innerHTML = `
                    <p><strong>Business:</strong> ${{html_escape(state.data.display_name)}}</p>
                    <p><strong>Email:</strong> ${{html_escape(state.data.email)}}</p>
                    <p><strong>Use case:</strong> ${{html_escape(state.data.use_case || '')}}</p>
                    <p><strong>DID:</strong> ${{html_escape(d)}}</p>
                    <p><strong>Wallet:</strong> ${{html_escape(p)}}</p>
                `;
            }}

            window.wizardSubmit = async function() {{
                if (!document.getElementById('w_terms').checked) {{ alert('Please accept the terms.'); return; }}
                const btn = document.getElementById('w_submit_btn');
                btn.disabled = true; btn.textContent = 'Submitting...';
                try {{
                    const idempotency = 'wizard_' + state.request_id;
                    const data = await api(`/api/wizard/submit/${{state.request_id}}`, 'POST', {{ idempotency_key: idempotency }});
                    clearState();
                    document.getElementById('w_confirm_email').textContent = state.data.email || '';
                    showStep('confirm');
                }} catch (err) {{
                    document.getElementById('w_submit_status').textContent = 'Error: ' + err.message;
                    btn.disabled = false; btn.textContent = 'Submit Request';
                }}
            }};

            function html_escape(s) {{
                const div = document.createElement('div');
                div.textContent = s;
                return div.innerHTML;
            }}

            // Bootstrap
            loadState();
            initRequest().then(() => showStep(state.step)).catch(err => {{
                document.getElementById('wizard_progress').insertAdjacentHTML('afterend', `<div class="banner error">Failed to initialise wizard: ${{err.message}}</div>`);
            }});
        }})();
        </script>
        """,
    )


