async def login_page(request: Request) -> Response:
    state = str(request.query_params.get("state") or "").strip()
    next_path = _safe_next_path(str(request.query_params.get("next") or "/"))
    simple_mode = "&simple=1" if _simple_mode_enabled(request) else ""
    redirect = f"/login/wallet?next={quote(next_path, safe='/?=&')}{simple_mode}"
    if state:
        redirect = f"{redirect}&state={quote(state, safe='')}"
    return RedirectResponse(url=redirect, status_code=307)


async def logout(request: Request) -> RedirectResponse:
    response = RedirectResponse(url="/", status_code=303)
    _clear_cookie(response, BACKEND_SESSION_TOKEN_COOKIE, request, httponly=True)
    _clear_cookie(response, BACKEND_REFRESH_TOKEN_COOKIE, request, httponly=True)
    _clear_cookie(response, FRONTDOOR_AUTH_COOKIE, request, httponly=True)
    _clear_cookie(response, PRINCIPAL_DID_COOKIE, request, httponly=False)
    _clear_cookie(response, GITHUB_STATE_COOKIE, request, httponly=True)
    _clear_cookie(response, GITHUB_NEXT_COOKIE, request, httponly=True)
    return response


