async def login_passkey_login_finish(request: Request) -> JSONResponse:
    payload = _as_dict(await request.json())
    status_code, body = await _auth_proxy_post("/auth/verify", dict(payload))
    response = JSONResponse(body, status_code=status_code)
    if status_code == 200 and isinstance(body, dict):
        session_raw = body.get("session")
        session = _as_dict(session_raw)
        refresh_session_raw = body.get("refresh_session")
        refresh_session = _as_dict(refresh_session_raw)
        token = str(session.get("token") or "").strip()
        refresh_token = str(refresh_session.get("token") or "").strip()
        principal_did = str(session.get("principal_did") or body.get("principal_did") or "").strip()
        if token:
            _set_cookie(response, BACKEND_SESSION_TOKEN_COOKIE, token, request, httponly=True, max_age=3600)
        if refresh_token:
            _set_cookie(response, BACKEND_REFRESH_TOKEN_COOKIE, refresh_token, request, httponly=True, max_age=86400)
            _set_cookie(response, FRONTDOOR_AUTH_COOKIE, _frontdoor_cookie_signature(), request, httponly=True, max_age=86400)
        if principal_did:
            _set_cookie(response, PRINCIPAL_DID_COOKIE, principal_did, request, httponly=False, max_age=86400 * 30)
    return response


