async def api_auth_session_refresh(request: Request) -> JSONResponse:
    refresh_token = str(request.cookies.get(BACKEND_REFRESH_TOKEN_COOKIE) or "").strip()
    if not refresh_token:
        response = JSONResponse(
            {
                "error": "authentication_required",
                "login_url": f"/login?next={quote(_safe_next_path(_current_relative_url(request)), safe='/?=&')}",
            },
            status_code=401,
        )
        _clear_cookie(response, BACKEND_SESSION_TOKEN_COOKIE, request, httponly=True)
        _clear_cookie(response, BACKEND_REFRESH_TOKEN_COOKIE, request, httponly=True)
        _clear_cookie(response, FRONTDOOR_AUTH_COOKIE, request, httponly=True)
        _clear_cookie(response, PRINCIPAL_DID_COOKIE, request, httponly=False)
        return response
    token = str(request.cookies.get(BACKEND_SESSION_TOKEN_COOKIE) or "").strip()
    headers = {"x-refresh-token": refresh_token}
    if token:
        headers["x-session-token"] = token
    status_code, body = await _auth_proxy_post(
        "/auth/session/refresh",
        {},
        headers=headers,
    )
    payload = dict(body if isinstance(body, dict) else {})
    if status_code == 401:
        payload["login_url"] = f"/login?next={quote(_safe_next_path(_current_relative_url(request)), safe='/?=&')}"
    response = JSONResponse(payload, status_code=status_code)
    session = _as_dict(payload.get("session"))
    refresh_session = _as_dict(payload.get("refresh_session"))
    refreshed_token = str(session.get("token") or "").strip()
    refreshed_refresh_token = str(refresh_session.get("token") or "").strip()
    principal_did = str(payload.get("principal_did") or "").strip()
    if status_code < 400 and refreshed_token and refreshed_refresh_token and principal_did:
        _set_cookie(response, BACKEND_SESSION_TOKEN_COOKIE, refreshed_token, request, httponly=True, max_age=3600)
        _set_cookie(response, BACKEND_REFRESH_TOKEN_COOKIE, refreshed_refresh_token, request, httponly=True, max_age=86400)
        _set_cookie(response, FRONTDOOR_AUTH_COOKIE, _frontdoor_cookie_signature(), request, httponly=True, max_age=86400)
        _set_cookie(response, PRINCIPAL_DID_COOKIE, principal_did, request, httponly=False, max_age=86400 * 30)
    elif status_code == 401:
        _clear_cookie(response, BACKEND_SESSION_TOKEN_COOKIE, request, httponly=True)
        _clear_cookie(response, BACKEND_REFRESH_TOKEN_COOKIE, request, httponly=True)
        _clear_cookie(response, FRONTDOOR_AUTH_COOKIE, request, httponly=True)
        _clear_cookie(response, PRINCIPAL_DID_COOKIE, request, httponly=False)
    return response


