async def api_control_plane_sources_upload(request: Request) -> JSONResponse:
    _, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    form = await request.form()
    ledger_id = str(form.get("ledger_id") or "").strip()
    principal_did = str(form.get("principal_did") or "").strip()
    batch_label = str(form.get("batch_label") or "").strip()
    uploaded_files = [
        value for _key, value in form.multi_items()
        if isinstance(value, UploadFile) and str(value.filename or "").strip()
    ]
    if not uploaded_files:
        return JSONResponse({"error": "source_files_required"}, status_code=400)

    job_id = f"source-job-{secrets.token_hex(8)}"
    now = datetime.now(timezone.utc).isoformat()
    state = _load_control_plane_state()
    source_records: list[dict[str, Any]] = []
    source_ids: list[str] = []

    # Persist uploads locally and queue an async chunk job. If middleware ingestion
    # is available, prefer its coordinates; otherwise fall back to local chunking.
    job_dir = _source_job_root(job_id)
    job_dir.mkdir(parents=True, exist_ok=True)

    for upload in uploaded_files:
        original_name = _sanitize_source_filename(str(upload.filename or "source.txt"))
        raw_bytes = await upload.read()
        source_id = f"source-{secrets.token_hex(4)}"
        storage_path = job_dir / f"{source_id}_{original_name}"
        storage_path.write_bytes(raw_bytes)
        coordinate = f"{ledger_id or 'anonymous'}:{source_id}" if ledger_id else source_id

        source_record = {
            "source_id": source_id,
            "job_id": job_id,
            "ledger_id": ledger_id,
            "principal_did": principal_did,
            "batch_label": batch_label,
            "file_name": original_name,
            "original_file_name": str(upload.filename or original_name),
            "content_type": str(upload.content_type or "application/octet-stream"),
            "size_bytes": len(raw_bytes),
            "status": "queued",
            "summary": f"Uploaded {original_name}",
            "uploaded_at": now,
            "updated_at": now,
            "storage_path": str(storage_path),
            "chunk_manifest_path": "",
            "chunk_count": 0,
            "canonical_subject": _canonical_entity_subject("source", source_id),
            "canonical_subject_source": "did:web:source",
            "coordinate": coordinate,
            "parent_coordinate": ledger_id or "",
            "part_coordinates": [],
        }
        source_records.append(source_record)
        source_ids.append(source_id)
        state["sources"] = _upsert_control_plane_record(
            _as_dict_list(state.get("sources")), "source_id", source_record
        )

    job_record = {
        "job_id": job_id,
        "status": "queued",
        "ledger_id": ledger_id,
        "principal_did": principal_did,
        "batch_label": batch_label,
        "source_ids": source_ids,
        "source_count": len(source_ids),
        "progress_total": len(source_ids),
        "progress_done": 0,
        "queued_at": now,
        "started_at": "",
        "completed_at": "",
        "updated_at": now,
        "failure_message": "",
        "ingest_results": [],
    }
    state["source_jobs"] = _upsert_control_plane_record(
        _as_dict_list(state.get("source_jobs")), "job_id", job_record
    )
    _save_control_plane_state(state)

    # Attempt middleware ingestion for every uploaded file. If the middleware
    # accepts a file we mark that source ready and complete the job immediately
    # so the UI doesn't have to rely on serverless background tasks (which may
    # be killed after the HTTP response is sent).
    ingest_results: list[dict[str, Any]] = []
    async with httpx.AsyncClient(timeout=60.0) as client:
        for source in source_records:
            try:
                metadata = {
                    "filename": source["file_name"],
                    "content_type": source["content_type"],
                    "size_bytes": source["size_bytes"],
                    "batch_label": batch_label,
                    "principal_did": principal_did,
                }
                files = {
                    "file": (
                        source["file_name"],
                        Path(source["storage_path"]).read_bytes(),
                        source["content_type"],
                    )
                }
                data = {
                    "entity": ledger_id or "anonymous",
                    "kind": batch_label or "attachment",
                    "ledger_id": ledger_id,
                    "metadata": json.dumps(metadata),
                }
                resp = await client.post(
                    f"{MIDDLEWARE_BASE_URL}/api/ingest/file",
                    data=data,
                    files=files,
                )
                if resp.status_code < 400:
                    ingest_result = resp.json()
                    ingest_results.append(ingest_result)
                    source.update({
                        "status": "ready",
                        "coordinate": ingest_result.get("coordinate") or source["coordinate"],
                        "parent_coordinate": ingest_result.get("parent_coordinate") or source["parent_coordinate"],
                        "part_coordinates": ingest_result.get("part_coordinates") or [],
                        "ingest_results": [ingest_result],
                        "updated_at": datetime.now(timezone.utc).isoformat(),
                    })
            except Exception:
                # Per-file ingest failure is not fatal; fall through to local
                # chunking for any files the middleware could not handle.
                pass

    # Persist whatever the middleware accepted, then decide whether the job is
    # complete or needs local chunking.
    if ingest_results:
        state = _load_control_plane_state()
        for source in source_records:
            state["sources"] = _upsert_control_plane_record(
                _as_dict_list(state.get("sources")), "source_id", source
            )
        now = datetime.now(timezone.utc).isoformat()
        job_record.update({
            "status": "completed",
            "progress_done": len(ingest_results),
            "progress_total": len(source_records),
            "completed_at": now,
            "updated_at": now,
            "ingest_results": ingest_results,
        })
        state["source_jobs"] = _upsert_control_plane_record(
            _as_dict_list(state.get("source_jobs")), "job_id", job_record
        )
        _save_control_plane_state(state)
    else:
        # If middleware ingestion is unavailable, run local chunking
        # asynchronously. On serverless platforms this may not complete, but it
        # keeps the local-dev path working.
        async def _background_process_source_job(job_id: str) -> None:
            try:
                await _process_source_job(job_id)
            except Exception as exc:
                print(f"Background source job {job_id} failed: {exc}")
        try:
            asyncio.create_task(_background_process_source_job(job_id))
        except Exception:
            pass

    return JSONResponse(
        {
            "status": "queued",
            "job": _normalized_source_job_record(job_record),
            "sources": [_normalized_source_record(item) for item in source_records],
            "upload_root": str(job_dir),
        },
        status_code=202,
    )


async def api_control_plane_source_job_status(request: Request) -> JSONResponse:
    _, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    job_id = str(request.path_params.get("job_id") or "").strip()
    if not job_id:
        return JSONResponse({"error": "job_id_required"}, status_code=400)
    state = _load_control_plane_state()
    job = next((item for item in _source_jobs_from_state(state) if str(item.get("job_id") or "").strip() == job_id), None)
    if not isinstance(job, dict):
        return JSONResponse({"error": "source_job_not_found"}, status_code=404)
    sources = [
        item for item in _source_records_from_state(state)
        if str(item.get("job_id") or "").strip() == job_id
    ]
    return JSONResponse({"status": "ok", "job": job, "sources": sources}, status_code=200)


