async def api_control_plane_app_surfaces_advance(request: Request) -> JSONResponse:
    _, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    payload = _as_dict(await request.json())
    surface_id = str(payload.get("surface_id") or "").strip()
    action = str(payload.get("action") or "").strip()
    if not surface_id or not action:
        return JSONResponse({"error": "surface_id_and_action_required"}, status_code=400)
    surfaces_status, surfaces_body = await _control_plane_get("/api/control-plane/surfaces")
    app_surfaces = [_app_surface_from_surface_record(item) for item in _as_dict_list(surfaces_body.get("surfaces"))] if surfaces_status < 400 and isinstance(surfaces_body, dict) else []
    selected = next((item for item in app_surfaces if isinstance(item, dict) and str(item.get("surface_id") or "").strip() == surface_id), None)
    if selected is None:
        return JSONResponse({"error": "surface_not_found", "surface_id": surface_id}, status_code=404)
    updated = _advance_surface_record(selected, action)
    if action.strip().lower() == "activate":
        status_code, body = await _control_plane_post(
            "/api/control-plane/entities/activate",
            {"entity_type": "surface", "entity_id": surface_id, "status": "active"},
        )
        if status_code >= 400:
            return JSONResponse(body if isinstance(body, dict) else {"error": "surface_activate_failed"}, status_code=status_code)
        return JSONResponse({"status": "ok", "app_surface": updated, "saved": True, **dict(body if isinstance(body, dict) else {})}, status_code=200)
    status_code, body = await _control_plane_post("/api/control-plane/surfaces", {**_surface_control_plane_payload(updated), "governance_mode": "direct_write"})
    if status_code >= 400:
        return JSONResponse(body if isinstance(body, dict) else {"error": "surface_advance_failed"}, status_code=status_code)
    return JSONResponse({"status": "ok", "app_surface": _app_surface_from_surface_record(_as_dict(body.get("surface"))), "saved": True}, status_code=200)


async def api_control_plane_integration_plans(request: Request) -> JSONResponse:
    _, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    snapshot = await build_dashboard_snapshot(request)
    auth_headers = _auth_headers_from_request(request)
    principal_status, principal_rows_body = await _principal_registry_get("/api/principals?limit=100", headers=auth_headers)
    principals = _as_dict_list(principal_rows_body.get("principals")) if principal_status < 400 and isinstance(principal_rows_body, dict) else []
    principals = _merge_frontend_model_principals(
        principals,
        _as_dict(snapshot.get("models_current")),
        tenant_id=str(_as_dict(_as_dict(snapshot.get("identity_card")).get("identity_vc")).get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
    )
    model_principals = []
    for item in principals:
        if not isinstance(item, dict):
            continue
        metadata = _as_dict(item.get("metadata"))
        if str(metadata.get("actor_type") or "").strip().lower() == "model":
            model_principals.append(item)
    models_debug = await fetch_json('/api/models/debug', headers=auth_headers)
    models_debug_data = _migrated_models_debug(models_debug)
    llm_provider = str(models_debug_data.get("settings_llm_provider") or os.getenv("LLM_PROVIDER") or "unknown").strip()
    llm_model = str(models_debug_data.get("settings_llm_model") or os.getenv("LLM_MODEL") or "unknown").strip()
    stored_providers, stored_bindings, stored_app_surfaces = _snapshot_control_plane_records(snapshot)
    provider_records = _merged_control_plane_records(
        _control_plane_provider_records(_as_dict(models_debug)),
        stored_providers,
        "provider_id",
    )
    binding_records = _merged_control_plane_records(
        _control_plane_model_binding_records(provider_records, model_principals, llm_provider, llm_model, _as_dict(snapshot.get("models_current"))),
        stored_bindings,
        "binding_id",
    )
    app_surfaces = _merged_control_plane_records(
        _control_plane_app_surface_records(snapshot, binding_records),
        stored_app_surfaces,
        "surface_id",
    )
    plans = [_surface_integration_plan(item) for item in app_surfaces if isinstance(item, dict)]
    surface_id = str(request.query_params.get("surface_id") or "").strip()
    if surface_id:
        plan = next((item for item in plans if str(item.get("surface_id") or "").strip() == surface_id), None)
        if plan is None:
            return JSONResponse({"error": "surface_not_found", "surface_id": surface_id}, status_code=404)
        return JSONResponse({"status": "ok", "integration_plan": plan}, status_code=200)
    return JSONResponse({"status": "ok", "integration_plans": plans}, status_code=200)


