async def api_control_plane_relationships_upsert(request: Request) -> JSONResponse:
    _, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    payload = _as_dict(await request.json())
    subject_entity_type = str(payload.get("subject_entity_type") or "").strip().lower()
    subject_entity_id = str(payload.get("subject_entity_id") or "").strip()
    object_entity_type = str(payload.get("object_entity_type") or "").strip().lower()
    object_entity_id = str(payload.get("object_entity_id") or "").strip()
    relationship_type = str(payload.get("relationship_type") or "related_to").strip().lower() or "related_to"
    if subject_entity_type not in {"ledger", "principal", "surface"} or not subject_entity_id:
        return JSONResponse({"error": "subject_entity_type_and_subject_entity_id_required"}, status_code=400)
    if object_entity_type not in {"ledger", "principal", "surface"} or not object_entity_id:
        return JSONResponse({"error": "object_entity_type_and_object_entity_id_required"}, status_code=400)
    subject_type, subject_id, object_type, object_id, canonical_relationship_type = _canonical_relationship_parts(
        subject_entity_type,
        subject_entity_id,
        object_entity_type,
        object_entity_id,
    )
    record = _relationship_defaults(
        subject_type,
        subject_id,
        object_type,
        object_id,
        relationship_type if relationship_type != "related_to" else canonical_relationship_type,
        str(payload.get("label") or "").strip(),
    )
    try:
        permission_payload = _parse_relationship_permission_payload(payload.get("permission_payload"))
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)
    record.update(
        {
            "label": str(payload.get("label") or "").strip(),
            "status": str(payload.get("status") or "active").strip().lower() or "active",
            "enabled_state": str(payload.get("enabled_state") or "enabled").strip().lower() or "enabled",
            "permission_scope": str(payload.get("permission_scope") or "full").strip().lower() or "full",
            "permission_payload": permission_payload,
            "start_at": str(payload.get("start_date") or "").strip(),
            "end_at": str(payload.get("end_date") or "").strip(),
            "notes": str(payload.get("notes") or "").strip(),
            "constraints": str(payload.get("constraints") or "").strip(),
            "metadata": _as_dict(payload.get("metadata")) if isinstance(payload.get("metadata"), dict) else {},
            "updated_at": datetime.now(timezone.utc).isoformat(),
        }
    )
    status_code, body = await _control_plane_post("/api/control-plane/relationships", record)
    if status_code >= 400:
        return JSONResponse(body if isinstance(body, dict) else {"error": "relationship_save_failed"}, status_code=status_code)
    saved = _as_dict(body.get("relationship"))
    if saved:
        state = _load_control_plane_state()
        state["relationships"] = _upsert_control_plane_record(_as_dict_list(state.get("relationships")), "relationship_id", saved)
        _save_control_plane_state(state)
    response_payload = dict(body if isinstance(body, dict) else {})
    response_payload["status"] = "ok"
    response_payload["relationship"] = saved or record
    response_payload["saved"] = True
    return JSONResponse(response_payload, status_code=200)


async def api_control_plane_entity_links(request: Request) -> JSONResponse:
    session, auth_error = await _control_plane_json_session(request)
    if auth_error is not None:
        return auth_error
    payload = _as_dict(await request.json())
    owner_type = str(payload.get("owner_entity_type") or "").strip().lower()
    owner_id = str(payload.get("owner_entity_id") or "").strip()
    if owner_type not in {"ledger", "principal", "surface"} or not owner_id:
        return JSONResponse({"error": "owner_entity_type_and_owner_entity_id_required"}, status_code=400)
    context = await _load_connection_lookup_context(request, identity_card=session)
    visible: dict[str, set[str]] = {
        "ledger": set(context.get("ledger_map", {}).keys()),
        "principal": set(context.get("principal_map", {}).keys()),
        "surface": set(context.get("surface_map", {}).keys()),
    }
    links_payload = _as_dict(payload.get("links"))
    desired: dict[str, list[str]] = {}
    for entity_type in ("ledger", "principal", "surface"):
        if entity_type == owner_type:
            continue
        raw_ids = _as_list(links_payload.get(entity_type))
        kept: list[str] = []
        seen: set[str] = set()
        for raw in raw_ids:
            item_id = str(raw or "").strip()
            if item_id and item_id not in seen and item_id in visible.get(entity_type, set()):
                kept.append(item_id)
                seen.add(item_id)
        desired[entity_type] = kept
    current_rows = _relationship_rows_for_entity(owner_type, owner_id, context)
    current: dict[str, set[str]] = {}
    for row in current_rows:
        entity_type = str(row.get("entity_type") or "").strip().lower()
        entity_id = str(row.get("entity_id") or "").strip()
        if entity_type and entity_id and entity_type != owner_type:
            current.setdefault(entity_type, set()).add(entity_id)
    errors: list[str] = []

    def _save_relationship_to_state(saved: dict[str, Any]) -> None:
        if not saved:
            return
        state = _load_control_plane_state()
        state["relationships"] = _upsert_control_plane_record(
            _as_dict_list(state.get("relationships")), "relationship_id", saved
        )
        _save_control_plane_state(state)

    # Remove links that are no longer desired by retiring the relationship record.
    for entity_type, current_ids in current.items():
        for entity_id in current_ids - set(desired.get(entity_type, [])):
            record = _relationship_record(owner_type, owner_id, entity_type, entity_id)
            record["status"] = "retired"
            record["enabled_state"] = "disabled"
            record["updated_at"] = datetime.now(timezone.utc).isoformat()
            status_code, body = await _control_plane_post("/api/control-plane/relationships", record, request)
            if status_code >= 400:
                errors.append(f"remove_{entity_type}_{entity_id}: {body.get('error') if isinstance(body, dict) else 'failed'}")
            else:
                _save_relationship_to_state(_as_dict(body.get("relationship")))
    # Add new links.
    for entity_type, desired_ids in desired.items():
        for entity_id in set(desired_ids) - current.get(entity_type, set()):
            related_record = context.get(f"{entity_type}_map", {}).get(entity_id)
            label = _display_label_for_entity(entity_type, entity_id, related_record)
            record = _relationship_record(owner_type, owner_id, entity_type, entity_id, label)
            record["status"] = "active"
            record["enabled_state"] = "enabled"
            record["updated_at"] = datetime.now(timezone.utc).isoformat()
            status_code, body = await _control_plane_post("/api/control-plane/relationships", record, request)
            if status_code >= 400:
                errors.append(f"add_{entity_type}_{entity_id}: {body.get('error') if isinstance(body, dict) else 'failed'}")
            else:
                _save_relationship_to_state(_as_dict(body.get("relationship")))
    # Keep canonical metadata in sync when a principal or surface changes ledgers.
    if owner_type == "principal":
        await _update_principal_ledger_metadata(owner_id, desired.get("ledger", []), context, request)
    elif owner_type == "surface":
        await _update_surface_canonical_metadata(owner_id, desired, context, request)
    if errors:
        return JSONResponse({"status": "partial", "errors": errors}, status_code=400)
    return JSONResponse({"status": "ok", "updated": True}, status_code=200)


