async def verified_id_page(request: Request) -> HTMLResponse:
    state = str(request.query_params.get('state') or '').strip()
    record: dict[str, Any] | None = None
    banner = ''
    banner_kind = 'ok'
    if state:
        status_code, body = await _verified_id_get(f"/api/verified-id/requests/{quote(state, safe='')}")
        if status_code >= 400:
            detail = body.get('detail') or body.get('error') or body
            banner = f'Unable to load Verified ID request ({status_code}): {detail}'
            banner_kind = 'warn'
        else:
            record = body.get('request') if isinstance(body.get('request'), dict) else None
    principal_did = str(request.query_params.get('principal_did') or '').strip() or str(request.cookies.get(PRINCIPAL_DID_COOKIE) or '').strip()
    identity_card = await _build_identity_card(request)
    return HTMLResponse(
        render_verified_id_page(
            request,
            banner=banner,
            banner_kind=banner_kind,
            principal_did=principal_did,
            request_record=record,
            identity_card=identity_card,
        ),
        status_code=200 if not banner else 502 if banner_kind == 'warn' else 200,
    )


async def verified_id_issue_start(request: Request) -> HTMLResponse | RedirectResponse:
    form = await request.form()
    principal_did = str(form.get('principal_did') or '').strip() or str(request.cookies.get(PRINCIPAL_DID_COOKIE) or '').strip()
    identity_card = await _build_identity_card(request)
    if not principal_did:
        return HTMLResponse(
            render_verified_id_page(request, banner='Principal DID is required before starting Verified ID issuance.', banner_kind='warn', identity_card=identity_card),
            status_code=400,
        )
    entra_cookie = str(request.cookies.get('ds_entra_oidc') or '').strip()
    entra_token = str(request.query_params.get('_entra_auth') or '').strip() or str(form.get('_entra_auth') or '').strip()
    cookies = {'ds_entra_oidc': entra_cookie} if entra_cookie else None
    issuance_payload = {'principal_did': principal_did}
    if entra_token:
        issuance_payload['_entra_auth'] = entra_token
    status_code, body = await _verified_id_post('/api/verified-id/issuance-requests', issuance_payload, cookies=cookies, auth_token=entra_token)
    # Handle Entra OIDC auth gate for OpenID4VCI issuance
    if status_code == 401 and str(body.get('error') or '').strip() == 'auth_required':
        login_url = str(body.get('login_url') or '').strip()
        if login_url:
            next_path = f'/verified-id?principal_did={principal_did}'
            separator = '&' if '?' in login_url else '?'
            next_url = f"{PUBLIC_BASE_URL}{next_path}"
            redirect_url = f"{login_url}{separator}next={quote(next_url, safe='/?=&')}"
            return RedirectResponse(url=redirect_url, status_code=303)
    if status_code >= 400:
        detail = body.get('detail') or body.get('error') or body
        return HTMLResponse(
            render_verified_id_page(request, banner=f'Unable to start Verified ID issuance ({status_code}): {detail}', banner_kind='warn', principal_did=principal_did, identity_card=identity_card),
            status_code=502,
        )
    record = body.get('request') if isinstance(body.get('request'), dict) else None
    wallet_mode = str((record or {}).get('mode') or '').strip()
    if wallet_mode == 'walt_id_issuance':
        banner = 'OpenID4VCI credential offer created. Scan the QR code with your MATTR wallet, or copy the credential offer link below.'
    else:
        banner = 'Microsoft Verified ID issuance request created. Scan the QR code in Microsoft Authenticator or open the deep link to add the DSS identity card to the wallet.'
    return HTMLResponse(
        render_verified_id_page(request, banner=banner, banner_kind='ok', principal_did=principal_did, request_record=record, identity_card=identity_card),
        status_code=200,
    )


async def verified_id_start(request: Request) -> HTMLResponse:
    form = await request.form()
    principal_did = str(form.get('principal_did') or '').strip() or str(request.cookies.get(PRINCIPAL_DID_COOKIE) or '').strip()
    identity_card = await _build_identity_card(request)
    if not principal_did:
        return HTMLResponse(
            render_verified_id_page(request, banner='Principal DID is required before starting Verified ID.', banner_kind='warn', identity_card=identity_card),
            status_code=400,
        )
    status_code, body = await _verified_id_post('/api/verified-id/presentation-requests', {'principal_did': principal_did})
    if status_code >= 400:
        detail = body.get('detail') or body.get('error') or body
        return HTMLResponse(
            render_verified_id_page(request, banner=f'Unable to start Verified ID request ({status_code}): {detail}', banner_kind='warn', principal_did=principal_did, identity_card=identity_card),
            status_code=502,
        )
    record = body.get('request') if isinstance(body.get('request'), dict) else None
    wallet_mode = str((record or {}).get('mode') or '').strip()
    if wallet_mode == 'walt_id_issuance':
        banner = 'OpenID4VCI presentation request created. Scan the QR code with your wallet to present the credential.'
    else:
        banner = 'Microsoft Verified ID request created. Scan the QR code in Microsoft Authenticator or open the deep link on a compatible device.'
    return HTMLResponse(
        render_verified_id_page(request, banner=banner, banner_kind='ok', principal_did=principal_did, request_record=record, identity_card=identity_card),
        status_code=200,
    )


async def api_verified_id_request(request: Request) -> JSONResponse:
    state = str(request.path_params.get('state') or '').strip()
    status_code, body = await _verified_id_get(f"/api/verified-id/requests/{quote(state, safe='')}")
    return JSONResponse(body, status_code=status_code)


async def profile_setup_page(request: Request) -> HTMLResponse:
    identity_card = await _build_identity_card(request)
    identity_vc = _as_dict(identity_card.get("identity_vc"))
    snapshot = await build_dashboard_snapshot(request)
    model_library_state = _current_model_library_state(snapshot)
    profile_data = {
        "authenticated": bool(identity_vc.get("verified")),
        "principal_did": str(identity_vc.get("principal_did") or "").strip(),
        "existing_did": "",
        "display_name": str(identity_vc.get("principal_display_name") or "").strip(),
        "did_mode": "provision_new",
        "model_library_options": _as_list(model_library_state.get("available_models")),
        "model_library_model_id": str(model_library_state.get("selected_model_id") or "").strip(),
        "model_library_principal_did": str(model_library_state.get("selected_model_principal_did") or "").strip(),
        "model_library_account_binding_id": str(model_library_state.get("account_binding_id") or "").strip(),
        "model_library_ledger_binding_id": str(model_library_state.get("ledger_binding_id") or "").strip(),
    }
    return HTMLResponse(render_profile_setup(request, profile_data=profile_data))


async def profile_setup_submit(request: Request) -> HTMLResponse:
    form = await request.form()
    principal_did = str(form.get("principal_did") or "").strip()
    model_library_model_id = str(form.get("model_library_model_id") or "").strip()
    model_library_principal_did = str(form.get("model_library_principal_did") or "").strip()
    model_library_account_binding_id = str(form.get("model_library_account_binding_id") or "").strip()
    model_library_ledger_binding_id = str(form.get("model_library_ledger_binding_id") or "").strip()
    payload = {
        "display_name": str(form.get("display_name") or "").strip(),
        "contact_email": str(form.get("contact_email") or "").strip(),
        "did_mode": str(form.get("did_mode") or "provision_new").strip(),
        "existing_did": str(form.get("existing_did") or "").strip(),
        "notes": str(form.get("notes") or "").strip(),
        "principal_did": principal_did,
        "model_library_model_id": model_library_model_id,
        "model_library_principal_did": model_library_principal_did,
        "model_library_account_binding_id": model_library_account_binding_id,
        "model_library_ledger_binding_id": model_library_ledger_binding_id,
    }
    identity_card = await _build_identity_card(request)
    identity_vc = _as_dict(identity_card.get("identity_vc"))
    snapshot = await build_dashboard_snapshot(request)
    auth_headers = _auth_headers_from_request(request)
    authenticated_principal = str(identity_vc.get("principal_did") or "").strip()
    if authenticated_principal and principal_did and authenticated_principal == principal_did:
        lookup_status, lookup_body = await _principal_registry_get(f"/api/principals/{quote(principal_did, safe='')}", headers=auth_headers)
        existing = _as_dict(lookup_body) if lookup_status < 400 and isinstance(lookup_body, dict) else {}
        metadata = _as_dict(existing.get("metadata"))
        contact_email = payload["contact_email"]
        existing_did = payload["existing_did"] or principal_did
        additional_dids = _principal_known_dids(metadata.get("additional_dids"), metadata.get("dids"))
        if existing_did and existing_did != principal_did and existing_did not in additional_dids:
            additional_dids.append(existing_did)
        known_dids = _principal_known_dids(principal_did, additional_dids)
        updated_metadata = dict(metadata)
        updated_metadata.update(
            {
                "contact_email": contact_email,
                "email": contact_email,
                "did_mode": payload["did_mode"],
                "existing_did": existing_did,
                "primary_did": principal_did,
                "additional_dids": additional_dids,
                "dids": known_dids,
                "model_library_mode": "predefined" if model_library_model_id else metadata.get("model_library_mode"),
                "selected_model_id": model_library_model_id or metadata.get("selected_model_id"),
                "selected_model_principal_did": model_library_principal_did or metadata.get("selected_model_principal_did"),
                "selected_model_account_binding_id": model_library_account_binding_id or metadata.get("selected_model_account_binding_id"),
                "selected_model_ledger_binding_id": model_library_ledger_binding_id or metadata.get("selected_model_ledger_binding_id"),
            }
        )
        upsert_payload = {
            "principal_did": principal_did,
            "display_name": payload["display_name"] or str(existing.get("display_name") or principal_did).strip(),
            "tenant_id": str(existing.get("tenant_id") or identity_vc.get("tenant_id") or FRONTEND_TENANT_ID).strip() or FRONTEND_TENANT_ID,
            "status": str(existing.get("status") or "active").strip().lower() or "active",
            "principal_type": str(metadata.get("actor_type") or "human").strip().lower() or "human",
            "ledger_id": str(metadata.get("ledger_id") or identity_vc.get("ledger_id") or "").strip(),
            "provisioning_source": "control_plane_profile_update",
            "metadata": updated_metadata,
        }
        status_code, body = await _control_plane_post("/api/control-plane/principals", upsert_payload)
        profile_data = {
            "authenticated": True,
            "principal_did": principal_did,
            "existing_did": principal_did,
            "display_name": payload["display_name"],
            "contact_email": payload["contact_email"],
            "notes": payload["notes"],
            "did_mode": "use_existing",
            "model_library_options": _as_list(_current_model_library_state(snapshot).get("available_models")),
            "model_library_model_id": model_library_model_id or str(metadata.get("selected_model_id") or "").strip(),
            "model_library_principal_did": model_library_principal_did or str(metadata.get("selected_model_principal_did") or "").strip(),
            "model_library_account_binding_id": model_library_account_binding_id or str(metadata.get("selected_model_account_binding_id") or "").strip(),
            "model_library_ledger_binding_id": model_library_ledger_binding_id or str(metadata.get("selected_model_ledger_binding_id") or "").strip(),
        }
        if status_code >= 400:
            detail = body.get("detail") or body.get("error") or body
            return HTMLResponse(
                render_profile_setup(request, banner=f"Unable to update profile ({status_code}): {detail}", banner_kind="warn", profile_data=profile_data),
                status_code=502,
            )
        if model_library_model_id:
            library_state, selection_error = await _persist_onboarding_model_library_selection(
                request,
                identity_card=identity_card,
                snapshot=snapshot,
                selected_model_id=model_library_model_id,
            )
            if selection_error:
                profile_data["model_library_model_id"] = str(library_state.get("selected_model_id") or model_library_model_id).strip()
                profile_data["model_library_principal_did"] = str(library_state.get("selected_model_principal_did") or model_library_principal_did).strip()
                profile_data["model_library_account_binding_id"] = str(library_state.get("account_binding_id") or model_library_account_binding_id).strip()
                profile_data["model_library_ledger_binding_id"] = str(library_state.get("ledger_binding_id") or model_library_ledger_binding_id).strip()
                return HTMLResponse(
                    render_profile_setup(request, banner=f"Unable to seed the selected model library ({selection_error}).", banner_kind="warn", profile_data=profile_data),
                    status_code=502,
                )
        return HTMLResponse(
            render_profile_setup(request, banner="Profile updated. The canonical display name now comes from the principal registry.", banner_kind="ok", profile_data=profile_data),
            status_code=200,
        )
    operator_payload = _build_profile_request_operator_payload(payload, request)
    ok, message = await _send_profile_request_email(payload, operator_payload)
    return HTMLResponse(
        render_profile_setup(
            request,
            banner=message,
            banner_kind="ok" if ok else "warn",
            profile_data={
                "authenticated": bool(identity_vc.get("verified")),
                "principal_did": authenticated_principal,
                "existing_did": payload["existing_did"] or authenticated_principal,
                "display_name": payload["display_name"],
                "contact_email": payload["contact_email"],
                "notes": payload["notes"],
                "did_mode": payload["did_mode"],
                "model_library_options": _as_list(_current_model_library_state(snapshot).get("available_models")),
                "model_library_model_id": model_library_model_id,
                "model_library_principal_did": model_library_principal_did,
                "model_library_account_binding_id": model_library_account_binding_id,
                "model_library_ledger_binding_id": model_library_ledger_binding_id,
            },
            show_next_steps=ok,
        ),
        status_code=200 if ok else 503,
    )


class RequestContextMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next: RequestResponseEndpoint):
        token = _current_request.set(request)
        try:
            return await call_next(request)
        finally:
            _current_request.reset(token)


